INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-44023', 'gcn', 'AT2026fp', '2026-03-15T18:39:46.000Z', '{"measurements":{"dec":"-02d 36m 13.5s","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":19.2,"other_measurements":{"galactic_latitude":"57 deg.","galactic_longitude":"272 deg.","sun_altitude":"-42.8 deg.","zenith_distance":"45 deg."},"ra":"11h 44m 37.99s","redshift":null,"tables":[{"filter":"CLEAR","limiting_magnitude":20,"magnitude":19.2},{"date":"2026-02-12.28608 UT","filter":"FAULT","magnitude":19.9}]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"lipunov@xray.sai.msu.ru","institution":"Moscow State U/Krylov Obs","name":"Vladimir Lipunov"},"coordinates":{},"detectionTime":"1926-03-15T18:39:46.000Z","event":"AT2026fp","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 44023\nSUBJECT: IceCube Alert-260315A/AT2026fpm Automatic MASTER optical blue counterpart  candidate\nDATE: 26/03/15 18:39:46 GMT\nFROM: Vladimir Lipunov at Moscow State U/Krylov Obs <lipunov@xray.sai.msu.ru>\n\n\nM.J. Segura, C.Francile,  F. Podesta, R.Podesta, E. Gonzalez (Observatorio\nAstronomico Felix Aguilar (OAFA),\nYa.Kechin, V.Lipunov (Lomonosov MSU), N.Budnev, O.Gress (ISU),\nA.Kuznetsov, I.Panchenko, P.Balanutsa, G.Antipov, E.Gorbovskoy, N.Tiurina,\nV.Senik, A.Chasovnikov, M.Shilova,V.Topolev, D.Vlasenko, A.Sankovich,\nYu.Tselik (Lomonosov MSU),\nD.Svinkin (Ioffe Institute),\nA. Tlatov, D. Dormidontov (Kislovodsk Solar Station of the Pulkovo Observatory),\nA.Sosnovskij (CrAO),\nD.Buckley (SAAO),\nR.Rebolo (The Instituto de Astrofisica de Canarias),\nL.Carrasco, J.R.Valdes, V.Chavushyan, V.M.Patino Alvarez,\nJ.Martinez,A.R.Corella, J.Tanori, L. Villalobos, L.H.Rodriguez (INAOE, Guillermo\nHaro Astrophysics Observatory)\nA. Gabovich, V.Yurkov (Blagoveschensk Educational StateUniversity)\n\nMASTER OT J114437.99-023613.5/AT 2026fpm discovery\n\nMASTER-OAFA robotic telescope  [1]  located in Argentina (OAFA observatory of San Juan National University) was pointed to the IceCube Alert 260315A (trigger No 46886533,11h 42m 40.32s , -01d 53m 06.0s, R=0.71) errorbox 105 sec after notice time and 224 sec after trigger time at 2026-03-15 02:22:50 UT, with upper limit up to  20.4 mag. The observations began at zenith distance = 45 deg. The sun  altitude  is -42.8 deg.\n\nThe galactic latitude b = 57 deg., longitude l = 272 deg.\n\nReal time updated cover map and OT discovered available here:\nhttps://master.sai.msu.ru/site/master2/observ.php?id=3187113\n\nMASTER-OAFA auto-detection system [4]\ndiscovered OT source at (RA, Dec) = 11h 44m 37.99s -02d 36m 13.5s on 2026-03-15.10943 UT very close to center of neutrino errorbox (GCN Circular #44017).\n\nThe OT magnitude in ''CLEAR'' filter is 19.2m\n(mlim = 20.0).\n\nThe OT is seen in 44 images. There is no minor planet at this place.\n\nWe have reference image on 2026-02-12.28608 UT with ''FAULT'' filter 19.9m.\n\nSpectral observations are required.\n\nThe discovery and reference images are available at:\n\nhttp://master.sai.msu.ru/static/OT/114437.99-023613.5.png\n\n[1] Lipunov et al., 2010, Advances in Astronomy, vol. 2010, 30L\n[2] Lipunov et al. 2022, Universe, Vol. 8(5), id.271\n[3] Lipunov et a. 2019, ARep, vol.63, 293\n[4] Lipunov et al. 2023, Astronomical Robotic Networks and Operative Multichanel\nAstrophysics,Lomonosov MSU PRESS, 591pp.\n http://www.pereplet.ru/lipunov/625.html#625"}', 'The MASTER-OAFA robotic telescope in Argentina discovered a new optical transient, J114437.99-023613.5/AT2026fpm, located near the errorbox of an IceCube neutrino alert. The transient has a magnitude of 19.2 in the ''CLEAR'' filter and was not detected in a reference image from February 2026. Spectral observations are required for further analysis.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-44022', 'gcn', 'GRB 260310A', '2026-03-15T17:21:19.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":18.54,"other_measurements":{"observation_duration_days":4.56,"observation_duration_hours":109.54},"ra":null,"redshift":null,"tables":[{"Date":"2026-03-14","Exp time (s)":"100s*1","Filter":"R","Magnitude":"18.54 ± 0.12","Start_UT":"18:29:38","T_start-T0(days)":"~4.56"}]},"authors":{"affiliations":["Aryabhatta Research Institute of Observational Sciences (ARIES)"],"authors":["Pankaj Pawar, Debalina Kar, Anshika Gupta, Dhruv Jain, Kuntal Misra"],"institutions":["Aryabhatta Research Institute of Observational Sciences (ARIES)"],"universities":["Aryabhatta Research Institute of Observational Sciences (ARIES)"]},"telescopes":{"facilities":["Devasthal Observatory"],"instruments":[],"observatories":["Devasthal Observatory"],"telescopes":["1.3m Devasthal Fast Optical Telescope (DFOT)"]},"urls":[],"basic_data":{"author":{"email":"","institution":"","name":"pawarpankaj1492@gmail.com"},"coordinates":{},"detectionTime":"1926-03-15T17:21:19.000Z","event":"GRB 260310A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 44022\nSUBJECT: GRB 260310A / AT2026fgk: 1.3m DFOT optical observations\nDATE: 26/03/15 17:21:19 GMT\nFROM: pawarpankaj1492@gmail.com\n\nPankaj Pawar, Debalina Kar, Anshika Gupta, Dhruv Jain and Kuntal Misra (ARIES) report:\n\nWe observed the likely optical counterpart of GRB 260310A, detected by Fermi/GBM(Fermi/GBM team, GCN 43951) and AstroSat(Salunke et al., GCN 43958), with the 1.3m Devasthal Fast Optical Telescope (DFOT), located at the Devasthal Observatory of the Aryabhatta Research Institute of Observational Sciences (ARIES), India.\n\nThe observations began on 2026-03-14 at 18:29:38 UT, approximately 109.54 hours (~4.56 days) after the trigger. The reported optical couterpart AT2026fgk (Lipunov et al., GCN 43954; Konno et al., GCN 43974, Hinds et al., GCN 43977; ​ ​ Lipunov et al., GCN 43978; Martin-Carrillo et al., GCN 43979, Moren Méndez et al., GCN 43980; de Ugarte Postigo et al., GCN 43984, Pursiainen et al., Becerra et al., GCN 43991; Martin-Carrillo et al., GCN 44000; Watson et al., GCN 44001; Lai et al., GCN 44002; L. Izzo, GCN 44003; Brivio et al., GCN 44004; Rhodes et al., GCN 44005; Moskvitin et al., GCN 44006; Brosio et al., GCN 44021) is clearly detected in a single 100s R-band frame.\n\nWe derive the following magnitude from the stacked image:\n\nDate Start_UT T_start-T0(days) Filter  Exp time (s)  Magnitude\n===============================================================\n2026-03-14  18:29:38  ~4.56      R      100s*1      18.54 ± 0.12\n\nThe reported magnitude is calibrated using Pan-STARRS field stars and\nis not corrected for Galactic extinction."}', 'Astronomers at the Aryabhatta Research Institute of Observational Sciences (ARIES) in India used the 1.3m Devasthal Fast Optical Telescope (DFOT) to observe the optical counterpart of GRB 260310A, which was detected by Fermi/GBM and AstroSat. The observation, conducted approximately 4.56 days after the trigger, revealed a clear detection of the counterpart in a single 100s R-band frame, with a magnitude of 18.54 ± 0.12.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6621', 'gcn', 'GRB 070714', '2007-07-14T07:07:04.000Z', '{"measurements":{"dec":"+28:17:51.4","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"observation_duration":"~15 minutes","position_error":"0.5 arcsec"},"ra":"03:51:22.2","redshift":null,"tables":[]},"authors":{"affiliations":["Liverpool JMU"],"authors":["Racusin"],"institutions":["Liverpool GRB team"],"universities":["Liverpool John Moores U"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Liverpool Telescope"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"axm@astro.livjm.ac.uk","institution":"Liverpool John Moores U","name":"Andrea Melandri"},"coordinates":{"dec":3.8561666666666667},"detectionTime":"2007-07-14T07:07:04.000Z","event":"GRB 070714","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6621\nSUBJECT: GRB 070714 : Liverpool Telescope optical counterpart ?\nDATE: 07/07/14 07:07:04 GMT\nFROM: Andrea Melandri at Liverpool John Moores U  <axm@astro.livjm.ac.uk>\n\nA. Melandri (Liverpool JMU) on behalf of the Liverpool GRB\nteam report:\n\n\nOn 2007 Jul 14 at 05:10:56 UT the 2-m Liverpool Telescope\nautomatically observed the field of GRB 070714 (trigger=284856,\nRacusin et al. GCN 6620).\n\nDue to the incoming dawn the automatic observation sequence stopped\nafter ~15 minutes, after the acquisition of only 9 frames.\n\nInside the XRT error circle (Racusin et al. GCN 6620) we find a\nsingle source at the position (error of 0.5 arcsec)\n\nRA = 03:51:22.2\nDec = +28:17:51.4\n\nIt is not a catalog source but presently it''s not clear yet whether\nthe object is fading."}', 'The Liverpool Telescope has detected a potential optical counterpart for GRB 070714, located at RA 03:51:22.2, Dec +28:17:51.4 with a position error of 0.5 arcsec. The observation lasted for approximately 15 minutes, and it is currently unclear whether the object is fading.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6620', 'gcn', 'GRB 070714', '2007-07-14T05:28:15.000Z', '{"measurements":{"dec":"+28d 17'' 43\"","distance":null,"duration":"3 seconds","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"initial_flux_xrt":"2.4e-09 erg/cm2/s (0.2-10 keV)","peak_count_rate_bat":"20000 counts/s (15-350 keV)"},"ra":"03h 51m 25s","redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC (Swift Team)","Penn State University","LANL"],"authors":["J. L. Racusin","S. D. Barthelmy","D. N. Burrows","M. M. Chester","N. Gehrels","H. A. Krimm","D. M. Palmer","T. Sakamoto"],"institutions":["NASA/GSFC","Penn State University","LANL","NASA/ORAU","USRA"],"universities":["Penn State University","NASA/GSFC","LANL"]},"telescopes":{"facilities":[],"instruments":["BAT","XRT","UVOT"],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-14T05:28:15.000Z","event":"GRB 070714","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6620\nSUBJECT: GRB 070714: Swift detection of a bright burst, possibly short\nDATE: 07/07/14 05:28:15 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nJ. L. Racusin (PSU), S. D. Barthelmy (GSFC), D. N. Burrows (PSU),\nM. M. Chester (PSU), N. Gehrels (NASA/GSFC), H. A. Krimm (GSFC/USRA),\nD. M. Palmer (LANL) and T. Sakamoto (NASA/ORAU) report on behalf of\nthe Swift Team:\n\nAt 04:59:29 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070714 (trigger=284856).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 57.854, +28.295 which is \n   RA(J2000)  =  03h 51m 25s\n   Dec(J2000) = +28d 17'' 43\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows a duration of\n3 seconds with a spike to a peak of 20000 counts/s (15-350 keV) \nat T+0.2 s. \n\nThe XRT began observing the field at 05:00:30 UT, 61 seconds after the\nBAT trigger. Using ground processed data, XRT found a bright, fading, \nuncatalogued X-ray source located at RA, Dec 57.8423, +28.2978 which is\n   RA(J2000)  =  03h 51m 22.1s\n   Dec(J2000) =  28d 17'' 52.0\"\nwith an uncertainty of 3.9 arcseconds (radius, 90% containment). \nThis location is 39 arcseconds from the BAT on-board position,\nwithin the BAT error circle. The initial flux in the 2.5s image\nwas 2.4e-09 erg/cm2/s (0.2-10 keV). \n\nThe UVOT began observing the field at 05:00:40.05 UT, 70.4 s after the\nBAT trigger. No counterpart is apparent in the 2.7'' x 2.7'' subimage,\nbased on visual comparison with the DSS. Additional processing is\nunderway. \n\nBurst Advocate for this burst is J. L. Racusin (racusin AT astro.psu.edu). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift satellite detected a bright gamma-ray burst, GRB 070714, with a duration of 3 seconds and a peak count rate of 20,000 counts/s in the 15-350 keV range. The X-ray source associated with the burst was located by the XRT instrument and found to be fading with an initial flux of 2.4e-09 erg/cm2/s (0.2-10 keV). No optical counterpart was detected by the UVOT.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-662', 'gcn', 'GRB000418', '2000-05-03T18:16:03.000Z', '{"measurements":["16.718","16.668","16.020","15.654","15.291","19.559","18.529","17.447","16.802","16.281","20.424","19.631","19.118","18.538","19.856","18.988","18.484","18.043","19.402","19.800","19.330","18.935","18.637"],"authors":{"affiliations":["USRA/USNO"],"authors":["A. Henden"],"institutions":["USNO/USRA"],"universities":["USRA","USNO"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["USNOFS 1.0-m telescope"]},"urls":["ftp://ftp.nofs.navy.mil/pub/outgoing/aah/grb/grb000418.dat"],"basic_data":{"author":{"email":"aah@nofs.navy.mil","institution":"USNO/USRA","name":"Arne A. Henden"},"coordinates":{},"detectionTime":"2000-05-03T18:16:03.000Z","event":"GRB000418","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 662\nSUBJECT: GRB000418, UBVRI field photometry update\nDATE: 00/05/03 18:16:03 GMT\nFROM: Arne A. Henden at USNO/USRA  <aah@nofs.navy.mil>\n\nA. Henden (USRA/USNO) reports on behalf of the USNO GRB team:\n\nFinal UBVRcIc all-sky photometry for the field of GRB000418\nis now available on our anonymous ftp site:\nftp://ftp.nofs.navy.mil/pub/outgoing/aah/grb/grb000418.dat\nIt has been acquired with the USNOFS 1.0-m telescope on three\nphotometric nights.  This 11x11arcmin field surrounds\nthe proposed counterpart and extends a little fainter than V=21.\nAll stars brighter than V=14 are saturated and should be used\nwith care.  The astrometry in this file\nis based on linear plate solutions with respect to USNO-A2.0.\nThe internal errors are less than 100mas.\n\nThe field is filled with galaxies.  In fact, object C\nin the original list of comparison stars is a galaxy; it\nhas been replaced in the updated table below with a stellar\nobject (G) to the north of the optical counterpart:\n\nID   x    y     U       B       V       R       I\nA   000  000  16.718  16.668  16.020  15.654  15.291\n               0.020   0.020   0.019   0.019   0.019\n\nB  -158 +050  19.559  18.529  17.447  16.802  16.281\n               0.192   0.030   0.027   0.027   0.027\n\nD  -094 -006    -     20.424  19.631  19.118  18.538\n                       0.051   0.032   0.035   0.070\n\nE  -200 -042    -     19.856  18.988  18.484  18.043\n                       0.021   0.021   0.061   0.078\n\nG  -102 +220  19.402  19.800  19.330  18.935  18.637\n               0.150   0.065   0.065   0.065   0.079\n\nNotes: star A is the Mirabal et. al. comparison star;\nx,y offsets are in arcsec with respect to this star,\npositive east and north."}', 'Astronomer A. Henden of USRA/USNO has released final UBVRI photometry data for the field of GRB000418, obtained using the USNOFS 1.0-m telescope. The data, available on the USNO anonymous FTP site, includes measurements for 12 stars and replaces a galaxy with a stellar object (G) in the updated table. The internal errors are less than 100mas.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6619', 'gcn', 'Swift detection of a possible burst (Trigger 284850)', '2007-07-14T04:20:07.000Z', '{"measurements":{"dec":30.24,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"slew_uncertainty":"6 arcmin","trigger_time_uncertainty":"5 minutes"},"ra":43.94,"redshift":null,"tables":[]},"authors":{"affiliations":["astro.psu.edu","Swift Team","GSFC"],"authors":["D. Grupe","S. D. Barthelmy","D. N. Burrows","M. M. Chester","N. Gehrels"],"institutions":["NASA/GSFC","Penn State University"],"universities":["Penn State University","NASA/GSFC"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-14T04:20:07.000Z","event":"Swift detection of a possible burst (Trigger 284850)","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6619\nSUBJECT: Swift detection of a possible burst (Trigger 284850)\nDATE: 07/07/14 04:20:07 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nD. Grupe (PSU), S. D. Barthelmy (GSFC), D. N. Burrows (PSU),\nM. M. Chester (PSU) and N. Gehrels (NASA/GSFC) report on behalf of\nthe Swift Team:\n\nAt approximately 03:18 +/-5min UT BAT triggered on a possible GRB\n(trigger 284850).  Swift automatically slewed to the location\nRA=43.94 Dec=+30.24 (J2000).  The uncertainty is 6 arcmin. \nWe are uncertain about both the time and the location at this time\nbecause the trigger occurred during a TDRSS outage,\nso most of the regular TDRSS Notices were lost.  We are also\nin the middle of the computer downtime as announced earlier today,\nso analysis of the full Malindi downlink data will have to wait until\nlate Saturday UT. \n\nWe wish to thank J. Knavel of the Swift Operations Team for notifying\nthe science team that Swift had slewed to a GRB. \n\nBurst Advocate for this burst is D. Grupe (grupe AT astro.psu.edu). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'Swift telescope detected a possible gamma-ray burst (GRB 284850) at approximately 03:18 UT with uncertain time and location due to a TDRSS outage and computer downtime. The RA and Dec coordinates are given as 43.94 and +30.24 (J2000), with an uncertainty of 6 arcmin. The Swift team is currently analyzing the data and the burst advocate is D. Grupe of Penn State University.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6618', 'gcn', 'SN 2007bg', '2007-07-11T20:40:27.000Z', '{"measurements":{"dec":"+51d49m20.2s","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"g":21.82,"r":21.12},"other_measurements":{"difference_in_magnitude_g_band":1.7,"host_galaxy_luminosity":"-12"},"ra":"11h49m25.74s","redshift":0.034,"tables":[{"column_name":"model_magnitude_g","value":21.82},{"column_name":"model_magnitude_r","value":21.12}]},"authors":{"affiliations":["Ohio State"],"authors":["J. L. Prieto","K. Z. Stanek","J. F. Beacom"],"institutions":["CfA (Harvard-Smithsonian Center for Astrophysics)"],"universities":["Ohio State"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://www.astronomy.ohio-state.edu/~prieto/sn07bg_host.gif"],"basic_data":{"author":{"email":"kstanek@cfa.harvard.edu","institution":"CfA","name":"Krzysztof Z. Stanek"},"coordinates":{},"detectionTime":"2007-07-11T20:40:27.000Z","event":"SN 2007bg","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6618\nSUBJECT: SN 2007bg - off-axis GRB?\nDATE: 07/07/11 20:40:27 GMT\nFROM: Krzysztof Z. Stanek at CfA  <kstanek@cfa.harvard.edu>\n\nJ. L. Prieto, K. Z. Stanek & J. F. Beacom (Ohio State) report:\n\nIn a study of supernova hosts (Prieto, Stanek & Beacom 2007,\narXiv:0707.0690v1 [astro-ph]), the recent broad-lined SN Ic 2007bg at\nz=0.034 (Quimby et al. 2007, CBET 927; IAUC 8834;  Harutyunyan et al.\n2007, CBET 948), was identified as a good candidate for an off-axis GRB.\n\nThe supernova, discovered on April 16 2007 (CBET 927, IAUC 8834), is\nlocated at 1.6 arcsec North and 4.0 arcsec East of a source identified in\nthe SDSS-DR6 catalog, SDSS J114925.74+514920.2, which has model magnitudes\ng=21.82 +/- 0.07, r=21.12 +/- 0.07 (uncorrected for Galactic extinction;\nAg=0.08, Ar=0.06) and estimated photometric redshift between 0.3 and 0.4.\nThere is a fainter source at ~2\" from the position of the supernova\nclearly detected in the SDSS g-band image, and which is not identified in\nthe SDSS-DR6 catalog.  This fainter source is most likely the host galaxy\nof SN 2007bg (CBET 948). A 1x1 arcmin SDSS g-band image around the\nposition of the supernova can be found here:\n\nhttp://www.astronomy.ohio-state.edu/~prieto/sn07bg_host.gif\n\nWe used Sextractor to measure a difference of 1.7 mag in g-band between\nthe likely host and SDSS J114925.74+514920.2. At the redshift of the\nsupernova, z=0.034 (CBET 927), this makes the likely host an extremely\nlow-luminosity galaxy with M_B ~ -12, one of the least-luminous supernova\nhosts ever observed. Such a low-luminosity host is certain to be very\nmetal poor (~1/20 solar; Lee et al. 2006, ApJ, 647, 970L), and therefore\nthis supernova is a very good candidate for association with an off-axis\nGRB (e.g., Stanek et al. 2006, AcA, 56, 333). We encourage follow-up\nobservations to look for an off-axis GRB jet.\n\nThis message may be cited."}', 'A team of astronomers led by J. L. Prieto, K. Z. Stanek, and J. F. Beacom from Ohio State University have identified SN 2007bg, a low-luminosity supernova discovered in 2007, as a potential off-axis gamma-ray burst (GRB) candidate. The supernova, located at a redshift of 0.034, is extremely metal-poor and its host galaxy is one of the least-luminous ever observed. The team encourages follow-up observations to search for an associated off-axis GRB jet.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6617', 'gcn', 'GRB 070704', '2007-07-11T10:21:38.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["IKI RAN","TUG","METU","Sabanci Uni.","KSU/AST"],"authors":["A. Meshcheryakov","R. Burenin","M. Pavlinsky","R. Sunyaev","I. Khamitov","Z. Tunca","U. Kiziloglu","E. Gogus","I. Bikmaev","N. Sakhibullin"],"institutions":["IKI","TUBITAK National Observatory","METU","Sabanci Uni.","KSU/AST"],"universities":["IKI RAN","TUG","METU","Sabanci Uni.","KSU/AST"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["TUBITAK National Observatory"],"telescopes":["Russian-Turkish 1.5-m telescope (RTT150)"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_message_page.msfc?id=6617"],"basic_data":{"author":{"email":"gardel@hea.iki.rssi.ru","institution":"IKI RAN","name":"Alexander Mescheryakov"},"coordinates":{},"detectionTime":"2007-07-11T10:21:38.000Z","event":"GRB 070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6617\nSUBJECT: GRB 070704: RTT150 optical observations\nDATE: 07/07/11 10:21:38 GMT\nFROM: Alexander Mescheryakov at IKI RAN  <gardel@hea.iki.rssi.ru>\n\nA. Meshcheryakov, R. Burenin, M. Pavlinsky, R. Sunyaev (IKI), \nI. Khamitov, Z. Tunca (TUG), U. Kiziloglu (METU), E. Gogus (Sabanci Uni.),\nI. Bikmaev, and N. Sakhibullin (KSU/AST) report:\n\nWe observed the field of GRB 070704 (Sakamoto et al., GCN 6594) with\nRussian-Turkish 1.5-m telescope (RTT150, Bakyrlytepe,TUBITAK National\nObservatory, Turkey). The observations consisted of a series 30-second\nexposures in g'',r'',i'' filters, until ~1h after the burst time we\ncontinue only r''-filter exposures. The first exposure in g'' started at\n20:15:13.9UT, i.e.556 s after the BAT trigger. The observations were\nfinished ~1.5 hour after the burst time.\n\nIn 30-second images as well as in combined images we do not detect any\nnew object at the revised XRT position (Godet & Sakamoto, GCN 6598) down\nto following limiting magnitudes:\n\nFilter  T_start(sec after trigger) Exp(s)  Lim    \n----------------------------------------------------------------------------\n  g''     556                       30      20.1    first\n                                  240      21.2    combined\n  r''     641                       30      20.1    first\n                                 1720      22.3    combined\n  i''     721                       30      20.3    first\n                                  180      21.3    combined\n\nThis message may be cited.\n\n[GCN OPS NOTE(12jul07): Per author''s request, IK was added to the author list,\nand the extra period after ''filter'' in the 4th line was removed.]"}', 'A team of astronomers led by A. Meshcheryakov from IKI RAN reported non-detection of any new object at the revised position of GRB 070704 using the Russian-Turkish 1.5-m telescope (RTT150) at TUBITAK National Observatory. Observations were carried out in g'', r'', and i'' filters, with limiting magnitudes of 20.1, 22.3, and 21.3, respectively.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6616', 'gcn', 'GRB 070704', '2007-07-10T11:39:17.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"35 seconds","energy":"50 keV - 5 MeV","fluence":"(8.4+/-1.7)*10^-6 erg/cm^2","magnitude":null,"other_measurements":{"peak_flux":"0.19+/-0.06 photons/cm^2/s","photon_index":"2.0+/-0.4"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"ohno@hirax7.hepl.hiroshima-u.ac.jp","institution":"Hiroshima U","name":"Masanori Ohno"},"coordinates":{},"detectionTime":"2007-07-10T11:39:17.000Z","event":"GRB 070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6616\nSUBJECT: GRB 070704: Suzaku/WAM observation of the prompt emission\nDATE: 07/07/10 11:39:17 GMT\nFROM: Masanori Ohno at Hiroshima U  <ohno@hirax7.hepl.hiroshima-u.ac.jp>\n\nC. Kira, M. Ohno, T. Uehara, T. Takahashi, Y. Fukazawa (Hiroshima U.),\nK. Yamaoka, Y. E. Nakagawa, S. Sugita (Aoyama Gakuin U.),\nK. Morigami, N. Kodaka, K. Onda, M. Tashiro, M. Suzuki,Y. Urata, A. Endo (Saitama U.),\nT. Enoto, R. Miyawaki, K. Nakawaza, K. Makishima (Univ. of Tokyo),\nS. Hong (Nihon U.),\nM. Kokubun, M. Suzuki, T. Takahashi (ISAS/JAXA),\nE. Sonoda, M. Yamauchi, S. Maeno, H. Tanaka, R. Hara(Univ. of Miyazaki),\nT. Tamagawa, Y. Terada (RIKEN), \nand Suzaku WAM team report:\n\nThe long burst, GRB 070704 (Swift/BAT trigger #283791; T. Sakamoto et al., GCN Circ. 6594;\nA. Melandri et al., GCN Circ. 6602; S. Karpov et al., GCN Circ.6603) was triggered \nat T0=2007-07-04 20:05:02 UT by Suzaku Wide-band All-sky Monitor (WAM)\nwhich covers the energy range of 50 keV - 5 MeV.\nThe observed light curve shows the multiple peaked structures \nwith a duration (T90 in the 50-5000 keV band) of nearly 35 seconds.\nAccording to the GCN Report 69.2, the light curve observed by Swift BAT shows an upsurge\naround T0+350, while in the light curve by Suzaku WAM, there is no such a structure.\n\nThe fluence in the 100-1000 keV band was (8.4+/-1.7)*10^-6 erg/cm^2,\nand the 1-s peak flux in the same band was 0.19+/-0.06 photons/cm^2/s.\nPreliminary result shows that the time-averaged spectrum from T0-5 to T0+40 is\nwell fitted by single power law with a photon index of 2.0+/-0.4 in 100-1000 keV range.\n\nAll the quoted errors are at the 90% confidence level, \nwhile systematic errors are not included.\n\nThe WAM light curve of this event is available at the following URL.\nhttp://www.astro.isas.jaxa.jp/suzaku/HXD-WAM/WAM-GRB/grb/trig/grb_table.html"}', 'The Suzaku Wide-band All-sky Monitor (WAM) detected a long gamma-ray burst (GRB 070704) with a duration of approximately 35 seconds and a fluence of (8.4+/-1.7)*10^-6 erg/cm^2 in the 50 keV - 5 MeV energy range. The light curve showed no evidence of an upsurge around 350 seconds after the burst, unlike Swift BAT observations. The time-averaged spectrum was found to be well fitted by a single power law with a photon index of 2.0+/-0.4 in the 100-1000 keV range.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6615', 'gcn', 'GRB 070707', '2007-07-09T15:27:11.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"1 s","energy":null,"fluence":"1.41(-1.07, +0.16)x10^-6 erg/cm2","magnitude":null,"other_measurements":{"Ep":"427(-144, +374) keV","alpha":"0.57 (-0.59, +0.43)","peak_flux":"8.1(-6.7, +2.9)x10^-6 erg/cm2/s"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Ioffe Inst, on behalf of the Konus-Wind team"],"authors":["S. Golenetskii","R.Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline"],"institutions":["Ioffe Inst"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Konus-Wind"]},"urls":["http://www.ioffe.rssi.ru/LEA/GRBs/GRB070707_T58122/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-07-09T15:27:11.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6615\nSUBJECT: Konus-Wind observation of GRB 070707\nDATE: 07/07/09 15:27:11 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team report:\n\nThe short GRB 070707 (Beckmann et al., GCN 6605; Gotz et al., GCN 6607) \ntriggered Konus-Wind at T0=58122.823 s UT (16:08:42.823).\n\nThe Konus-Wind light curve shows a multipeaked structure\nwith a total duration of ~1 s.\nAs observed by Konus-Wind the burst\nhad a fluence of 1.41(-1.07, +0.16)x10^-6 erg/cm2,\nand a 16-ms peak flux measured from T0-0.016 s\n8.1(-6.7, +2.9)x10^-6 erg/cm2/s\n(both in the 20 keV - 2 MeV energy range).\n\nThe spectrum of the most intense part of the burst\n(from T0 to T0+0.256) is well fitted\n(in the 20 keV - 2 MeV range)\nby a power law with exponential cutoff model:\ndN/dE ~ E^(-alpha)*exp(-E*(2-alpha)/Ep)\nwith alpha = 0.57 (-0.59, +0.43)\nand Ep = 427(-144, +374) keV (chi2 = 13/19 dof).\nThus, this burst is classified as a short hard GRB.\n\nAll the quoted errors are at the 90% confidence level.\n\nThe Konus-Wind light curve of this GRB is available\nat http://www.ioffe.rssi.ru/LEA/GRBs/GRB070707_T58122/"}', 'The Konus-Wind team reported the observation of short gamma-ray burst (GRB) 070707, which triggered the instrument at T0=58122.823 s UT. The burst had a duration of approximately 1 second and a fluence of (1.41-0.16)x10^-6 erg/cm2 in the 20 keV - 2 MeV energy range. The peak flux was measured to be (8.1-2.9)x10^-6 erg/cm2/s. The spectrum was found to be well-fit by a power law with exponential cutoff model, classifying this burst as a short hard GRB.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6614', 'gcn', 'Updated Swift/UVOT calibration', '2007-07-09T12:34:36.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":-0.5,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["MSSL/UCL"],"authors":["A. Breeveld"],"institutions":["MSSL (Mullard Space Science Laboratory)"],"universities":["University College London (UCL)"]},"telescopes":{"facilities":["HEASARC (High Energy Astrophysics Science Archive Research Center)"],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://heasarc.gsfc.nasa.gov/docs/heasarc/caldb/swift/"],"basic_data":{"author":{"email":"aad@mssl.ucl.ac.uk","institution":"MSSL-UCL","name":"Alice Breeveld"},"coordinates":{},"detectionTime":"2007-07-09T12:34:36.000Z","event":"Updated Swift/UVOT calibration","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6614\nSUBJECT: Updated Swift/UVOT calibration\nDATE: 07/07/09 12:34:36 GMT\nFROM: Alice Breeveld at MSSL-UCL  <aad@mssl.ucl.ac.uk>\n\nA. Breeveld (MSSL/UCL) reports on behalf of the Swift/UVOT team:\n\nA new, improved calibration for all the UVOT broadband filters (u, b, v, \nuvw1, uvm2, uvw2 and white) has been released by the HEASARC. The new \ncalibration includes updated zero points, coincidence loss formula, \nfilter effective areas, colour transformations and count rate to flux \ntransformations. The latest CALDB files and documentation can be \ndownloaded from:\nhttp://heasarc.gsfc.nasa.gov/docs/heasarc/caldb/swift/\n\nFor filters u, b and v the zero points are consistent with the previous \nzero points within the previous quoted error, but the uv and white zero \npoints have changed more significantly, by up to 0.5 mag (white). Please \nbe aware that from now on the UVOT magnitudes given in GCNs sent out by \nthe Swift UVOT team will be calculated using these zero points. The \nquoted magnitudes are in the UVOT instrumental system (lower case u, b, \nv) and can be converted to Johnson U, B, V magnitudes using the colour \ntransformations. The differences between UVOT magnitudes and Johnson are \nmost significant in the u filter but are generally small."}', 'A new Swift/UVOT calibration has been released, which includes updated zero points, effective areas, and colour transformations for all UVOT broadband filters. The changes are most significant for the uv and white filters, with zero point shifts up to 0.5 mag. The latest CALDB files and documentation can be downloaded from HEASARC.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6613', 'gcn', 'GRB 070707', '2007-07-09T04:20:54.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":-0.7,"other_measurements":{"magnitude_error":0.1},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["INAF-OABr","INAF-OAR","DIAS-DCU","ESO"],"authors":["Paolo D''Avanzo","S. Piranomonte","S. Vergani","L. Christensen","P. Amico"],"institutions":["INAF-OAB","INAF-OAR","DIAS-DCU","ESO"],"universities":["INAF","DIAS"]},"telescopes":{"facilities":[],"instruments":["FORS1"],"observatories":["ESO"],"telescopes":["ESO-VLT"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6612","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6610","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6609","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6605","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6607"],"basic_data":{"author":{"email":"paolo.davanzo@brera.inaf.it","institution":"INAF-OAB","name":"Paolo D''Avanzo"},"coordinates":{},"detectionTime":"2007-07-09T04:20:54.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6613\nSUBJECT: GRB 070707: optical afterglow\nDATE: 07/07/09 04:20:54 GMT\nFROM: Paolo D''Avanzo at INAF-OAB  <paolo.davanzo@brera.inaf.it>\n\nP. D''Avanzo (INAF-OABr), S. Piranomonte (INAF-OAR) & S. Vergani \n(DIAS-DCU) on behalf of the MISTICI collaboration L. Christensen,  P. \nAmico (ESO) report:\n\nWe observed again the field of the short/hard GRB 070707 (Beckmann et \nal., GCN 6605; Gotz et al., GCN 6607) with the ESO-VLT in imaging mode. \nObservations have been carried out around Jul 09.08 UT in the R band \nwith the FORS1 camera.\n\nA comparison with the images of our previous observing run (D''Avanzo et \nal., GCN 6609) revealed that the object inside the XRT error box \n(Beardmore et al., GCN 6610) reported by Piranomonte et al. (GCN 6612) \nfaded of about 0.7 +/- 0.1 mag. We thus propose this object as the \noptical afterglow of GRB 070707.\n\nFurther observations are planned. We acknowledge the ESO staff for \nreliable support.\n\nThis message can be cited."}', 'Astronomers using the ESO-VLT telescope have identified a fading object in the error box of the short/hard gamma-ray burst GRB 070707, proposing it as the optical afterglow of the event. The object''s magnitude has faded by approximately 0.7 mag since previous observations.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6612', 'gcn', 'GRB 070707', '2007-07-08T19:10:28.000Z', '{"measurements":{"dec":"-68:55:27.2","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":23,"other_measurements":{"coordinate_error":"0.5\""},"ra":"17:50:58.55","redshift":null,"tables":[]},"authors":{"affiliations":["INAF-OABr","INAF-OAR"],"authors":["S. Piranomonte","S. Vergani","P. D''Avanzo","G. Tagliaferri"],"institutions":["INAF-OAB","INAF-OAR","DIAS-DCU"],"universities":["INAF"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["VLT"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_archive.msf?is_archive=1&is_gcn=1&is_alert=1&start_time=2008-07-07T19:10:28Z&end_time=2008-07-07T19:10:28Z&gcn_id=6612"],"basic_data":{"author":{"email":"paolo.davanzo@brera.inaf.it","institution":"INAF-OAB","name":"Paolo D''Avanzo"},"coordinates":{"dec":17.849597222222222},"detectionTime":"2007-07-08T19:10:28.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6612\nSUBJECT: GRB 070707: object inside XRT error circle\nDATE: 07/07/08 19:10:28 GMT\nFROM: Paolo D''Avanzo at INAF-OAB  <paolo.davanzo@brera.inaf.it>\n\nS. Piranomonte (INAF-OAR), S. Vergani (DIAS-DCU), P. D''Avanzo & G. \nTagliaferri (INAF-OABr) report on behalf of the MISTICI collaboration:\n\nFollowing the detection by Swift/XRT (Beardmore et al., GCN 6610) of GRB \n070707 (Beckmann et al., GCN 6605; Gotz et al., GCN 6607), we have \ninspected our VLT R-band images (D''Avanzo et al., GCN 6609).\n\nInside the XRT error box, we find a single source with R ~ 23.0 \n(calibrated using archival instrumental zeropoints), at the coordinates \n(J2000, 0.5\" error):\n\nRA(2000) = 17:50:58.55\nDec(2000) = -68:55:27.2\n\nAt the present stage, we cannot yet assess the relationship of this \nsource with GRB 070707. Further observations are planned.\n\nThis message can be cited."}', 'Astronomers using the VLT telescope have identified a faint source with a magnitude of 23.0 at the coordinates RA(2000) = 17:50:58.55, Dec(2000) = -68:55:27.2, inside the error circle of the Swift/XRT detection of GRB 070707. The relationship between this source and the gamma-ray burst is not yet clear, and further observations are planned.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6611', 'gcn', 'GRB070707', '2007-07-08T18:56:30.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[{"Exp(s)":543,"Filter":"V","Mag (3-sigma upper limit)":19.7,"T_mid(s)":53885},{"Exp(s)":324,"Filter":"B","Mag (3-sigma upper limit)":20.6,"T_mid(s)":31910},{"Exp(s)":97,"Filter":"U","Mag (3-sigma upper limit)":19.5,"T_mid(s)":47905},{"Exp(s)":964,"Filter":"UVW1","Mag (3-sigma upper limit)":20.3,"T_mid(s)":47149},{"Exp(s)":1190,"Filter":"UVM2","Mag (3-sigma upper limit)":20.5,"T_mid(s)":39328},{"Exp(s)":1800,"Filter":"UVW2","Mag (3-sigma upper limit)":20.5,"T_mid(s)":53182}]},"authors":{"affiliations":["MSSL-UCL","GSFC"],"authors":["P. Schady","A. Parsons"],"institutions":["MSSL (Mullard Space Science Laboratory)"],"universities":["University College London (UCL)"]},"telescopes":{"facilities":["Swift UVOT","INTEGRAL XRT"],"instruments":["UVOT"],"observatories":["INTEGRAL"],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/int-parms/6607/6607.gcn3.fits","http://gcn.gsfc.nasa.gov/gcn3/int-parms/6606/6606.gcn3.fits","http://gcn.gsfc.nasa.gov/gcn3/int-parms/6610/6610.gcn3.fits"],"basic_data":{"author":{"email":"ps@mssl.ucl.ac.uk","institution":"MSSL/Swift","name":"Patricia Schady"},"coordinates":{},"detectionTime":"2007-07-08T18:56:30.000Z","event":"GRB070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6611\nSUBJECT: Swift/UVOT Observations of GRB070707\nDATE: 07/07/08 18:56:30 GMT\nFROM: Patricia Schady at MSSL/Swift  <ps@mssl.ucl.ac.uk>\n\nP. Schady (MSSL-UCL) and A. Parsons (GSFC) report on the behalf of the \nSwift UVOT team:\n\nThe Swift/UVOT observed the field of INTEGRAL burst, GRB070707 starting 8.8hrs \nafter the INTEGRAL trigger (Beckmann et al. 2007, GCN Circ. 6606). We do not \nfind any new source in any of the UVOT observations inside the refined INTEGRAL \nerror circle (Gotz et al. 2007, GCN Circ. 6607) or XRT error circle (Beardmore \net al. 2007, GCN 6610)\n\nThe 3-sigma upper limits for detecting a source inside the refined XRT\nerror circle in the initial data products are:\n\nFilter    T_mid(s) Exp(s) Mag (3-sigma upper limit)\n-------------------------------------------------------\nV         53885    543      19.7\nB         31910    324      20.6\nU         47905    97       19.5\nUVW1      47149    964      20.3\nUVM2      39328    1190     20.5\nUVW2      53182    1800     20.5\n-----------------------------------------------------------------\n\nwhere T_mid is the weighted mid time of the coadded exposure. The values\nquoted above are not corrected for the expected Galactic extinction\ncorresponding to a reddening of E_{B-V} = 0.08 mag in the direction of the\nburst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reported no detection of a new source in the error circles of the INTEGRAL burst GRB070707 using Swift UVOT observations. They provided 3-sigma upper limits for detecting a source in each filter, ranging from 19.5 to 20.6 magnitudes.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6610', 'gcn', 'GRB 070707', '2007-07-08T18:53:29.000Z', '{"measurements":{"dec":"-68d 55m 27.0s","distance":null,"duration":"3.8 ks","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"offset_from_gotz_position":"36.3 arcsec","uncertainty":"5.4 arcsec (90% containment)"},"ra":"17h 50m 58.49s","redshift":null,"tables":[{"background_counts":1,"count_rate_confidence_level":"99.73%","count_rate_lower_bound":"0.003 count s^-1","count_rate_upper_bound":"0.011 count s^-1","end_time_after_trigger":"54.1 ks","exposure_time":"3.8 ks","source_counts":26,"start_time_after_trigger":"31.8 ks"}]},"authors":{"affiliations":["U. Leicester","GSFC"],"authors":["A.P. Beardmore","K.L. Page","A. Parsons"],"institutions":["University of Leicester","GSFC"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"apb@star.le.ac.uk","institution":"U Leicester","name":"Andy Beardmore"},"coordinates":{},"detectionTime":"2007-07-08T18:53:29.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6610\nSUBJECT: Swift XRT observation of GRB 070707\nDATE: 07/07/08 18:53:29 GMT\nFROM: Andy Beardmore at U Leicester  <apb@star.le.ac.uk>\n\nA.P. Beardmore, K.L. Page (U. Leicester) and A. Parsons (GSFC) report on\nbehalf of the Swift XRT team:\n\nOn 2007 Jul 08 00:57:50UT the Swift XRT started observing the field of\nthe INTEGRAL burst GRB 070707 (Beckmann et al., GCN 6606; Gotz et al.,\nGCN 6607). In a 3.8ks exposure photon counting mode image taken from\n31.8 ks to 54.1 ks after the trigger, we detect a source at\nRA, Dec = 267.7437, -68.9242, which is\n\nRA(J2000)  =  17h 50m 58.49s\nDec(J2000) = -68d 55m 27.0s\n\nwith an uncertainty of 5.4 arcsec (90% containment). This is 36.3 arcsec\nfrom the position reported by Gotz et al. (GCN 6607), and within their\nerror circle.\n\nUsing a circular extraction region of 10 pixels radius, we observe 26\ntotal counts. Together with an estimated background level of 1.0\ncount in the extraction region, we find the 99.73% Bayesian\nconfidence level on the source count rate is 0.003 to 0.011 count s^-1.\n\nHowever, with such a limited number of photons, it is impossible to\nsay at this stage whether the source is fading and if this is the X-ray\ncounterpart to the GRB.\n\nThis circular is an official product of the Swift XRT team."}', 'The Swift XRT team reports the detection of a source in X-rays, 36.3 arcsec from the position of GRB 070707, using data from a 3.8 ks exposure taken 31.8-54.1 ks after the trigger. The team estimates a count rate of 0.003-0.011 count s^-1 with a 99.73% confidence level, but it''s uncertain if this is the X-ray counterpart to the GRB.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-661', 'gcn', 'GRB 000418', '2000-05-03T06:25:31.000Z', '{"measurements":{"dec":null,"distance":2.515e+28,"duration":null,"energy":4.9e+52,"fluence":0.000013,"magnitude":null,"other_measurements":{},"ra":null,"redshift":1.11854,"tables":[]},"authors":{"affiliations":["(Caltech)"],"authors":["J. S. Bloom","A. Diercks","S. G. Djorgovski","D. Kaplan","S. R. Kulkarni"],"institutions":["Caltech-NRAO-CARA GRB collaboration"],"universities":["Caltech"]},"telescopes":{"facilities":[],"instruments":["Echellette Spectrograph and Imager (ESI)"],"observatories":["Mauna Kea"],"telescopes":["Keck II 10-m Telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn/gcn3_batch.cfm?id=642","https://gcn.gsfc.nasa.gov/gcn/gcn3_batch.cfm?id=645"],"basic_data":{"author":{"email":"jsb@astro.caltech.edu","institution":"CIT","name":"Josh Bloom"},"coordinates":{},"detectionTime":"2000-05-03T06:25:31.000Z","event":"GRB 000418","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 661\nSUBJECT: The redshift of GRB 000418\nDATE: 00/05/03 06:25:31 GMT\nFROM: Josh Bloom at CIT  <jsb@astro.caltech.edu>\n\nThe redshift of GRB 000418\n\nJ. S. Bloom, A. Diercks, S. G. Djorgovski, D. Kaplan, and S. R. Kulkarni\n(Caltech) report on behalf of the larger Caltech-NRAO-CARA GRB\ncollaboration:\n\n\"We observed the transient position of GRB 000418 (Klose et al. GCN #645)\nwith the Echellette Spectrograph and Imager (ESI) on the Keck II 10-m\nTelescope on Mauna Kea at 2.318 May 2000 UT.  In a 1200-s exposure we\ndetect both broadband continuum and a strong doublet in emission at\nwavelengths Lambda = 7894.0,7899.4 Angstrom (preliminary reduction).  \nFurther observations of the source are in progress.\n\nWe attribute this doublet to [OII] emission from the underlying host\ngalaxy.  If so, this would place GRB 000418 at a redshift of \nz=1.11854 +/- 0.0007, placing it near the median of GRB redshifts thus far\nobtained. Assuming a flat lambda cosmology of H_0 = 65 km/s/Mpc, Omega_m =\n0.3, Omega_lam = 0.7 the luminosity distance to the GRB is \nD_L = 2.515 x 10^28 cm.  Since the total fluence of the burst is \n1.3 x 10^{-5} erg cm^{-2} (Hurley et al. GCN #642), we estimate the total\nisotropic energy release of the GRB to be E = 4.9 x 10^52 erg.\"\n\nThis message may be cited."}', 'Astronomers at Caltech report the detection of [OII] emission lines in the afterglow of GRB 000418 using the Echellette Spectrograph and Imager on the Keck II 10-m Telescope. The redshift measurement from the lines places GRB 000418 at z=1.11854 +/- 0.0007, and the estimated total isotropic energy release is E = 4.9 x 10^52 erg.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6609', 'gcn', 'GRB 070707', '2007-07-08T11:34:53.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":25.7,"other_measurements":{"observation_duration":"20 minutes","time_after_trigger":"11 hours"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["OAR (OAR is an acronym for Osservatorio Astrofisico di Arcetri)","INAF-OABr (INAF is the Italian National Institute for Astrophysics and OABr is the Osservatorio Astrofisico di Brera)","INAF-OAR"],"authors":["P. D''Avanzo","S. Piranomonte","L. Stella","G. Chincarini"],"institutions":["OAR","INAF-OABr","INAF-OAR","MISTICI collaboration"],"universities":["University of Geneva","INAF-OABr","INAF-OAR"]},"telescopes":{"facilities":["ESO"],"instruments":["FORS1"],"observatories":["ESO (European Southern Observatory)"],"telescopes":["VLT (Very Large Telescope)"]},"urls":["http://horde.org/imp/","<http://horde.org/imp/>"],"basic_data":{"author":{"email":"piranomonte@mporzio.astro.it","institution":"OAR","name":"Silvia Piranomonte"},"coordinates":{},"detectionTime":"2007-07-08T11:34:53.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6609\nSUBJECT: GRB 070707: VLT observations\nDATE: 07/07/08 11:34:53 GMT\nFROM: Silvia Piranomonte at OAR  <piranomonte@mporzio.astro.it>\n\nP. D''Avanzo (INAF-OABr), S. Piranomonte, L. Stella (INAF-OAR) and G.\nChincarini ((INAF-OABr) report on behalf of the MISTICI collaboration:\n\nWe observed the field of the short GRB 070707 (Beckmann et al., GCN\n6605; Gotz et al., GCN 6607) using FORS1 on the VLT telescope about 11\nhours after the trigger time. We obtained 20 minutes of R-band imaging.\n\nInside the refined INTEGRAL error circle (Gotz et al., GCN 6607) we do\nnot detect any obvious afterglow candidate down to the depth of the\nDSS image. Our 3-sigma limiting magnitude is R=25.7.\n\nFurther observations are planned. We acknowledge the ESO staff for\nreliable support.\n\nThis message can be cited.\n\n\n\n-------------------------------------------------\nThis mail sent through IMP: http://horde.org/imp/"}', 'The MISTICI collaboration reported observing the field of short gamma-ray burst GRB 070707 using FORS1 on the VLT telescope 11 hours after the trigger time. No obvious afterglow candidate was detected down to a limiting magnitude of R=25.7. Further observations are planned.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6608', 'gcn', 'GRB 070707', '2007-07-08T00:24:38.000Z', '{"measurements":{"dec":-68.9144,"distance":null,"duration":1.1,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"spectral_slope":1.4},"ra":267.7506,"redshift":null,"tables":[]},"authors":{"affiliations":["CEA Saclay","ISDC, Versoix","IASF, Milano"],"authors":["Diego Gotz","V. Beckmann","S. Mereghetti","A. Paizis"],"institutions":["IASF-CNR","ISDC","Versoix","IASF, Milano"],"universities":["IASF-CNR","ISDC","IASF, Milano"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"dgotz@cea.fr","institution":"IASF-CNR","name":"Diego Gotz"},"coordinates":{},"detectionTime":"2007-07-08T00:24:38.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6608\nSUBJECT: INTEGRAL GRB 070707 is a short hard burst\nDATE: 07/07/08 00:24:38 GMT\nFROM: Diego Gotz at IASF-CNR  <dgotz@cea.fr>\n\nD. Gotz (CEA Saclay), V. Beckmann (ISDC, Versoix), S. Mereghetti, and\nA. Paizis (IASF, Milano) on behalf of the IBAS localization Team report:\n\nA refined analysis of GRB 070707 shows that it is composed by a single\nspike lasting about 1.1 s, and its spectrum can be well fit with a power\nlaw of slope 1.4, indicating a rather hard spectrum.\n\nIts refined position is\n\nR.A. (J2000): 267.7506 [degrees]\nDEC. (J2000): -68.9144 [degrees]\n\nwith an uncertainty of 2.1 arcmin (90% c.l.)\n\nThis messages can be cited."}', 'Astronomers have refined their analysis of GRB 070707 and determined it to be a short, hard burst with a duration of 1.1 seconds and a spectral slope of 1.4. The refined position is R.A. (J2000): 267.7506 degrees, DEC. (J2000): -68.9144 degrees, with an uncertainty of 2.1 arcmin.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6607', 'gcn', 'GRB 070707', '2007-07-07T23:37:18.000Z', '{"measurements":{"dec":-68.9144,"distance":null,"duration":1.1,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"spectral_slope":1.4},"ra":267.7506,"redshift":null,"tables":[]},"authors":{"affiliations":["CEA Saclay","ISDC, Versoix","IASF, Milano"],"authors":["Diego Gotz","V. Beckmann","S. Mereghetti","A. Paizis"],"institutions":["IASF-CNR","ISDC","Versoix","IASF, Milano"],"universities":["IASF-CNR","ISDC","IASF, Milano"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"dgotz@cea.fr","institution":"IASF-CNR","name":"Diego Gotz"},"coordinates":{},"detectionTime":"2007-07-07T23:37:18.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6607\nSUBJECT: INTEGRAL GRB 070707 is a short hard burst\nDATE: 07/07/07 23:37:18 GMT\nFROM: Diego Gotz at IASF-CNR  <dgotz@cea.fr>\n\nD. Gotz (CEA Saclay), V. Beckmann (ISDC, Versoix), S. Mereghetti, and\nA. Paizis (IASF, Milano) on behalf of the IBAS localization Team report:\n\nA refined analysis of GRB 070707 shows that it is composed by a single\nspike lasting about 1.1 s, and its spectrum can be well fit with a power\nlaw of slope 1.4, indicating a rather hard spectrum.\n\nIts refined position is\n\nR.A. (J2000): 267.7506 [degrees]\nDEC. (J2000): -68.9144 [degrees]\n\nwith an uncertainty of 2.1 arcmin (90% c.l.)\n\nThis messages can be cited."}', 'Astronomers have refined their analysis of GRB 070707 and determined that it is a short, hard burst lasting approximately 1.1 seconds. The spectral slope of the burst is 1.4, indicating a rather hard spectrum. The refined position of the burst is at R.A. (J2000): 267.7506 degrees, DEC. (J2000): -68.9144 degrees, with an uncertainty of 2.1 arcmin.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6606', 'gcn', 'GRB 070707', '2007-07-07T23:05:21.000Z', '{"measurements":{"dec":-68.95,"distance":null,"duration":100,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":267.67,"redshift":null,"tables":[]},"authors":{"affiliations":["ISDC, Versoix","IASF-Milano","CEA-Saclay","CAMK, Torun"],"authors":["V. Beckmann","C. Ricci","M. Beck","S. Mereghetti","A. Paizis","D. Gotz","J. Borkowski"],"institutions":["ISDC (Institute for Space and Astronautical Science Data Centre)"],"universities":["University of Geneva (UNIGE)"]},"telescopes":{"facilities":["IBAS (International Gamma-Ray Astrophysics Laboratory)"],"instruments":["IBIS/ISGRI"],"observatories":[],"telescopes":["IBIS/ISGRI"]},"urls":["<Volker.Beckmann@obs.unige.ch>"],"basic_data":{"author":{"email":"Volker.Beckmann@obs.unige.ch","institution":"ISDC","name":"Volker Beckmann"},"coordinates":{"ra":2.1021305555555556},"detectionTime":"2007-07-07T23:05:21.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6606\nSUBJECT: GRB 070707: A long GRB detected by INTEGRAL\nDATE: 07/07/07 23:05:21 GMT\nFROM: Volker Beckmann at ISDC  <Volker.Beckmann@obs.unige.ch>\n\nV. Beckmann, C. Ricci, M. Beck (ISDC, Versoix), S. Mereghetti, A.  \nPaizis (IASF-Milano), D. Gotz (CEA-Saclay), and J. Borkowski (CAMK,  \nTorun) on behalf of the IBAS Localization Team report:\n\nA GRB lasting about 100 s has been detected by IBAS in IBIS/ISGRI data  \non July 7 at 16:08:21 UT.\n\nThe coordinates (J2000) are:\n\nRA:  267.67 [degrees]\nDEC: -68.95 [degrees]\n\nwith an uncertainty of 4 arcmin. The light curve is a single,  \nFRED-like peak. This message can be cited."}', 'A long gamma-ray burst (GRB) with a duration of approximately 100 seconds was detected by the IBIS/ISGRI instrument on the INTEGRAL satellite on July 7, 2007. The event, named GRB 070707, occurred at coordinates RA: 267.67 degrees, DEC: -68.95 degrees, with an uncertainty of 4 arcmin.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6605', 'gcn', 'GRB 070707', '2007-07-07T22:21:44.000Z', '{"measurements":{"dec":-68.95,"distance":null,"duration":100,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":267.67,"redshift":null,"tables":[]},"authors":{"affiliations":["ISDC, Versoix, Switzerland, IASF-Milano, Italy, CEA-Saclay, France, CAMK, Torun, Poland"],"authors":["V. Beckmann, C. Ricci, M. Beck, S. Mereghetti, A. Paizis, D. Gotz, J. Borkowski"],"institutions":["ISDC (Institute for Space and Astronomy Research in Cooperation), IASF-Milano (Instituto di Astrofisica Spaziale e Fisica del Plasma), CEA-Saclay (Commissariat à l''Énergie Atomique et aux Énergies Alternatives), CAMK (Casimir Pulaski University of Technology and Humanities)"],"universities":["University of Geneva (UNIGE)"]},"telescopes":{"facilities":["IBAS"],"instruments":["IBIS/ISGRI"],"observatories":["IBAS (International Gamma-Ray Astrophysics Laboratory)"],"telescopes":["IBIS/ISGRI (International Gamma-Ray Astrophysics Laboratory Imaging Spectrometer)"]},"urls":[""],"basic_data":{"author":{"email":"Volker.Beckmann@obs.unige.ch","institution":"ISDC","name":"Volker Beckmann"},"coordinates":{"ra":2.1021305555555556},"detectionTime":"2007-07-07T22:21:44.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6605\nSUBJECT: GRB 070707: A long GRB detected by INTEGRAL\nDATE: 07/07/07 22:21:44 GMT\nFROM: Volker Beckmann at ISDC  <Volker.Beckmann@obs.unige.ch>\n\nV. Beckmann, C. Ricci, M. Beck (ISDC, Versoix), S. Mereghetti, A.\nPaizis (IASF-Milano), D. Gotz (CEA-Saclay), and J. Borkowski (CAMK,\nTorun) on behalf of the IBAS Localization Team report:\n\nA GRB lasting about 100 s has been detected by IBAS in IBIS/ISGRI data\non July 7 at 16:08:21 UT.\n\nThe coordinates (J2000) are:\n\nRA:  267.67 [degrees]\nDEC: -68.95 [degrees]\n\nwith an uncertainty of 4 arcmin. The light curve is a single,\nFRED-like peak. This message can be cited."}', 'A long gamma-ray burst (GRB) lasting about 100 seconds was detected by the IBIS/ISGRI instrument on the International Gamma-Ray Astrophysics Laboratory (IBAS) on July 7, 2007. The event, named GRB 070707, occurred at coordinates RA: 267.67 degrees, DEC: -68.95 degrees, with an uncertainty of 4 arcmin.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6604', 'gcn', 'GRB 070429B', '2007-07-06T23:23:50.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":21.5,"other_measurements":{"exposure_time_per_image":"60 seconds","number_of_images_first_epoch":18,"observation_time_first_epoch":"06:10:28 UT on April 30, 2007","observation_time_second_epoch":"06:23:04 UT on June 2, 2007","time_since_burst_first_epoch":"1.13 days","time_since_burst_second_epoch":"34.2 days"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["STScI"],"authors":["M. Nysewander","A. Fruchter","J. Graham"],"institutions":["STScI"],"universities":["Stanford University School of Medicine","Space Telescope Science Institute"]},"telescopes":{"facilities":[],"instruments":["ISPI","ISIS2"],"observatories":["CTIO"],"telescopes":["Blanco 4-m"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"mnysewan@stsci.edu","institution":"STScI","name":"Melissa Nysewander"},"coordinates":{},"detectionTime":"2007-07-06T23:23:50.000Z","event":"GRB 070429B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6604\nSUBJECT: GRB 070429B: NIR Observations\nDATE: 07/07/06 23:23:50 GMT\nFROM: Melissa Nysewander at STScI  <mnysewan@stsci.edu>\n\nM. Nysewander, A. Fruchter and J. Graham (STScI) report on behalf of a \nlarger collaboration:\n\nWe observed the entire BAT error circle of the short GRB 070429B \n(Markwardt et al. GCN 6358) with ISPI on the Blanco 4-m at CTIO at a \nmean time of 06:10:28 UT on April 30, 2007 (1.13 days post burst) in 18 \nx 60-s J-band exposures, and again at a mean time of 06:23:04 UT on June \n2, 2007, (34.2 days post burst) with the same exposure sequence.\n\nDue to the questionable nature of the faint XRT afterglow candidate \n(Beardmore et al. GCN 6360), we searched the entire BAT error circle by \nsubtracting the two epochs using ISIS2 (Alard, 2000). We do not find any \nvariation between the two epochs to the limiting magnitude of the first \nepoch, J ~ 21.5. Specifically, the source within the XRT error circle \nnoted by Cucchiara et al. (GCN 6368) also did not vary between the two \nepochs."}', 'Astronomers led by Melissa Nysewander at STScI observed the error circle of short gamma-ray burst GRB 070429B using ISPI on the Blanco 4-m at CTIO 1.13 days and 34.2 days post-burst. They did not find any variation between the two epochs to a limiting magnitude of J ~ 21.5, indicating no significant afterglow emission from the burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6603', 'gcn', 'GRB070704', '2007-07-06T17:34:41.000Z', '{"measurements":{"dec":null,"distance":null,"duration":{"unit":"minutes","value":20},"energy":null,"fluence":null,"magnitude":[10.8,13],"other_measurements":{"frame_exposure":{"unit":"seconds","value":0.128},"frame_rate":{"unit":"frames per second","value":7.5},"temporal_resolution":{"unit":"seconds","value":12.8},"time_interval":{"unit":"seconds","value":182}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["SAO RAS, Russia","Russia"],"authors":["S. Karpov","G. Beskin","S. Bondar","E. Ivanov","E. Katkova","A. Pozanenko"],"institutions":["Special Astrophysical Observatory of Russian Academy of Sciences","Research Institute for Precision Instrumentation"],"universities":["Russian Academy of Sciences"]},"telescopes":{"facilities":[],"instruments":["FAVOR (FAst Variability Optical Registrator) wide-field fast camera"],"observatories":["Russia, North Caucasus"],"telescopes":["6-m telescope"]},"urls":[],"basic_data":{"author":{"email":"karpov@sao.ru","institution":"SAO RAS","name":"Sergey Karpov"},"coordinates":{},"detectionTime":"2007-07-06T17:34:41.000Z","event":"GRB070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6603\nSUBJECT: GRB070704: FAVOR optical observations\nDATE: 07/07/06 17:34:41 GMT\nFROM: Sergey Karpov at SAO RAS  <karpov@sao.ru>\n\nS. Karpov, G. Beskin (Special Astrophysical Observatory of Russian Academy of\n   Sciences, Russia), S. Bondar, E. Ivanov, E. Katkova (Research Institute for \nPrecision Instrumentation, Russia), A. Pozanenko (Space Research Institute, Russia)\n\nreport on behalf of the FAVOR team:\n\nThe field of GRB 070704 (Sakamoto et al, GCN 6594) has been observed by the\nFAVOR (FAst Variability Optical Registrator) wide-field fast camera (15 cm\ndiameter, 16x21 deg FOV) located in Russia, North Caucasus, near 6-m telescope\nsince UT 20:05:17 (40 seconds before BAT trigger, 25 seconds after actual burst\nonset), during the event and for 20 minutes after it with 7.5 frames per second\nacquisition rate (0.128 s frame exposure). The event occured on the edge of CCD\ndetector and has been affected by the image distortion. The authomatic data\nreduction and transient detection pipeline, based on the inspection of each\npixel statistical properties in time, has not detected any transient event at\nthe XRT position of the source with the limiting magnitude of 10.8 (3-sigma) in\nthe unfiltered light close to V on a single frame.\n\nWe performed additional study of the data on T-40s - T+142s time interval\n(i.e. prior to Swift/UVOT observations). Combining the sets of 100 consecutive\nimages we obtained an upper limit of 13.0 m (3-sigma) on the optical emission\nover this time span with temporal resolution of 12.8 s.\n\nThe message may be cited."}', 'The FAVOR team reported observing GRB 070704 with their wide-field fast camera since 20 minutes before the burst onset. No transient was detected with a limiting magnitude of 10.8 (3-sigma), but an upper limit of 13.0 m (3-sigma) was obtained for the optical emission over a 182-second time span. The event occurred on the edge of the CCD detector and was affected by image distortion.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6602', 'gcn', 'GRB 070704', '2007-07-06T12:50:15.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"observation_duration_hours":4.2},"ra":null,"redshift":null,"tables":[{"Filter":"r''","Lim":23,"Tot_Exp (s)":1800,"t_mid (hr from GRB)":4.26},{"Filter":"i''","Lim":23.3,"Tot_Exp (s)":1800,"t_mid (hr from GRB)":5.1}]},"authors":{"affiliations":["Liverpool JMU","U. Leicester"],"authors":["A. Melandri","E. Rol","N. Tanvir"],"institutions":["RoboNet GRB collaboration"],"universities":["Liverpool John Moores U"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["2-m Liverpool Telescope"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6598","http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6594"],"basic_data":{"author":{"email":"axm@astro.livjm.ac.uk","institution":"Liverpool John Moores U","name":"Andrea Melandri"},"coordinates":{},"detectionTime":"2007-07-06T12:50:15.000Z","event":"GRB 070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6602\nSUBJECT: GRB 070704 : Liverpool Telescope Observations\nDATE: 07/07/06 12:50:15 GMT\nFROM: Andrea Melandri at Liverpool John Moores U  <axm@astro.livjm.ac.uk>\n\nA. Melandri (Liverpool JMU), E. Rol, N. Tanvir (U. Leicester)\nreport on behalf of the RoboNet GRB collaborationon:\n\n\nWe observed the field of GRB 070704 (trigger=283791, Sakamoto\net al., GCN 6594) with the 2-m Liverpool Telescope about 4.2\nhours after the trigger time.\n\nAt the revised XRT position (Godet & Sakamoto, GCN 6598) we do\nnot detect any new object in stacked images down to:\n\n\nFilter    t_mid (hr from GRB)    Tot_Exp (s)       Lim\n--------------------------------------------------------------\n   r''           4.26                 1800           23.0\n   i''           5.10                 1800           23.3\n--------------------------------------------------------------\n\n\nMagnitudes were calibrated vs R2 and I USNO-B1 magnitude for\nfew selected stars."}', 'The Liverpool Telescope team, on behalf of the RoboNet GRB collaboration, reported no detection of a new object in the field of GRB 070704 using the 2-m Liverpool Telescope about 4.2 hours after the trigger time. They did not detect any object in stacked images in the r'' and i'' filters with limits of 23.0 and 23.3 magnitudes, respectively.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6601', 'gcn', 'GRB 070611', '2007-07-06T09:59:43.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":-5.3,"other_measurements":{"dm":5.3,"dm_error":0.3,"observation_duration":4200,"observation_duration_unit":"s","time_since_burst":4.26,"time_since_burst_acquisition":7.58,"time_since_burst_acquisition_unit":"hr","time_since_burst_unit":"days"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U. Hertfordshire","DARK, NBI"],"authors":["Pall Jakobsson","Daniele Malesani","Dong Xu","Johan P.U. Fynbo","Jens Hjorth","Christina C. Thoene"],"institutions":["DARK, NBI"],"universities":["University of Hertfordshire"]},"telescopes":{"facilities":[],"instruments":["FORS1"],"observatories":["European Southern Observatory"],"telescopes":["Very Large Telescope"]},"urls":["http://star-www.herts.ac.uk/~palli/grb070611/grb070611.jpg"],"basic_data":{"author":{"email":"P.Jakobsson@herts.ac.uk","institution":"U Hertfordshire","name":"Pall Jakobsson"},"coordinates":{},"detectionTime":"2007-07-06T09:59:43.000Z","event":"GRB 070611","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6601\nSUBJECT: GRB 070611: VLT observations\nDATE: 07/07/06 09:59:43 GMT\nFROM: Pall Jakobsson at U Hertfordshire  <P.Jakobsson@herts.ac.uk>\n\nPall Jakobsson (U. Hertfordshire), Daniele Malesani,\nDong Xu, Johan P.U. Fynbo, Jens Hjorth and Christina\nC. Thoene (DARK, NBI) report:\n\nUsing FORS1 on the Very Large Telescope during\nnon-photometric conditions, we obtained a total of\n4200 s R-band imaging of the GRB 070611 field\n(Stroh et al., GCN 6494) on June 15.375 (4.26 days\nafter the burst). On the edge of the refined XRT circle\n(Butler 2007, AJ, 133, 1027; DSS catalog; version 3.6),\nwe clearly detect a source that is consistent with the\nUVOT position (Landsman et al., GCN 6504).\n\nCompared to the acquisition image obtained on June 11.040\n(7.58 hr post-burst; Thoene et al., GCN 6499), the source\nhas faded by dm = 5.3 +/- 0.3 mag. If the optical afterglow\ndisplays a similar fading behaviour as the X-ray afterglow\nwith a possible jet-break around 1 day (Stroh et al.,\nGCN Report 63.3), we would expect dm = 3.5 +/- 1.4 mag.\nThus, the VLT observations are marginally consistent with a\nbreak occurring in the optical band as well.\n\nWe note that the source is somewhat extended at the latter\nepoch, implying that the host might contribute to the flux\nand hence the observed dm could be larger. An image of the\nfield (on June 15.375) is shown at:\n\nhttp://star-www.herts.ac.uk/~palli/grb070611/grb070611.jpg"}', 'A team led by Pall Jakobsson at the University of Hertfordshire reported the detection of a fading source in the field of GRB 070611 using the Very Large Telescope''s FORS1 during non-photometric conditions. The source, located on the edge of the refined XRT circle, is consistent with the UVOT position and has faded by 5.3 ± 0.3 mag since the acquisition image obtained 7.58 hours post-burst. The observations suggest that a break might be occurring in the optical band, but the source appears somewhat extended, implying that the host might contribute to the flux.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6600', 'gcn', 'GRB 070612A', '2007-07-05T21:49:36.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"flux_density":{"error":56,"unit":"uJy","value":189},"frequency":{"unit":"GHz","value":4.88}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U Virginia/NRAO","NRAO"],"authors":["Poonam Chandra","Dale A. Frail"],"institutions":["NRAO","Caltech-NRAO-Carnegie GRB Collaboration"],"universities":["University of Virginia","Caltech"]},"telescopes":{"facilities":["National Science Foundation"],"instruments":[],"observatories":["National Radio Astronomy Observatory"],"telescopes":["Very Large Array"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6600"],"basic_data":{"author":{"email":"pc8s@virginia.edu","institution":"U Virginia/NRAO","name":"Poonam Chandra"},"coordinates":{},"detectionTime":"2007-07-05T21:49:36.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6600\nSUBJECT: VLA detection of GRB 070612A in C Band\nDATE: 07/07/05 21:49:36 GMT\nFROM: Poonam Chandra at U Virginia/NRAO  <pc8s@virginia.edu>\n\nPoonam Chandra (NRAO/UVA) and Dale A. Frail (NRAO) report on behalf of \nthe Caltech-NRAO-Carnegie GRB Collaboration:\n\n\n\n\"We used the Very Large Array to observe the field of view toward GRB\n070612A (GCN 6509) at a frequency of 4.88 GHz on 2007 June 30th  at\n20.66 UT.  We detect the GRB afterglow at P60 optical afterglow position\n(GCN 6517). The flux density of the GRB is 189+/-56 uJy. \n\n\nThe National Radio Astronomy Observatory is a facility of the National\nScience Foundation operated under cooperative agreement by Associated\nUniversities, Inc.\""}', 'The Very Large Array (VLA) at the National Radio Astronomy Observatory detected the afterglow of GRB 070612A at a frequency of 4.88 GHz, with a flux density of 189+/-56 uJy.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-660', 'gcn', 'GRB000424', '2000-05-02T16:51:39.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"unit":"R","value":22.8},"other_measurements":{"exposure_time":[{"unit":"times","value":6},{"unit":"seconds","value":600}],"seeing":[{"unit":"\"","value":1.5},{"unit":"\"","value":1}]},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Caltech"],"authors":["S. Yost","A. Diercks","F. Harrison","R. Gal","V. Hradecky","D. Kaplan","A. Mahabal","P. Mao"],"institutions":["Caltech - Solar Radiation Laboratory (SRL)"],"universities":["Caltech"]},"telescopes":{"facilities":[],"instruments":["CCD 13"],"observatories":[],"telescopes":["Palomar 60"]},"urls":[],"basic_data":{"author":{"email":"yost@srl.caltech.edu","institution":"Caltech","name":"Sarah Yost"},"coordinates":{},"detectionTime":"2000-05-02T16:51:39.000Z","event":"GRB000424","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 660\nSUBJECT: GRB000424, optical observations\nDATE: 00/05/02 16:51:39 GMT\nFROM: Sarah Yost at Caltech  <yost@srl.caltech.edu>\n\nS. Yost, A. Diercks, F. Harrison, R. Gal, V. Hradecky, D. Kaplan,\nA. Mahabal, P. Mao (Caltech) report:\n\n\"We imaged the entire error circle of GRB000424 (Piro, GCN #644) with the \nCCD 13 instrument on the Palomar 60\" telescope on two consecutive nights.\nExposures consisted of R-band 6x600s on April 27.17 UT and 7x600s on April\n28.19 UT with seeing of approximately 1.5\" and 1\" respectively.\nSubtraction of the two epochs reveals no variable candidates to the\ndetection limit of approximately R ~ 22.8 (field calibration by comparison\nwith USNO data).\"\n \nThis message may be cited."}', 'Astronomical alert: GRB000424, optical observations', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6599', 'gcn', 'GRB 070626', '2007-07-05T16:38:28.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["Ioffe Inst, on behalf of the Konus-Wind team"],"authors":["S. Golenetskii","R. Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline"],"institutions":["Ioffe Inst"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":[],"instruments":["Konus-Wind"],"observatories":[],"telescopes":["Konus-Wind"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-07-05T16:38:28.000Z","event":"GRB 070626","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6599\nSUBJECT: Konus-Wind observation of GRB 070626\nDATE: 07/07/05 16:38:28 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team:\n\nWe report further analysis of the bright long GRB 070626\nlocalized by IPN (Golenetskii  et al., GCN 6592).\n\nAs observed by Konus-Wind the burst\nhad a fluence of 3.91(-0.13, +0.16)x10^-4 erg/cm2,\nand a 64-ms peak flux measured from T0+73.216 s\n1.94(-0.16, +0.20)x10^-5 erg/cm2/s\n(both in the 20 keV - 4 MeV energy range).\n\nThe time-integrated spectrum of the burst\n(from T0 to T0+187.905 s: this interval comprises ~93%\nof the burst total counts) can be fitted\n(in the 20 keV - 4 MeV range)\nby GRBM (Band) model for which:\nthe low-energy photon index is alpha = -1.45 (-0.03, +0.04),\nthe high energy photon index beta = -2.28 (-0.12, +0.08),\nthe peak energy Ep = 226 (-17, +19) keV (chi2 = 79/68 dof).\n\nThe spectrum of the burst maximum\n(accumulated from T0+72.192 s to T0+74.752 s)\nis well fitted (in the 20 keV - 4 MeV range)\nby GRBM (Band) model for which:\nthe low-energy photon index is alpha = -1.27 (-0.07, +0.08),\nthe high energy photon index beta = -2.51 (-0.88, +0.27),\nthe peak energy Ep = 355 (-62, +69) keV (chi2 = 77/69 dof).\n\nAll the quoted errors are at the 90% confidence level."}', 'The Konus-Wind team reports the analysis of GRB 070626, a bright long gamma-ray burst localized by IPN. The burst had a fluence of 3.91x10^-4 erg/cm2 and a peak flux of 1.94x10^-5 erg/cm2/s in the 20 keV - 4 MeV energy range. The time-integrated and maximum spectra were fitted with the GRBM (Band) model, with different low-energy and high-energy photon indices and peak energies.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6598', 'gcn', 'GRB 070704', '2007-07-05T11:43:49.000Z', '{"measurements":[{"column_name":"Time","value":"T0+153s to T0+3e4s"},{"column_name":"Photon Index","value":1.85},{"column_name":"Column Density","value":"1.08e22 cm^-2"},{"column_name":"Flux (Absorbed)","value":"(1.57+/-0.05)E-9 ergs cm^-2 s^-1"},{"column_name":"Flux (Unabsorbed)","value":"2.85E-9 ergs cm^-2 s^-1"},{"column_name":"Photon Index (PC Data)","value":1.97},{"column_name":"Flux (Absorbed, PC Data)","value":"(3.3 +0.6/-0.8)E-12 ergs cm^-2 s^-1"},{"column_name":"Flux (Unabsorbed, PC Data)","value":"6.54E-12 ergs cm^-2 s^-1"}],"authors":{"affiliations":["U. Leicester","GSFC/ISAS"],"authors":["O. Godet","T. Sakamoto"],"institutions":["GSFC/ISAS"],"universities":["U. of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift XRT","UVOT"],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"og19@star.le.ac.uk","institution":"U.of Leicester","name":"Olivier Godet"},"coordinates":{"dec":23.64661111111111},"detectionTime":"2007-07-05T11:43:49.000Z","event":"GRB 070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6598\nSUBJECT: GRB 070704: Swift-XRT refined analysis\nDATE: 07/07/05 11:43:49 GMT\nFROM: Olivier Godet at U.of Leicester  <og19@star.le.ac.uk>\n\nO. Godet (U. Leicester) & T. Sakamoto (GSFC/ISAS) report on behalf the\nSwift/XRT team\n\nWe have analysed the first 8.5ks of Swift XRT PC and WT data of GRB\n070704 (Sakamoto et al., GCN Circ. 6594) taken from T0+153s to T0+3e4s. \nUsing 129 s of overlapping XRT Photon Counting mode and UVOT V-band\ndata, we find an astrometrically corrected X-ray position (using the\nXRT-UVOT alignment and matching UVOT field sources to the USNO-B1\ncatalogue): RA, Dec = 354.69915, +66.25328 which is equivalent to:\n\nRA (J2000):  23 38 47.80\nDec (J2000): +66 15 11.8\n\nwith an uncertainty of 2.7 arcsec (90% confidence). This is 3.7 arcsec\nfrom the initially reported XRT position and 39.4 arcsec from the BAT\nposition (GCN Circ. 6594).\n\nThe XRT light curve exhibits an initial decay on which is superposed a\nlarge flare peaking around T0+300s. We note that between T0+250s and T0\n+410s an emission was also detected in the BAT (Markwardt et al., GCN\nCirc. 6596). The light-curve from T0+600s to T0+3e4s is fit well by a\npower-law with a decay index of 0.87 +0.11/-0.12. \n\nThe spectrum of the WT data from T0+153s to T0+527s is fit well by an\nabsorbed power-law with a photon index of 1.85 +/-0.06 and column\ndensity of N_H = (1.08+/-0.06)e22 cm^-2 in excess of the Galactic value\n(8.6E21 cm^-2; Dickey & Lockman, 1990). The absorbed (unabsorbed)\n0.3-10.0keV flux for that spectrum is (1.57+/-0.05)E-9 (2.85E-9) ergs\ncm^-2 s^-1. The spectrum of the PC data from T0+530s to T0+3e4s is fit\nwell by an absorbed power-law with a photon index of 1.97+/-0.27 with\nN_H fixed at 1.08e22 cm^-2. The absorbed (unabsorbed) 0.3-10.0keV flux\nfor that spectrum is (3.3 +0.6/-0.8)E-12 (6.54E-12) ergs cm^-2 s^-1.\n\nAssuming the source continues to decay at the same rate, we predict an\nXRT count rate of 0.0044 counts/s at T0+24 hours, which corresponds to\nan observed (unabsorbed) flux of 6.2E-13 (2.9E-12) ergs cm^-2 s^-1.\n\nThis circular is an official product of the Swift XRT team."}', 'The Swift XRT team has released an updated analysis of GRB 070704, reporting a refined X-ray position with an uncertainty of 2.7 arcsec and a significant discrepancy from previously reported positions. The XRT light curve exhibits a power-law decay with a decay index of 0.87, and the spectrum is best fit by an absorbed power-law with a photon index of 1.85 and a column density of 1.08e22 cm^-2. The team predicts an XRT count rate of 0.0044 counts/s at T0+24 hours.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6597', 'gcn', 'GRB070704', '2007-07-05T10:16:46.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"BAT trigger delay":{"Unit":"s","Value":142},"Galactic extinction":{"E_{B-V}":1.81,"Unit":"mag"}},"ra":null,"redshift":null,"tables":[{"Exp(s)":597,"Filter":"V","Mag (3-sigma upper limit)":19.16,"T_mid(s)":654},{"Exp(s)":10,"Filter":"B","Mag (3-sigma upper limit)":17.56,"T_mid(s)":749},{"Exp(s)":20,"Filter":"U","Mag (3-sigma upper limit)":17.64,"T_mid(s)":729},{"Exp(s)":439,"Filter":"UVW1","Mag (3-sigma upper limit)":18.91,"T_mid(s)":5603},{"Exp(s)":239,"Filter":"UVM2","Mag (3-sigma upper limit)":19.36,"T_mid(s)":4431},{"Exp(s)":220,"Filter":"UVW2","Mag (3-sigma upper limit)":19.27,"T_mid(s)":5697},{"Exp(s)":209,"Filter":"White","Mag (3-sigma upper limit)":19.65,"T_mid(s)":574}]},"authors":{"affiliations":["MSSL-UCL","NASA/ORAU"],"authors":["P. Schady","T. Sakamoto"],"institutions":["MSSL (Mullard Space Science Laboratory)"],"universities":["University College London (UCL)"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"ps@mssl.ucl.ac.uk","institution":"MSSL/Swift","name":"Patricia Schady"},"coordinates":{},"detectionTime":"2007-07-05T10:16:46.000Z","event":"GRB070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6597\nSUBJECT: Swift/UVOT Observations of GRB070704\nDATE: 07/07/05 10:16:46 GMT\nFROM: Patricia Schady at MSSL/Swift  <ps@mssl.ucl.ac.uk>\n\nP. Schady (MSSL-UCL) and T. Sakamoto (NASA/ORAU) report on the behalf of the \nSwift UVOT team:\n\nThe Swift/UVOT observed the field of GRB 070704 starting 142 s after the \nBAT trigger (Sakamoto et al. 2007, GCN Circ. 6594).  We do not find any \nsource, in any of the UVOT observations, inside the XRT error circle \n(Sakamoto et al. 2007, GCN Circ. 6594).\n\nThe 3-sigma upper limits for detecting a source inside the refined XRT \nerror circle in the initial data products are:\n\nFilter    T_mid(s) Exp(s) Mag (3-sigma upper limit)\n-------------------------------------------------------\nV         654      597    19.16\nB         749      10     17.56\nU         729      20     17.64\nUVW1      5603     439    18.91\nUVM2      4431     239    19.36\nUVW2      5697     220    19.27\nWhite     574      209    19.65\n-----------------------------------------------------------------\n\nwhere T_mid is the weighted mid time of the coadded exposure. The values \nquoted above are not corrected for the expected Galactic extinction \ncorresponding to a reddening of E_{B-V} = 1.81 mag in the direction of the \nburst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reported no detection of a source within the error circle of GRB 070704 using UVOT observations started 142 seconds after the BAT trigger. The team provided 3-sigma upper limits for detecting a source in various filters, which were not corrected for Galactic extinction.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6596', 'gcn', 'GRB 070704', '2007-07-04T23:50:57.000Z', '{"measurements":{"dec":"66d 15'' 25\"","distance":null,"duration":"380 +- 10 sec","energy":null,"fluence":"5.9 +- 0.3 x 10^-6 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"42%","peak_photon_flux":"2.1 +- 0.2 ph/cm2/sec","time_averaged_power_law_index":"1.79 +- 0.08"},"ra":"23h 38m 49.6s","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/UMD","GSFC","GSFC/UMBC","LANL","GSFC/ORAU","GSFC/USRA","GWU"],"authors":["C. Markwardt","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","NASA/UMD","GSFC/UMBC","LANL","GSFC/ORAU","GSFC/USRA","GWU"],"universities":["University of Maryland","University of Maryland, Baltimore County","George Washington University","Los Alamos National Laboratory","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-04T23:50:57.000Z","event":"GRB 070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6596\nSUBJECT: GRB 070704, Swift-BAT refined analysis\nDATE: 07/07/04 23:50:57 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nC. Markwardt (GSFC/UMD), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), D. Palmer (LANL), A. Parsons (GSFC),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nJ. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-239 to T+523 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 070704 (trigger #283791)\n(Sakamoto, et al., GCN Circ. 6594).  The BAT ground-calculated position is\nRA, Dec = 354.707, 66.257 deg  which is \n   RA(J2000)  = 23h 38m 49.6s \n   Dec(J2000) = 66d 15'' 25\" \nwith an uncertainty of 1.6 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 42%.\n \nThe mask-weighted light curve shows the burst started at ~T-65 sec when\nSwift was executing a preplanned slew.  There are multiple peaks with\ndecreasing amplitude with time.  The burst almost returns to background\nduring T+110 to T+230 sec, but then has emission from T+250 to T+410 sec.\nT90 (15-350 keV) is 380 +- 10 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-57.3 to T+400.8 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.79 +- 0.08.  The fluence in the 15-150 keV band is 5.9 +- 0.3 x 10^-6 erg/cm2.\nThe 1-sec peak photon flux measured from T-53.10 sec in the 15-150 keV band\nis 2.1 +- 0.2 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'The Swift-BAT team reported a refined analysis of GRB 070704 (trigger #283791), with a ground-calculated position of RA: 23h 38m 49.6s, Dec: 66d 15'' 25'''' and an uncertainty of 1.6 arcmin. The burst started around T-65 sec, had multiple peaks with decreasing amplitude, and showed emission from T+250 to T+410 sec. The duration was estimated to be 380 ± 10 sec, and the time-averaged spectrum was best fit by a simple power-law model with an index of 1.79 ± 0.08. The fluence in the 15-150 keV band was 5.9 ± 0.3 x 10^-6 erg/cm2, and the 1-sec peak photon flux was 2.1 ± 0.2 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6595', 'gcn', 'GRB 070704', '2007-07-04T22:47:59.000Z', '{"measurements":{"dec":66.25226,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"distance_from_bat_position":40.8,"distance_from_bat_position_unit":"arcseconds","flux_energy_range":"0.2-10 keV","flux_unit":"erg/cm2/s","initial_flux":3.7e-10,"uncertainty":5.5,"uncertainty_unit":"arcseconds"},"ra":354.69922,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC (on behalf of the Swift Team)","NASA/ORAU"],"authors":["Takanori Sakamoto"],"institutions":["NASA/GSFC","NASA/ORAU"],"universities":["NASA"]},"telescopes":{"facilities":[],"instruments":["XRT","BAT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"takanori@milkyway.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Takanori Sakamoto"},"coordinates":{"dec":3.0846386722222223},"detectionTime":"2007-07-04T22:47:59.000Z","event":"GRB 070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6595\nSUBJECT: GRB 070704: Correction to GCN Circ 6594\nDATE: 07/07/04 22:47:59 GMT\nFROM: Takanori Sakamoto at NASA/GSFC  <takanori@milkyway.gsfc.nasa.gov>\n\nT. Sakamoto (NASA/ORAU) on behalf of the Swift Team:\n\nThe XRT paragraph in the GCN 6594 contains a error.  We stated \nthat the XRT position was \"outside\" the BAT error circle -- it is, \nin fact, inside.  The corrected XRT paragraph is:\n\nThe XRT began observing the field at 20:08:30 UT, 153 seconds after the\nBAT trigger. The on-board XRT position was not correct, because the \nalgorithm centroided on a hot pixel.  From the ground data analysis,  \na moderately bright and uncatalogued X-ray source was found \nat RA, Dec 354.69922, + 66.25226 which is\n   RA(J2000)  =  23h 38m 47.8s\n   Dec(J2000) =  66d 15'' 08.1\"\nwith an uncertainty of 5.5 arcseconds (radius, 90% containment). \nThis location is 40.8 arcseconds from the BAT on-board position \nand within the BAT error circle.  The initial flux in the 2.5s \nimage was 3.7e-10 erg/cm2/s (0.2-10 keV). \n\nWe apologize for the mistake.  We would like to thank Alex Kann \nfor pointing the error."}', 'A correction was made to a previous GCN circular (6594) regarding GRB 070704. The X-ray source detected by the Swift XRT was initially reported as being outside the BAT error circle, but it is actually inside, with a position of RA = 23h 38m 47.8s, Dec = 66d 15'' 08.1'''' and an uncertainty of 5.5 arcseconds. The initial X-ray flux was 3.7e-10 erg/cm2/s in the 0.2-10 keV energy range.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6594', 'gcn', 'GRB 070704', '2007-07-04T20:40:31.000Z', '{"measurements":{"dec":66.248,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"bat_trigger_time":"20:05:57 UT","bat_uncertainty_radius":"3 arcmin","bat_xrt_distance":"40.8 arcseconds","initial_flux_value":"3.7e-10 erg/cm2/s (0.2-10 keV)","uvot_v_filter_exposure":"400 seconds","uvot_white_filter_exposure":"100 seconds","xrt_observation_start":"20:08:30 UT","xrt_uncertainty_radius":"5.5 arcseconds"},"ra":354.723,"redshift":null,"tables":[{"column_name":"initial_flux","value":"3.7e-10 erg/cm2/s"}]},"authors":{"affiliations":["NASA/ORAU","GSFC","U Leicester","PSU","GSFC/UMCP","GSFC/ISAS","INAF-IASFPA"],"authors":["T. Sakamoto","S. D. Barthelmy","A. P. Beardmore","M. M. Chester","N. Gehrels","O. Godet","S. T. Holland","S. Immler","F. E. Marshall","P. T. O''Brien","D. M. Palmer","G. Sato","B. Sbarufatti","R. L. C. Starling"],"institutions":["NASA/ORAU","GSFC","CRESST/GSFC/USRA","UMCP","ISAS","INAF-IASFPA"],"universities":["University of Leicester","Penn State University","LANL"]},"telescopes":{"facilities":[],"instruments":["BAT","XRT","UVOT"],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":3.0846452777777777},"detectionTime":"2007-07-04T20:40:31.000Z","event":"GRB 070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6594\nSUBJECT: GRB 070704: Swift detection of a burst\nDATE: 07/07/04 20:40:31 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nT. Sakamoto (NASA/ORAU), S. D. Barthelmy (GSFC),\nA. P. Beardmore (U Leicester), M. M. Chester (PSU),\nN. Gehrels (NASA/GSFC), O. Godet (U Leicester),\nS. T. Holland (CRESST/GSFC/USRA), S. Immler (GSFC/UMCP),\nF. E. Marshall (NASA/GSFC), P. T. O''Brien (U Leicester),\nD. M. Palmer (LANL), G. Sato (GSFC/ISAS), B. Sbarufatti (INAF-IASFPA)\nand R. L. C. Starling (U Leicester) report on behalf of the Swift\nTeam:\n\nAt 20:05:57 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070704 (trigger=283791).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 354.723, +66.248 which is \n   RA(J2000)  =  23h 38m 54s\n   Dec(J2000) = +66d 14'' 52\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve does not show anything\nsignificant, as is typical for image-trigger events.  There is a possibility\nthat the burst started at ~T-70 sec, but since Swift was executing\na preplanned slew from ~T-35 to T_0 sec, it is difficult to interpret\nthe TDRSS lightcurve. \n\nThe XRT began observing the field at 20:08:30 UT, 153 seconds after the\nBAT trigger. The on-board XRT position was not correct, because the algorithm \ncentroided on a hot pixel. \nFrom the ground data analysis,  a moderately bright and uncatalogued X-ray \nsource was found at RA, Dec 354.69922, + 66.25226 which is\n   RA(J2000)  =  23h 38m 47.8s\n   Dec(J2000) =  66d 15'' 08.1\"\nwith an uncertainty of 5.5 arcseconds (radius, 90% containment). \nThis location is 40.8 arcseconds from the BAT on-board position,\noutside the BAT error circle. The initial flux in the 2.5s image\nwas 3.7e-10 erg/cm2/s (0.2-10 keV). \n\nUVOT took a finding chart exposure of 100 seconds with the White\n(160-650 nm) filter starting 158 seconds after the BAT trigger, and a\nfinding chart exposure of 400 seconds with the V filter starting 265\nseconds after the BAT trigger. No afterglow candidate has been found\nin the initial data products. The 8''x8'' region for the list of\nsources generated on-board covers 100% of the BAT and XRT error\ncircles. The 2.7''x2.7'' sub-image does not cover the XRT error circle. \nThe list of sources is typically complete to about 18.0 mag. No\ncorrection has been made for the large, but uncertain extinction\nexpected. \n\nBurst Advocate for this burst is T. Sakamoto (takanori AT milkyway.gsfc.nasa.gov). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift satellite detected a gamma-ray burst (GRB 070704) at 20:05:57 UT with a calculated location of RA: 23h 38m 54s, Dec: +66d 14'' 52'''' (uncertainty: 3 arcmin). The X-ray Telescope (XRT) began observing 153 seconds later but initially identified an incorrect position due to a hot pixel. The correct position, RA: 23h 38m 47.8s, Dec: 66d 15'' 8.1'''' (uncertainty: 5.5 arcseconds), was 40.8 arcseconds from the BAT position. The initial X-ray flux was 3.7e-10 erg/cm2/s (0.2-10 keV). No afterglow candidate was found in the initial data from the Ultraviolet/Optical Telescope (UVOT).', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6593', 'gcn', 'GRB 070626', '2007-07-04T13:48:52.000Z', '{"measurements":{"dec":null,"distance":null,"duration":[120,210],"energy":[{"unit":"keV","value":100},{"unit":"keV","value":1000},{"unit":"keV","value":120},{"unit":"MeV","value":2},{"unit":"keV","value":600},{"unit":"keV","value":50}],"fluence":{"error":0.01,"unit":"x 10^-4 erg/cm^2","value":2.25},"magnitude":null,"other_measurements":{"Epeak":{"error":50,"unit":"keV","value":600},"alpha":{"error":0.05,"unit":"","value":-1.55},"beta":{"error":0.05,"unit":"","value":-2.15},"peak_flux":{"error":0.2,"unit":"photons/cm^2/sec","value":19.5}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"yamaoka@phys.aoyama.ac.jp","institution":"Aoyama Gakuin U","name":"Kazutaka Yamaoka"},"coordinates":{},"detectionTime":"2007-07-04T13:48:52.000Z","event":"GRB 070626","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6593\nSUBJECT: GRB 070626: Suzaku/WAM observation of the prompt emission\nDATE: 07/07/04 13:48:52 GMT\nFROM: Kazutaka Yamaoka at Aoyama Gakuin U  <yamaoka@phys.aoyama.ac.jp>\n\nY. Terada, T. Tamagawa (RIKEN), M. Ohno, T. Uehara, T. Takahashi, \nY. Fukazawa, C. Kira (Hiroshima U.), K. Yamaoka, Y. E. Nakagawa, \nS. Sugita (Aoyama Gakuin U.), K. Morigami, N. Kodaka, K. Onda, \nM. Tashiro, M. Suzuki, Y. Urata, A. Endo (Saitama U.), T. Enoto, \nR. Miyawaki, K. Nakazawa, K. Makishima (Univ. of Tokyo), E. Sonoda, \nM. Yamauchi, S. Maeno, H. Tanaka, R. Hara (Univ. of Miyazaki), \nM. Kokubun, M. Suzuki, T. Takahashi (ISAS/JAXA), S. Hong (Nihon U.), \non behalf of the Suzaku WAM team, report:\n\nThe long burst, GRB 070626 (S. Golenetskii et al. GCN 6592) was\ndetected at 2007-06-26 04:07:30 UT (= T0) with the Suzaku Wide-band All-sky\nMonitor (WAM), which covers an energy range of 50 keV - 5 MeV. The burst\ncontinues from T= T0-120 sec to T0+210 sec, as already reported on GCN\n6592. The object position reported by GCN 6592 corresponds to the\nincident angle of (theta, phi) = (103 deg, 169 deg) to the HXD WAM,\nwhere the energy response is well calibrated. \nThe fluence in the 100 -- 1000 keV energy band was 2.25(+- 0.01) x\n10^-4 erg/cm2, and the 1-sec peak flux was 19.5 +/- 0.2 photons/cm^2/sec \nin the same energy range.\n\nAccording to preliminary analyses, the time averaged spectrum from T0\nto T0+190 sec in the 120 keV to 2.0 MeV energy band can be reproduced by \nthe Band function (Band et al. 1993, ApJ 413, p281) with the following \nparameters;\n  alpha = -1.55 +/- 0.05, \n  beta  = -2.15 +/- 0.05, and\n  Epeak =   600 +/- 50 keV.\n\nAll the quoted errors are at the 90% confidence level, while systematic \nerrors are not included. Since the on-board trigger system was disabled \nat the time of T0, no BST mode data with a time resolution of 15.625\nmsec is available, and the spectral analyses were performed by the \ncontinuous monitoring (TRN) data with the 1 sec resolution.\n\nThe light curve data with 1 sec resolution will be appeared at the web site \n http://www.astro.isas.ac.jp/suzaku/HXD-WAM/WAM-GRB/grb/untrig/grb_table.html"}', 'GRB 070626, a long gamma-ray burst detected by Suzaku/WAM on June 26, 2007, was analyzed. The burst occurred in the energy range of 50 keV - 5 MeV and lasted from 4 seconds before to 214 seconds after the trigger time. The fluence in the 100-1000 keV energy band was 2.25 x 10^-4 erg/cm2, and the peak flux was 19.5 photons/cm2/sec. Preliminary spectral analysis suggested the presence of a Band function with parameters alpha = -1.55 +/- 0.05, beta = -2.15 +/- 0.05, and Epeak = 600 +/- 50 keV.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6592', 'gcn', 'GRB 070626', '2007-07-03T16:07:58.000Z', '{"measurements":[{"Dec(2000)":-39.872,"RA(2000)":139.529},{"Dec(2000)":-40.02,"RA(2000)":142.903},{"Dec(2000)":-39.805,"RA(2000)":143.21},{"Dec(2000)":-39.673,"RA(2000)":139.838}],"authors":{"affiliations":["Konus-Wind team","MESSENGER and RHESSI GRB teams","Suzaku WAM GRB team"],"authors":["S. Golenetskii","R. Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline","K. Hurley","J. Goldsten","D. M. Smith","R. P. Lin","J. McTiernan","R. Schwartz","C. Wigger","W. Hajdas","A. Zehnder","K. Yamaoka","M. Ohno","Y. Fukazawa","T. Takahashi","M. Tashiro","Y. Terada","T. Murakami","K. Makishima"],"institutions":["Ioffe Inst","MESSENGER","RHESSI","Suzaku"],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Ioffe Inst","Suzaku"],"telescopes":["Konus-Wind","Suzaku","RHESSI","MESSENGER neutron spectrometer"]},"urls":["http://www.ioffe.rssi.ru/LEA/GRBs/GRB070626_T14850/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-07-03T16:07:58.000Z","event":"GRB 070626","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6592\nSUBJECT: GRB 070626: IPN localization and Konus spectrum of a bright long burst\nDATE: 07/07/03 16:07:58 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R. Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team,\n\nK. Hurley, J. Goldsten, D. M. Smith, R. P. Lin, J. McTiernan, R. \nSchwartz, C. Wigger, W. Hajdas, and A. Zehnder, on behalf of the \nMESSENGER and RHESSI GRB teams,\n\nK. Yamaoka, M. Ohno, Y. Fukazawa, T. Takahashi, M. Tashiro, Y. Terada,\nT. Murakami, and K. Makishima, on behalf of the Suzaku WAM GRB team, report:\n\nA very long, bright GRB triggered Konus-Wind at 2007-06-26\nT0=14850.883 s UT (04:07:30.883). It was also observed by Suzaku-WAM, \nRHESSI and the MESSENGER neutron spectrometer, which also serves as a \nGRB detector.\n\nThe burst started at T-T0 ~-120 s and ended at T-T0 ~210 sec.\nThe Earth-crossing time of the onset was 14733 s UT (04:05:33).\nThe burst light curve shows several multipeaked pulses.\n\nWe have triangulated it to a 3 sigma error box whose coordinates are:\n\n-----------------------------------------------\n    RA(2000)                    Dec(2000)\n-----------------------------------------------\nCenter:\n  141.355 (09h 25m 25s)   -39.865 (-39d 51'' 54\")\nCorners:\n  139.529 (09h 18m 07s)   -39.872 (-39d 52'' 20\")\n  142.903 (09h 31m 37s)   -40.020 (-40d 01'' 11\")\n  143.210 (09h 32m 50s)   -39.805 (-39d 48'' 17\")\n  139.838 (09h 19m 21s)   -39.673 (-39d 40'' 24\")\n-------------------------------------------------\n\nThe error box area is 2047 square arcminutes.\nThe box may be improved.\n\nPreliminary analysis of the Konus-Wind data yields\na burst fluence of ~4x10^-4 erg/cm2 (in the 20 keV - 4 MeV range),\nthe spectrum of the main part of the burst (from T0 to T0+190 s)\ncan be fitted (in the 20 keV - 4 MeV range)\nby GRBM (Band) model for which:\nthe low-energy photon index is alpha = -1.5,\nthe high energy photon index beta = -2.3,\nthe peak energy Ep = 240 keV.\n\nThe Konus-Wind light curve of this GRB is available\nat http://www.ioffe.rssi.ru/LEA/GRBs/GRB070626_T14850/\n\nDetailed spectral parameters will be reported later."}', 'A very long and bright gamma-ray burst (GRB), designated as GRB 070626, was detected by the Konus-Wind, Suzaku-WAM, RHESSI, and MESSENGER neutron spectrometer teams. The burst occurred on June 26, 2007, and its light curve showed several multipeaked pulses. The triangulated error box for the burst''s location was determined to be approximately 2047 square arcminutes, with coordinates ranging from RA(2000) = 139.529° to 143.21° and Dec(2000) = -39.872° to -39.673°. Preliminary analysis of the Konus-Wind data suggested a burst fluence of ~4x10^-4 erg/cm2 in the 20 keV - 4 MeV range and a peak energy of 240 keV.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6591', 'gcn', 'GRB 070628', '2007-06-30T00:43:01.000Z', '{"measurements":[{"error":0.11,"filter":"WHITE","value":19.65},{"error":0.11,"filter":"WHITE","value":19.62},{"error":0.15,"filter":"WHITE","value":20.59},{"error":0.11,"filter":"V","value":18.88},{"error":0.25,"filter":"V","value":19.55},{"error":0.3,"filter":"B","value":20.7}],"authors":{"affiliations":["GSFC/SSAI","NASA/GSFC","CRESST/GSFC/USRA"],"authors":["W. Landsman","F.E. Marshall","S.T. Holland"],"institutions":["GSFC/SSAI","NASA/GSFC","CRESST/GSFC/USRA"],"universities":["NASA/GSFC","CRESST/GSFC/USRA"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"landsman@milkyway.gsfc.nasa.gov","institution":"GSFC/SSAI","name":"Wayne Landsman"},"coordinates":{},"detectionTime":"2007-06-30T00:43:01.000Z","event":"GRB 070628","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6591\nSUBJECT: GRB 070628 Swift-UVOT Refined Analysis\nDATE: 07/06/30 00:43:01 GMT\nFROM: Wayne Landsman at GSFC/SSAI  <landsman@milkyway.gsfc.nasa.gov>\n\nW. Landsman (GSFC/SSAI),  F.E. Marshall  (NASA/GSFC) and  S.T. Holland  \n(CRESST/GSFC/USRA) report on behalf of the Swift/UVOT team.\n\nThe Swift/UVOT observed the field of GRB 070628 starting 1099 sec after \nthe trigger (Holland et al., GCN Circ. 6584).    We strongly detect the \nafterglow in the white and V filters, and have a weak detection in the B \nfilter.    The refined afterglow position is\n\nRA(J2000)  =  07h 41m 06.09s\nDec(J2000) = -20d 16'' 45.4\"\n\nwith an uncertainty of 0.7\" (radius, 90% containment, including  \nsystematic uncertainty).  This is within the refined XRT error circle \n(Perri et al. GCN Circ. 6587).\n   \nMagnitudes and upper limits are reported below.\n\nFilter   Tstart  Tstop    Exp       Mag\n          (s)     (s)     (s)\n\nWHITE    1099    1199      98     19.65 � 0.11\n         1202    1302      98     19.62 � 0.11\n         6628    6827     197     20.59 � 0.15\n        11691   11990     295    >21.2 (3 sigma)\n\n\nV        1309    1708     393     18.88  � 0.11\n         1850    5804     256     19.55  � 0.25\n        13207   13506     295    >19.6 (3 sigma)\n\nB        1786    6622      78     20.7 � 0.3\n         7856    8055     197    >20.4 (3 sigma)\n                        \nU        6217    6417     197    >20.0 (3 sigma)\n\nUVW1     6014    6213     197    >19.8 (3 sigma)\n\nUVM2     5809    6008     197    >19.6 (3 sigma)\n\nUVW2     6833    7032     197    >19.9 (3 sigma)\n\n\nThe above magnitudes are not corrected for the large and uncertain \nextinction expected at the low Galactic latitude of GRB 070628.  \n\nA power-law fit  to the white filter observations gives a decay index of \n~0.55 +/- 0.3.\n\n[GCN OPS NOTE(30jun07):  Per author''s request, the authors line\nwas added.]"}', 'The Swift/UVOT team reports the detection of the afterglow of GRB 070628 in the white and V filters, with weak detection in the B filter. The refined position and magnitudes are provided, with uncertainties and upper limits for various filters. A power-law fit to the white filter observations yields a decay index of approximately 0.55.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6590', 'gcn', 'GRB 070628', '2007-06-29T19:54:12.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"10 min","energy":null,"fluence":null,"magnitude":{"H":16.2,"J_limit":16,"K":16.3},"other_measurements":{"observation_start_time":"22:21:57","time_after_grb":"7.7 hrs"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["MPE Garching","Tautenburg Observatory","Instituut voor Sterrenkunde Leuven, Belgium"],"authors":["N. Primak","G. Szokoly","J. Greiner","C. Clemens","T. Kruehler","A. Kuepcue-Yoldas","A. Yoldas","S. Klose","A. Rossi","F. Carrier"],"institutions":["Max-Planck Institute (MPE)","Tautenburg Observatory"],"universities":["Max-Planck Gesellschaft (MPG)","Instituut voor Sterrenkunde Leuven, Belgium"]},"telescopes":{"facilities":[],"instruments":["GROND"],"observatories":["ESO La Silla observatory"],"telescopes":["2.2m Max-Planck Institute telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_search.msfc?GCN_ID=6584"],"basic_data":{"author":{"email":"jcg@mpe.mpg.de","institution":"MPI","name":"Jochen Greiner"},"coordinates":{},"detectionTime":"2007-06-29T19:54:12.000Z","event":"GRB 070628","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6590\nSUBJECT: GRB 070628: NIR detection of afterglow\nDATE: 07/06/29 19:54:12 GMT\nFROM: Jochen Greiner at MPI  <jcg@mpe.mpg.de>\n\nN. Primak, G. Szokoly, J. Greiner, C. Clemens, T. Kruehler, A. Kuepcue-Yoldas, \nA. Yoldas (all MPE Garching), S. Klose, A. Rossi (Tautenburg Observatory), \nand F. Carrier (Instituut voor Sterrenkunde Leuven, Belgium) report:\n\nWe observed the field of GRB 070628 (Swift trigger 283320; Holland et al., \nGCN 6584) with GROND at the 2.2m Max-Planck Institute telescope at the \nESO La Silla observatory in Chile. The observations started at 22:21:57, \nabout 7.7 hrs after the GRB and just after sunset, and lasted 10 min. \nWe observed simultaneously in the g,r,i,z,J,H,K bands. The UVOT afterglow\n(Cronwall & Holland, GCN 6585) is clearly detected at H=16.2+-0.3 and \nK=16.3+-0.2 mag. The NIR magnitudes are calibrated against 2MASS. \nNothing is visible in the J band (limiting magnitude 16.0), and all \noptical frames are saturated due to twilight. \n\nWe note that the afterglow was atypically bright for the given time after\nthe burst, suggesting a slow fading. We encourage near-IR spectroscopy to\ndetermine the redshift."}', 'A team of astronomers led by Jochen Greiner at MPE Garching reported the detection of the near-infrared (NIR) afterglow of GRB 070628 using the GROND instrument at the 2.2m Max-Planck Institute telescope. The afterglow was detected at H=16.2±0.3 mag and K=16.3±0.2 mag, which is significantly brighter than typical for the given time after the burst. The team encourages near-IR spectroscopy to determine the redshift.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-659', 'gcn', 'GRB 000429', '2000-04-30T21:57:51.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":19,"other_measurements":{"exposure_time":"20 minutes","field_of_view":"11x11 arcmin"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["USRA/USNO"],"authors":["A. Henden"],"institutions":["USNO/USRA"],"universities":["USRA","USNO"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["NOFS"],"telescopes":["NOFS 1.0-m telescope"]},"urls":["<aah@nofs.navy.mil>"],"basic_data":{"author":{"email":"aah@nofs.navy.mil","institution":"USNO/USRA","name":"Arne A. Henden"},"coordinates":{},"detectionTime":"2000-04-30T21:57:51.000Z","event":"GRB 000429","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 659\nSUBJECT: GRB 000429, optical observation\nDATE: 00/04/30 21:57:51 GMT\nFROM: Arne A. Henden at USNO/USRA  <aah@nofs.navy.mil>\n\nA. Henden (USRA/USNO) reports on behalf of the USNO GRB Team:\n\nWe have imaged the IPN error box for GRB 000429\n(Hurley et al. GCN #657) with the NOFS 1.0-m telescope on\n000430.15 UT.  Since a CCD with 11x11arcmin field of view was\nused with a single pointing, the extreme corners of the error\nbox were not imaged.  Conditions were marginal, with poor seeing,\nlow altitude and twilight sky.  A composite 20-minute I-band image\nwas examined against the POSS-II red plate.  No new objects are\nseen down to the CCD frame limit of approximately I=19.0."}', 'Astronomical alert: GRB 000429, optical observation', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6589', 'gcn', 'GRB 070628', '2007-06-29T13:12:01.000Z', '{"measurements":{"dec":"-20.281","distance":null,"duration":"39.1 +- 2 sec","energy":null,"fluence":"3.5 +- 0.2 x 10^-6 erg/cm2","magnitude":null,"other_measurements":{"bat_data_end":"T+67 sec","main_emission_peak_end":"~T+20 sec","main_emission_peak_start":"~T-5 sec","partial_coding":"58%","peak_photon_flux":"5.1 +- 0.3 ph/cm2/sec","power_law_index":"1.91 +- 0.09","pretrigger_emission_start":"T-30 sec","uncertainty":"1.3 arcmin"},"ra":"115.271","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/USRA","GSFC","GSFC/UMBC","GSFC","LANL","GSFC/UMD","CRESST/GSFC/USRA","GSFC/ORAU","LANL","GSFC","GSFC/ORAU","GSFC/ISAS","GSFC/ORAU","GSFC","GWU"],"authors":["H. Krimm","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","S. T. Holland","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","GSFC/USRA","GSFC/UMBC","LANL","GSFC/UMD","CRESST/GSFC/USRA","GWU"],"universities":["GSFC","UMBC","LANL","UMD","ORAU","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-06-29T13:12:01.000Z","event":"GRB 070628","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6589\nSUBJECT: GRB 070628, Swift-BAT refined analysis\nDATE: 07/06/29 13:12:01 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nH. Krimm (GSFC/USRA), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nS. T. Holland (CRESST/GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), T. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS),\nM. Stamatikos (GSFC/ORAU), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-240 to T+67 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070628 (trigger #283320)\n(Holland, et al., GCN Circ. 6584).  The BAT ground-calculated position is\nRA, Dec = 115.271, -20.281 deg which is \n   RA(J2000)  =   7h 41m 5.1s \n   Dec(J2000) = -20d 16'' 50\"\nwith an uncertainty of 1.3 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 58%.\n \nThe mask-weighted light curve shows pretrigger emission starting at\nT-30 sec.  Then comes the main emission peak (roughly symmetrical)\nstarting at ~T-5 sec and ending at ~T+20 sec.  T90 (15-350 keV) is\n39.1 +- 2 sec (estimated error including systematics).  The BAT data\nend at T+67 sec because Swift entered the SAA.\n \nThe time-averaged spectrum from T-31.7 to T+16.2 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.91 +- 0.09.  The fluence in the 15-150 keV band is 3.5 +- 0.2 x 10^-6 erg/cm2.\nThe 1-sec peak photon flux measured from T+4.90 sec in the 15-150 keV band\nis 5.1 +- 0.3 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'A refined analysis of GRB 070628 (Swift-BAT trigger #283320) reports a ground-calculated position with an uncertainty of 1.3 arcmin, a duration of 39.1 +- 2 sec, and a fluence of 3.5 +- 0.2 x 10^-6 erg/cm2. The main emission peak occurred roughly symmetrically between -5 sec and +20 sec, and the power law index of the time-averaged spectrum was 1.91 +- 0.09.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6588', 'gcn', 'GRB 070628', '2007-06-29T10:05:31.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":17.9,"other_measurements":{"elevation_start":"22 degrees","galactic_extinction_R_band":"2.4 magnitudes"},"ra":null,"redshift":null,"tables":[{"filter_used":"R","magnitude_limit":"17.9","time_after_trigger":"8.3h"}]},"authors":{"affiliations":["CESR-OMP","OHP","LATT-OMP"],"authors":["Alain.Klotz@free.fr","Klotz, A.","Boer, M.","Atteia, J.L."],"institutions":["CESR-CNRS","OHP","LATT-OMP"],"universities":["CNRS","OMP"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["European Southern Observatory","La Silla observatory"],"telescopes":["TAROT"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6588"],"basic_data":{"author":{"email":"Alain.Klotz@free.fr","institution":"CESR-CNRS","name":"Alain Klotz"},"coordinates":{},"detectionTime":"2007-06-29T10:05:31.000Z","event":"GRB 070628","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6588\nSUBJECT: GRB 070628: TAROT La Silla observatory optical observations\nDATE: 07/06/29 10:05:31 GMT\nFROM: Alain Klotz at CESR-CNRS  <Alain.Klotz@free.fr>\n\nKlotz, A. (CESR-OMP), Boer M. (OHP), Atteia J.L. (LATT-OMP) report:\n\nWe imaged the field of GRB 070628 detected by SWIFT\n(trigger 283320) with the TAROT robotic telescope (D=25cm)\nlocated at the European Southern Observatory,\nLa Silla observatory, Chile.\n\nThe observations started 8.3h after the GRB trigger\n(started at the begining of the night).\nThe elevation of the field decreased from\nfrom 22 degrees above horizon and weather conditions\nwere good.\n\nWe co-added a series of exposures filtered in R, V and I.\nWe do not detect any OT at the UVOT location\n(Gronwall & Holland GCN Circ. 6585):\n\nt0+8.3h to t0+9.1h : R > 17.9\n\nMagnitudes were estimated with the nearby USNO-B1 stars\nand are not corrected for galactic dust extinction.\n\nN.B. Galactic coordinates are lon=236.5513 lat= +1.2335\nand the galactic extinction in R band is 2.4 magnitudes\nestimated from D. Schlegel et al. 1998ApJ...500..525S.\n\nThis message may be cited."}', 'The TAROT robotic telescope at La Silla observatory in Chile imaged the field of GRB 070628, detected by SWIFT, 8.3 hours after the trigger. No optical transient was detected in R, V, and I filters with a magnitude limit of 17.9. The observation started with an elevation of 22 degrees above the horizon under good weather conditions.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6587', 'gcn', 'GRB 070628', '2007-06-29T00:01:58.000Z', '{"measurements":{"dec":"-20.279750","distance":null,"duration":"T+14ks - T+116s","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"exposure_time":"6.3 ks","galactic_column_density":"7.35e21 cm^-2","photon_index":"2.2 +/- 0.1","total_column_density":"(7.5+/-0.7)e21 cm^-2","uncertainty":"3.5\" (90% containment)"},"ra":"115.275833","redshift":null,"tables":[]},"authors":{"affiliations":["ISAC/ASDC","CRESST/GSFC/USRA"],"authors":["M. Perri","G. Stratta","S.T. Holland"],"institutions":["ASDC","CRESST"],"universities":["ASI","GSFC"]},"telescopes":{"facilities":[],"instruments":["Swift XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6585","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6584"],"basic_data":{"author":{"email":"perri@asdc.asi.it","institution":"ISAC/ASDC","name":"Matteo Perri"},"coordinates":{},"detectionTime":"2007-06-29T00:01:58.000Z","event":"GRB 070628","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6587\nSUBJECT: GRB 070628: Swift XRT refined analysis\nDATE: 07/06/29 00:01:58 GMT\nFROM: Matteo Perri at ISAC/ASDC  <perri@asdc.asi.it>\n\nM. Perri, G. Stratta (ASDC)  and S.T. Holland (CRESST/GSFC/USRA)\nreport on behalf of the Swift XRT team:\n\nWe have analysed the first 3 orbits of Swift XRT data from the possible\nburst GRB 070628 (Holland et al., GCN Circ. 6584). Using an exposure\ntime of 6.3 ks the refined XRT position is RA (J2000) = 115.275833,\nDec (J2000) = -20.279750, corresponding to:\nRA(J2000) = 07h 41m 06.2s\nDec(J2000) = -20d 16'' 47.1\"\nwith an uncertainty of 3.5\" (90% containment). This is 0.5 arcmin from\nthe BAT position (GCN Circ. 6584) and 1.4 arcsec from the UVOT position\n(Gronwall et al. GCN Circ. 6585).\n\nThe XRT light-curve in the time interval from T+116s to T+14ks shows\na fading behavior with superimposed flaring activity. More data are being\ncollected to monitor the light-curve evolution.\n\nThe X-ray spectrum covering the time period from  T+1.1ks to T+14ks\nis well fit by an absorbed power law with a photon index of  2.2 +/- 0.1\nand a total column density of NH=(7.5+/-0.7)e21 cm**-2. We note that\nthe Galactic column density in the direction of the source is\n7.35e21 cm**-2 (Dickey & Lockman 1990).\n\nThis circular is an official product of the Swift XRT team."}', 'The Swift XRT team has refined the position of GRB 070628, reporting a new X-ray position with an uncertainty of 3.5 arcsec. The XRT data shows a fading behavior with superimposed flaring activity, and the X-ray spectrum is well fit by an absorbed power law with a photon index of 2.2 and a total column density of (7.5+/-0.7)e21 cm^-2. The position is 0.5 arcmin from the BAT position and 1.4 arcsec from the UVOT position.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6586', 'gcn', 'GRB 070628', '2007-06-28T21:56:11.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":16.2,"other_measurements":{"target_set_time":"18:20 UT"},"ra":null,"redshift":null,"tables":[{"image_usable":"no","time_after_trigger":"36.43 minutes"},{"band_limiting_magnitude":"16.2 (R-band)","exposure_duration":"60 seconds","time_after_trigger":"91.76 minutes"},{"band_limiting_magnitude":"17.2 (R-band)","combined_exposure_duration":"1620 seconds","time_after_trigger":"108.05 minutes"}]},"authors":{"affiliations":["University College Dublin","GACE Valencia","IAA CSIC Granada"],"authors":["Gary Melady","John French","Petr Kubanek","Martin Jelinek"],"institutions":["UCD","GACE Valencia","IAA CSIC Granada"],"universities":["University College Dublin"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Boyden Observatory"],"telescopes":["Watcher 40cm robotic telescope"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6586"],"basic_data":{"author":{"email":"gmelady@bermuda.ucd.ie","institution":"UCD","name":"Gary Melady"},"coordinates":{},"detectionTime":"2007-06-28T21:56:11.000Z","event":"GRB 070628","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6586\nSUBJECT: GRB 070628: Watcher Observations\nDATE: 07/06/28 21:56:11 GMT\nFROM: Gary Melady at UCD  <gmelady@bermuda.ucd.ie>\n\nGary Melady (University College Dublin), John French (UCD),\nPetr Kubanek (GACE Valencia), Martin Jelinek (IAA CSIC Granada)\n\nreport on behalf of the Watcher collaboration:\n\nThe Watcher 40cm robotic telescope, located at Boyden Observatory,\nSouth Africa, responded to Swift Trigger 283320 (GRB 070628, Holland et al. \nGCN 6584). when the dome opened at 15:17:29 UT, 36.43 minutes after the\ntrigger. However the bright evening sky rendered the earliest images\nunusable. \n\nAn unfiltered 60s exposure taken under twilight conditions at 16:12:48 UT, \n91.76 minutes after the Swift trigger, showed no new source in the UVOT \nerror box (as reported by Gronwall et al., GCN 6585) down to an R-band \nlimiting magnitude of approx 16.2 (in comparison to USNO-B1).\n\nWe combined 27 subsequent 60s exposures to create a 1620s unfiltered image with \nan exposure mid-time of 16:28:05 (108.05 minutes after the trigger). The later \nimages were taken at high air mass as the target was setting. This shows no new \nsource in the error box down to an R-band limiting magnitude of approx 17.2.\n\nThe target set at our location at 18:20 UT so no further observations will be made.\n\nThis message may be cited."}', 'The Watcher collaboration reported on observations of GRB 070628 using their 40cm robotic telescope at Boyden Observatory. Despite the bright evening sky, they obtained unfiltered images 91.76 minutes and 108.05 minutes after the Swift trigger, but found no new source in the error box with limiting magnitudes of approximately 16.2 and 17.2 (R-band) respectively.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6585', 'gcn', 'GRB 070628', '2007-06-28T15:21:36.000Z', '{"measurements":{"dec":-20.2795,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":19.1,"other_measurements":{"distance_from_bat_center":34.9,"error_radius":0.6,"exposure_duration":100,"time_after_trigger":1099},"ra":115.2755,"redshift":null,"tables":[]},"authors":{"affiliations":["PSU","CRESST/GSFC/USRA"],"authors":["C. Gronwall","S. T. Holland"],"institutions":["PSU","CRESST/GSFC/USRA"],"universities":["Pennsylvania State University (PSU)"]},"telescopes":{"facilities":["Swift"],"instruments":["Swift/UVOT"],"observatories":["Swift"],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"caryl@astro.psu.edu","institution":"PSU/Swift-UVOT","name":"Caryl Gronwall"},"coordinates":{"dec":1.0181320833333334},"detectionTime":"2007-06-28T15:21:36.000Z","event":"GRB 070628","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6585\nSUBJECT: Swift UVOT Observations of GRB 070628\nDATE: 07/06/28 15:21:36 GMT\nFROM: Caryl Gronwall at PSU/Swift-UVOT  <caryl@astro.psu.edu>\n\nSwift UVOT Observations of GRB 070628\n\nC. Gronwall (PSU) and S. T. Holland (CRESST/GSFC/USRA)\nreport on the behalf of the Swift UVOT team:\n\nIn response to GRB 070628 (Swift/BAT trigger 283320) at 14:41:02.84 UT,\nUVOT took a finding chart exposure of 100 seconds with the White \n(160-650 nm) filter starting 1099 seconds after the BAT trigger. There is \na candidate afterglow in the rapidly available 2.7''x2.7'' sub-image at\n    RA(J2000)  = 07:41:06.12 = 115.2755\n    DEC(J2000) = -20:16:46.2  = -20.2795\nwith a 1-sigma error radius of about 0.6 arc sec. This position is 34.9 \narcsec. from the center of the BAT error circle. The estimated magnitude is \n19.1 with a 1-sigma error of about 0.5 mag. No correction has been made \nfor extinction."}', 'Swift UVOT team reports the detection of a candidate afterglow for GRB 070628 at RA(J2000) = 07:41:06.12, DEC(J2000) = -20:16:46.2 with an estimated magnitude of 19.1 and a 1-sigma error of 0.5 mag, 34.9 arcsec from the center of the BAT error circle.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6584', 'gcn', 'GRB 070628', '2007-06-28T15:01:09.000Z', '{"measurements":{"dec":"-20d 17'' 04\"","distance":null,"duration":"20 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"galactic_latitude":"+1.25deg","peak_count_rate":"~3000 counts/sec (15-350 keV)","time_after_trigger_for_XRT_data_start":"111 seconds","time_of_BAT_trigger":"14:41:02 UT","time_of_XRT_data_start":"14:42:53 UT"},"ra":"07h 41m 08s","redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC/USRA","GSFC","U Leicester","PSU","INAF-OAB","ASDC","NASA/ORAU","GSFC/ISAS"],"authors":["S. T. Holland","S. D. Barthelmy","A. P. Beardmore","P. J. Brown","D. N. Burrows","S. Campana","M. L. Conciatore","N. Gehrels","C. Gronwall","C. Guidorzi","J. A. Kennea","H. A. Krimm","V. La Parola","V. Mangano","F. E. Marshall","P. T. O''Brien","K. L. Page","D. M. Palmer","M. Perri","P. Romano","T. Sakamoto","G. Sato","M. Stamatikos","T. N. Ukwatta"],"institutions":["CRESST/GSFC/USRA","GSFC","U Leicester","PSU","INAF-IASFPA","ASDC","NASA/ORAU","GSFC/ISAS","NASA/ORAU"],"universities":["University of Leicester","Penn State University","NASA/GSFC","University of Bicocca","INAF-OAB","ASDC","LANL","GWU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":1.0181344444444445},"detectionTime":"2007-06-28T15:01:09.000Z","event":"GRB 070628","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6584\nSUBJECT: GRB 070628: Swift detection of a possible burst\nDATE: 07/06/28 15:01:09 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS. T. Holland (CRESST/GSFC/USRA), S. D. Barthelmy (GSFC),\nA. P. Beardmore (U Leicester), P. J. Brown (PSU),\nD. N. Burrows (PSU), S. Campana (INAF-OAB), M. L. Conciatore (ASDC),\nN. Gehrels (NASA/GSFC), C. Gronwall (PSU),\nC. Guidorzi (Univ Bicocca&INAF-OAB), J. A. Kennea (PSU),\nH. A. Krimm (GSFC/USRA), V. La Parola (INAF-IASFPA),\nV. Mangano (INAF-IASFPA), F. E. Marshall (NASA/GSFC),\nP. T. O''Brien (U Leicester), K. L. Page (U Leicester),\nD. M. Palmer (LANL), M. Perri (ASDC),\nP. Romano (Univ. Bicocca & INAF-OAB), T. Sakamoto (NASA/ORAU),\nG. Sato (GSFC/ISAS), M. Stamatikos (NASA/ORAU) and\nT. N. Ukwatta (GSFC/GWU) report on behalf of the Swift Team:\n\nAt 14:41:02 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070628 (trigger=283320).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 115.284, -20.285 which is \n   RA(J2000)  =  07h 41m 08s\n   Dec(J2000) = -20d 17'' 04\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows a single peak\non a rising background while entering the SAA with a duration of about 20 sec. \nThe peak count rate was ~3000 counts/sec (15-350 keV), at ~5 sec after the\ntrigger.  Given the galactic latitude of +1.25deg, we can not rule out\na Galactic transient origin of this trigger. \n\nThe XRT began taking data at 14:42:53 UT, 111 seconds after the BAT\ntrigger. The initial image mode frames show many cosmic ray tracks\ndue to entrance into the SAA; the XRT on-board centroid algorithm did\nnot find a source in the image and no prompt position is available. \nFurther XRT data are delayed by the SAA passage. We are waiting for\ndown-linked data to detect and determine a position for the source. \n\nBecause Swift was entering the SAA, there were no prompt UVOT\nobservations of this source. \n\nBurst Advocate for this burst is S. T. Holland (sholland AT milkyway.gsfc.nasa.gov). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a gamma-ray burst (GRB 070628) with a peak count rate of ~3000 counts/sec (15-350 keV) at a galactic latitude of +1.25deg. The burst occurred at RA 07h 41m 08s, Dec -20d 17'' 04', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6583', 'gcn', 'GRB 070612A', '2007-06-27T23:06:44.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"NVSS_flux_density":"100 mJy","flux_density_1_4GHz_limit":"50 mJy","flux_density_5GHz_limit":"10 mJy"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley"],"authors":["R. Forster","M. Wright","J. Hare","J. S. Bloom","G. C. Bower"],"institutions":["UC Berkeley"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":["Allen Telescope Array"],"instruments":[],"observatories":[],"telescopes":["Allen Telescope Array"]},"urls":["http://ral.berkeley.edu/ata/"],"basic_data":{"author":{"email":"jbloom@astron.berkeley.edu","institution":"UC Berkeley","name":"Josh Bloom"},"coordinates":{},"detectionTime":"2007-06-27T23:06:44.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6583\nSUBJECT: GRB 070612A: Allen Telescope Array Observations\nDATE: 07/06/27 23:06:44 GMT\nFROM: Josh Bloom at UC Berkeley  <jbloom@astron.berkeley.edu>\n\nR. Forster, M. Wright, J. Hare, J. S. Bloom, G. C. Bower (UC  \nBerkeley) report on behalf of a large collaboration:\n\n\"Using the Allen Telescope Array (ATA, http://ral.berkeley.edu/ata/),  \nwe observed GRB 070612A (Grupe et al., GCN 6509) at 1.4 GHz on 2007  \nJune 16 UT and at 5 GHz on 2007 June 17 UT. The observations made use  \nof 8 antennas outfitted with dual-polarization receivers. At the  \nlocation of the optical afterglow (Updike et al., GCN 6515), we   \nobtained 3-sigma limits of 50 mJy at 1.4 GHz and 10 mJy at 5 GHz for  \nthe flux density of GRB 070612A at these epochs.  The data were  \ncalibrated versus the QSS 0927+392. At L-band the 8 brightest NVSS  \nwere measured to be located within 10% of the synthesized beamwidth  \nand 100 mJy of the NVSS flux densities. The limits reported herein  \nare consistent with the tentative WSRT detection at 4.9 GHz (Horst et  \nal. GCNs 6549, 6576).\n\nA 42-antenna ATA is currently being commissioned.\"\n\nThis message may be cited."}', 'A team led by UC Berkeley reported Allen Telescope Array (ATA) observations of GRB 070612A at 1.4 GHz on June 16, 2007 UT and at 5 GHz on June 17, 2007 UT. They obtained 3-sigma limits of 50 mJy at 1.4 GHz and 10 mJy at 5 GHz for the flux density of GRB 070612A at these epochs. The results are consistent with a tentative WSRT detection at 4.9 GHz and are in agreement with the NVSS flux densities of the brightest NVSS sources.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6582', 'gcn', 'IBAS Alert n. 4638', '2007-06-27T15:12:26.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["IASF, Milano","ISDC, Versoix"],"authors":["S. Mereghetti","S. Shaw"],"institutions":["IASF/CNR","ISDC"],"universities":["IASF","INAF","ISDC"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[""],"basic_data":{"author":{"email":"sandro@iasf-milano.inaf.it","institution":"IASF/CNR","name":"Sandro Mereghetti"},"coordinates":{},"detectionTime":"2007-06-27T15:12:26.000Z","event":"IBAS Alert n. 4638","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6582\nSUBJECT: IBAS Alert n. 4638: Not a GRB\nDATE: 07/06/27 15:12:26 GMT\nFROM: Sandro Mereghetti at IASF/CNR  <sandro@iasf-milano.inaf.it>\n\nS. Mereghetti (IASF, Milano), S.Shaw (ISDC, Versoix) \non behalf of the IBAS Localization Team report:\n\nIBAS alert No 4638 is not due to a GRB but to a known \nsource"}', 'IBAS Alert 4638, initially reported as a potential gamma-ray burst, has been identified as not being a GRB but rather a known astronomical source.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6581', 'gcn', 'OT20050728 was not an optical GRB afterglow', '2007-06-27T13:23:05.000Z', '{"measurements":{"dec":-18.84975,"distance":2100,"duration":1,"energy":null,"fluence":null,"magnitude":[{"date":"2005-07-28","time":"21849","value":20.09},{"date":"2005-07-28","time":"26054","value":18.69},{"date":"2005-07-28","time":"30330","value":20.94},{"date":"2005-07-28","time":"30631","value":20.66},{"date":"2005-07-29","time":"22204","value":21.59},{"date":"2007-06-08","time":null,"value":21.72}],"other_measurements":{"absolute_magnitude":9.5,"area_surveyed":1000,"color_index":{"g-i":1.86},"galactic_coordinates":{"B":25.65001461,"L":352.48572023},"galactic_extinction":{"A_I":0.58,"A_V":1},"height_above_disk":900,"magnitude_limit":22.5},"ra":239.32008,"redshift":null,"tables":[]},"authors":{"affiliations":["Lab d Astrophys., OMP, Toulouse, Institut d''Astrophysique de Paris"],"authors":["Jean-Luc Atteia, F. Malacrino, C. Veillet, J-L. Atteia, M. Boer, J-C. Cuillandre, A. Klotz, K. Withington"],"institutions":["Institut d''Astrophysique de Paris"],"universities":["Lab d Astrophys., OMP, Toulouse"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["<http://terapix.iap.fr/>","http://terapix.iap.fr/"],"basic_data":{"author":{"email":"atteia@ast.obs-mip.fr","institution":"Lab d Astrophys.,OMP,Toulouse","name":"Jean-Luc Atteia"},"coordinates":{},"detectionTime":"2007-06-27T13:23:05.000Z","event":"OT20050728 was not an optical GRB afterglow","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6581\nSUBJECT: OT20050728 was not an optical GRB afterglow\nDATE: 07/06/27 13:23:05 GMT\nFROM: Jean-Luc Atteia at Lab d Astrophys.,OMP,Toulouse  <atteia@ast.obs-mip.fr>\n\nF. Malacrino, C. Veillet, J-L. Atteia, M. Boer, J-C. Cuillandre,\nA. Klotz and K. Withington communicate\n\nOT20050728 was an optical transient, showing many similarities\nwith GRB optical afterglows, which was discovered by Malacrino et al. (2007)\nin the course of the CFHTLS Very Wide Survey.\nThe magnitudes of the transient, measured on July 28, 2005 were :\n(date, SOD, magnitude)\n2005-07-28, 21849, i''= 20.09\n2005-07-28, 26054, i''= 18.69\n2005-07-28, 30330, i''= 20.94\n2005-07-28, 30631, i''= 20.66\n2005-07-29, 22204, i''= 21.59\n\nTwo exposures taken in june 2005, with a g� filter\nshow no object at the position of the transient down to the\nlimiting magnitude of the observation g� = 24.0\n\n\nOn june 8th, 2007 we re-observed the position\nof OT20050728. These new observations clearly show\na star at the position of the transient, with coordinates (J2000) :\n\nRA = 15 57 16.82 (RA=239.32008)\nDEC = -18 50 59.1 (DEC=-18.84975)\n\nThe magnitude of the star is i�= 21.72\n\nWe conclude that the star brightened by 3 magnitudes\non 2005 july 28th, and that the ''flare'' lasted about 1 day\n(the magnitude on july 29th was almost back to normal).\n\nThe galactic coordinates of the star are\nL = 352.48572023\nB = +25.65001461\nThe galactic extinction in this direction, given by\nThe NASA Extragalactic Database, is A_I=0.58 and A_V=1.00\nThe magnitude of the star in quiescence, corrected for\nGalactic extinction are thus : i� = 21.14 and g� > 23.0\nThe color index g-i > 1.86\n\nAssuming that the star is an M dwarf, as suggested by its color,\nwith an absolute magnitude I=9.5 (Zheng et al. 2004), we can\nestimate the distance to the star: D ~ 2.1 kpc, and the height\nabove the disk: z ~ 900 pc. These values agree with those\nfound by Zheng et al. (2001) for the population of M dwarfs\ndetected with the HST WFC2.\n\n\nWhat was OT20050728 ?\n\nThe majority of optical transients detected to date have been\nattributed to late type flare stars (e.g. Becker et al. 2004,\nChristensen et al. 2004, Kulkarni & Rau 2006).\nGiven the red color Of OT20050728 in quiescence this may be another\nexample of such flaring activity.\nWe nevertheless consider this possibility as unlikely for two reasons:\nthe rise time of OT20050728 exceeds 1 hour, and the magnitude\nof the flare reaches 3 magnitudes in the i'' band.\nWe note that flares reaching 6 magnitudes in the B band\nhave an amplitude in the I band which is only 1 magnitude\n(Rockenfeller et al. 2006).\n\nA second possibility is a microlensing event, but the short duration\nof the transient would imply a fast moving lens.\n\nGiven the uncertainty on the origin of OT20050728, we strongly\nencourage spectroscopic observations of this object which is\nobservable now (until august).\n\n\nConsequences for Gamma-Ray Burts:\n\nThe main consequence of the stellar nature of OT20050728\nis that no GRB afterglow has been found in the Very Wide Survey\nof the CFHTLS. This search is one of the most extensive performed\nto date (Malacrino et al. 2007), with an area of ~1000 sq. deg\ndown to r� = 22.5.\nConsequently, we can constrain the number of afterglows brighter than \nr�=22.5,\nto be smaller than 220 in the whole sky at any time.\n\n\nAcknowledgements:\nWe thank the TERAPIX data center located at the Institut d''Astrophysique\nde Paris (http://terapix.iap.fr/) for the efficient processing of\nMegacam images\n\n\nReferences :\nBecker et al. 2004, ApJ,\nChristensen et al. 2004, GCNC 2849\nMalacrino et al. 2007, A&A, 464, L29\nKulkarni & Rau 2006, ApJ, 644, L63\nRockenfeller et al. 2006, MNRAS, 367, 407\nZheng et al. 2001, ApJ, 555, 393\nZheng et al. 2004 ApJ, 601, 500"}', 'OT20050728, an optical transient discovered in 2005, was not an optical GRB afterglow as previously thought. New observations revealed a star at the position of the transient that had brightened by 3 magnitudes and returned to normal within a day. The star''s location, magnitude, and color suggest it is an M dwarf star. This discovery means that no GRB afterglows were detected in the Very Wide Survey of the CFHTLS, limiting the number of afterglows brighter than r''=22.5 in the whole sky.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6580', 'gcn', 'GRB070615', '2007-06-26T15:01:42.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"3 ks","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"background_counts":{"unit":"counts","value":"0.1"},"count_rate_1":{"confidence_level":"95%","value":"5.5e-4 c/s"},"count_rate_2":{"confidence_level":"95%","value":"3.6e-3 c/s"},"observation_duration_1":{"time_after_trigger":"10.7 h","value":"3 ks"},"observation_duration_2":{"time_after_trigger":"6.9 days","value":"8.5 ks"},"upper_limit_count_rate":{"confidence_level":"95%","value":"3.5e-4 c/s"}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U. Leicester"],"authors":["O. Godet","N. Lyons","K.L. Page","A.P. Beardmore"],"institutions":["U. of Leicester","Swift-XRT team"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift PC"],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"og19@star.le.ac.uk","institution":"U.of Leicester","name":"Olivier Godet"},"coordinates":{},"detectionTime":"2007-06-26T15:01:42.000Z","event":"GRB070615","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6580\nSUBJECT: INTEGRAL burst GRB070615: X-ray continued observations\nDATE: 07/06/26 15:01:42 GMT\nFROM: Olivier Godet at U.of Leicester  <og19@star.le.ac.uk>\n\nO. Godet, N. Lyons, K.L. Page, A.P. Beardmore (U. Leicester) report on \nbehalf the Swift-XRT team:\n\nIn Godet et al. (GCN Circ. 6544), we reported the detection of a faint \nand uncatalogued X-ray source after analysing 3ks of Swift PC data taken \n10.7h after the IBAS trigger (Mereghetti et al., GCN Circ. 6537). We \nestimated the source count rate to be between 5.5e-4 c/s and 3.6e-3 c/s \nat a 95% confidence level using the Bayesian method. However, it was \nimpossible to say whether or not the source was fading due to the limited \nstatistics.\n\nWe analysed 8.5ks of additional PC data taken 6.9 days after the IBAS\ntrigger and no counts were found inside the 7.5 arcsec radius error\ncircle. In this region, only 0.1 background counts would be expected. \nUsing the Bayesian method, we estimated the upper limit on the count \nrate to be around 3.5e-4 c/s at a 95% confidence level.\nSo, the weak X-ray source may be fading.\n\nThis is an official product of the Swift XRT team."}', 'A faint X-ray source detected 10.7 hours after a gamma-ray burst (GRB070615) was identified using Swift PC data. The source had an estimated count rate between 5.5e-4 and 3.6e-3 counts per second (c/s) at a 95% confidence level. However, it was unclear if the source was fading due to limited statistics. Additional 8.5ks of Swift PC data taken 6.9 days after the burst revealed no counts within the error circle, suggesting the source may be fading with an upper limit count rate of around 3.5e-4 c/s at a 95% confidence level.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-658', 'gcn', 'GRB 000429', '2000-04-30T21:13:55.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":"V=12","other_measurements":{"external_zero_point_error":"three percent","internal_errors":"less than 100mas"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["USRA/USNO"],"authors":["A. Henden"],"institutions":["USNO/USRA"],"universities":["USRA","USNO"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["USNOFS 1.0-m"]},"urls":["ftp://ftp.nofs.navy.mil/pub/outgoing/aah/grb/grb000429.dat"],"basic_data":{"author":{"email":"aah@nofs.navy.mil","institution":"USNO/USRA","name":"Arne A. Henden"},"coordinates":{},"detectionTime":"2000-04-30T21:13:55.000Z","event":"GRB 000429","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 658\nSUBJECT: GRB 000429, UBVRI field photometry\nDATE: 00/04/30 21:13:55 GMT\nFROM: Arne A. Henden at USNO/USRA  <aah@nofs.navy.mil>\n\nA. Henden (USRA/USNO) reports on behalf of the USNO GRB team:\n\nWe have acquired preliminary shallow UBVRcIc all-sky photometry for\nan 11x11 arcmin field that covers the majority of the\nerror box for GRB000429 with the USNOFS 1.0-m telescope on one\nmarginally photometric night.  Stars brighter than\nV=12 are saturated and should be used with care.\nWe have placed the photometric data on our anonymous ftp site:\nftp://ftp.nofs.navy.mil/pub/outgoing/aah/grb/grb000429.dat\nThe current photometry has a potential external zero-point\nerror of about three percent.  The astrometry in this file\nis based on linear plate solutions with respect to USNO-A2.0.\nThe internal errors are less than 100mas.\n  Further calibration of this field will be performed if\nan optical afterglow is identified."}', 'The USNO GRB team, led by A. Henden at USRA/USNO, has acquired preliminary UBVRI photometry for the error box of GRB000429 using the USNOFS 1.0-m telescope. Stars brighter than V=12 are saturated and the data, which includes astrometry based on USNO-A2.0, is available on their FTP site. The external zero-point error is around three percent and internal errors are less than 100mas.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6579', 'gcn', 'GRB 070616', '2007-06-26T08:03:05.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["(Saitama-U)","(TUS/RIKEN)","(RIKEN)","(ISAS/JAXA)"],"authors":["N. Kodaka","K. Onda","Y. Urata","W. Iwakiri","T. Sugasahara","M. Tashiro","M. Kuwahara","T. Tamagawa","F. Usui"],"institutions":["Saitama U","TUS/RIKEN","RIKEN","ISAS/JAXA"],"universities":["Saitama-U","TUS/RIKEN","RIKEN","ISAS/JAXA"]},"telescopes":{"facilities":[],"instruments":["WIDGET"],"observatories":["Kiso, Japan"],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msf?is_alert=true&alert_id=6579"],"basic_data":{"author":{"email":"tashiro@phy.saitama-u.ac.jp","institution":"Saitama U/Swift","name":"Makoto Tashiro"},"coordinates":{},"detectionTime":"2007-06-26T08:03:05.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6579\nSUBJECT: GRB 070616 : WIDGET simultaneous optical observations\nDATE: 07/06/26 08:03:05 GMT\nFROM: Makoto Tashiro at Saitama U/Swift  <tashiro@phy.saitama-u.ac.jp>\n\nN. Kodaka,  K. Onda, Y. Urata, W. Iwakiri, T. Sugasahara, M. Tashiro\n(Saitama-U),  M. Kuwahara (TUS/RIKEN), T. Tamagawa (RIKEN) F. Usui\n(ISAS/JAXA) report:\n\n\"We observed the error region of GRB 070616 (Swift/BAT trigger #282445;\nStarling et al., GCN 6542; Sakamoto et al., GCN circ 6543; Starling et\nal., GCN Report 66.2) with the very wide-field camera WIDGET located at\nKiso, Japan. The WIDGET monitored the region with repeat of unfiltered\n5-second exposures between 27 seconds before and 136 seconds after the\nburst.\n\nWe did not find any  optical emission from the afterglow position\n(Fatkhullin et al. GCN  6547). The 1-sigma limiting magnitude of\neach frame derived by the Tycho-2 catalog was around V=11.8 magnitudes.\"\n\nThis message may be cited."}', 'A team of astronomers led by Saitama University reported no optical emission from the afterglow position of GRB 070616 using the WIDGET camera at Kiso, Japan. The limiting magnitude of each frame was around V=11.8 magnitudes.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6578', 'gcn', 'GRB 070616', '2007-06-26T07:51:35.000Z', '{"measurements":{"dec":null,"distance":null,"duration":140,"energy":[{"max":1000,"min":100,"unit":"keV"}],"fluence":{"max_error":0.7,"min_error":-0.6,"unit":"x 10^-6 erg/cm^2","value":6.6},"magnitude":null,"other_measurements":{"peak_flux":{"max_error":0.16,"min_error":-0.17,"unit":"photons/cm^2/s","value":1.4},"photon_index_gamma":{"max_error":0.12,"min_error":-0.12,"value":2.36}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"tashiro@phy.saitama-u.ac.jp","institution":"Saitama U/Swift","name":"Makoto Tashiro"},"coordinates":{},"detectionTime":"2007-06-26T07:51:35.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6578\nSUBJECT: GRB 070616: Suzaku/WAM observation of the prompt emission\nDATE: 07/06/26 07:51:35 GMT\nFROM: Makoto Tashiro at Saitama U/Swift  <tashiro@phy.saitama-u.ac.jp>\n\nK. Morigami, N. Kodaka, K. Onda, M. Tashiro, M. Suzuki, Y. Urata,\nA. Endo (Saitama U.), T. Uehara, M. Ohno, T. Takahashi, Y. Fukazawa,\nC. Kira (Hiroshima U.), T. Enoto, R. Miyawaki, K. Nakazawa,\nK. Makishima (Univ. of Tokyo), K. Yamaoka, Y. E. Nakagawa,\nS. Sugita (Aoyama Gakuin U.), T. Tamagawa, Y. Terada (RIKEN),\nS. Hong (Nihon U.), M. Kokubun, M. Suzuki, T. Takahashi (ISAS/JAXA),\nE. Sonoda, M.Yamauchi, S. Maeno, H. Tanaka, R. Hara (Univ. of Miyazaki),\nand Suzaku WAM team report:\n\nThe long burst, GRB 070616 (Swift/BAT trigger #282445; Starling et al.,\nGCN circ 6542; Sakamoto et al., GCN circ 6543; Starling et al., GCN\nReport 66.2) triggered the Suzaku Wide-band All-sky Monitor (WAM)\ncovering 50 keV to 5 MeV at 16:31:50 UT (T0), which was 137 second\nafter the Swift/BAT trigger time. Since The WAM BST mode data did not\ncover the Swift/BAT trigger time, we employed continuous monitoring\n(TRN) data to evaluate the whole light curve and the averaged spectrum\nof the burst. The observed light curve exhibits multiple peaked\nstructures preceded by a precursor-like emission (from T0-163 to T0-158 \nseconds). Although Starling et al. reported a very long duration, over \n600 seconds (GCN Report 66.1), the Suzaku/WAM covered only 140 seconds \nfrom the start of the main peaks before the entry of the SAA region in \nthe orbit.\n\nThe derived fluence in 100-1000 keV was more than\n6.6 (-0.6, +0.7) x 10^-6 erg/cm^2. The 1-s peak flux was\n1.40 (-0.17,+0.16) photons/cm^2/s in the same energy range.\n\nPreliminary result shows that the time-averaged spectrum from T0-10 to\nT0+30 seconds is well fitted with a single power-law of a photon\nindex Gamma = 2.36 (-0.12, +0.12) in the 100-1000 keV energy range.\n\nAll the quoted errors are at statistical 90% confidence level, while\nthe systematic errors are not considered.\n\nThe light curve data for this burst is available at the following web site.\n\nhttp://www.astro.isas.ac.jp/suzaku/HXD-WAM/WAM-GRB/grb/trig/grb_table.html"}', 'GRB 070616, a gamma-ray burst detected by Swift/BAT, triggered the Suzaku Wide-band All-sky Monitor (WAM) which observed the prompt emission between 50 keV to 5 MeV. The observation covered 140 seconds of the burst''s light curve, revealing multiple peaked structures and a precursor-like emission. The derived fluence in the 100-1000 keV energy range was more than 6.6 x 10^-6 erg/cm^2, with a peak flux of 1.4 photons/cm^2/s. The time-averaged spectrum was found to be well-fitted with a single power-law of a photon index Gamma = 2.36.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6577', 'gcn', 'IBAS Alert n.4637', '2007-06-25T07:53:55.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["IASF, Milano","ISDC, Geneva"],"authors":["S. Mereghetti","S. Shaw"],"institutions":["IASF/CNR","ISDC, Geneva"],"universities":["IASF","INAF","ISDC"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[""],"basic_data":{"author":{"email":"sandro@iasf-milano.inaf.it","institution":"IASF/CNR","name":"Sandro Mereghetti"},"coordinates":{},"detectionTime":"2007-06-25T07:53:55.000Z","event":"IBAS Alert n.4637","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6577\nSUBJECT: IBAS Alert n.4637:  not a GRB\nDATE: 07/06/25 07:53:55 GMT\nFROM: Sandro Mereghetti at IASF/CNR  <sandro@iasf-milano.inaf.it>\n\nS. Mereghetti (IASF, Milano), S.Shaw (ISDC, Geneva)\non behalf of the IBAS Localization Team report:\n\nIBAS alert No 4637 is not due to a GRB but to a known \nsource"}', 'IBAS Alert 4637, which was initially flagged as a potential gamma-ray burst (GRB), has been identified as not being a GRB but rather a known astronomical source. No further details on the nature of the source have been provided in the alert.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6576', 'gcn', 'GRB 070612A', '2007-06-24T10:19:49.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[{"flux":"72 +/- 27 microJy","frequency":"4.9 GHz","time_after_burst":"8.22 - 8.71 days"},{"flux":"53 +/- 19 microJy","frequency":"4.9 GHz","time_after_burst":"average of June 15 and June 20"}]},"authors":{"affiliations":["University of Amsterdam","University of Leicester"],"authors":["A.J. van der Horst","R.A.M.J. Wijers","K. Wiersema","E. Rol"],"institutions":["U of Amsterdam",""],"universities":["University of Amsterdam","University of Leicester"]},"telescopes":{"facilities":["WSRT"],"instruments":["WSRT"],"observatories":[""],"telescopes":["Westerbork Synthesis Radio Telescope"]},"urls":[""],"basic_data":{"author":{"email":"avdhorst@science.uva.nl","institution":"U of Amsterdam","name":"Alexander van der Horst"},"coordinates":{},"detectionTime":"2007-06-24T10:19:49.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6576\nSUBJECT: GRB 070612A: Second Epoch WSRT Radio Observations\nDATE: 07/06/24 10:19:49 GMT\nFROM: Alexander van der Horst at U of Amsterdam  <avdhorst@science.uva.nl>\n\nA.J. van der Horst, R.A.M.J. Wijers, K. Wiersema (University of Amsterdam),\nand E. Rol (University of Leicester) report on behalf of a larger\ncollaboration:\n\n\"We reobserved the position of the GRB 070612A afterglow (GCN 6509) at\n4.9 GHz with the Westerbork Synthesis Radio Telescope at June 20 7.91 UT\nto 19.76 UT, i.e. 8.22 - 8.71 days after the burst.\nAt the position of the optical counterpart (GCN 6515, GCN 6525) and the\ntentative radio counterpart (GCN 6549), we measure a formal flux of\n72 +/- 27 microJy, i.e. a possible radio source at 2.7 sigma significance.\nIn a combined image of the two epochs of WSRT observations, at June 15 and\nJune 20, the average formal flux is 53 +/- 19 microJy, a 2.8 sigma\ndetection. Therefore, we cannot state with certainty whether the radio\nafterglow (or the possible host galaxy) of GRB 070612A is detected.\n\nWe would like to thank the WSRT staff for scheduling and obtaining these\nobservations.\""}', 'A team of researchers led by A.J. van der Horst from the University of Amsterdam reported the results of their second epoch radio observations of GRB 070612A using the Westerbork Synthesis Radio Telescope. They detected a possible radio source at the position of the optical counterpart with a flux of 72 +/- 27 microJy, which corresponds to a 2.7 sigma significance. The average flux from the combined image of the two epochs was 53 +/- 19 microJy, representing a 2.8 sigma detection. However, they could not definitively confirm whether the radio afterglow or the host galaxy of GRB 070612A was detected.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6575', 'gcn', 'GRB070621', '2007-06-23T14:22:12.000Z', '{"measurements":{"dec":"-24:49:07.2","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":22.15,"other_measurements":{"error_in_magnitude":"0.2","exposure_time_per_image":"60 s","limiting_magnitude_combined_image":"22.3","limiting_magnitude_single_image":"20.8","number_of_exposures":16,"time_after_burst":"500 s"},"ra":"21:35:10.12","redshift":null,"tables":[]},"authors":{"affiliations":["TUG (Irek Khamitov)","KSU/AST (I. Bikmaev, N. Sakhibullin)","Sabanci Uni. (E. Gogus)","METU (U. Kiziloglu)","IKI (R. Burenin, M. Pavlinsky, R. Sunyaev)"],"authors":["I. Khamitov","I. Bikmaev","N. Sakhibullin","Z. Tunca","U. Kiziloglu","E. Gogus","R. Burenin","M. Pavlinsky","R. Sunyaev"],"institutions":["TUG","KSU/AST","Sabanci Uni.","METU","IKI"],"universities":["TUBITAK","KSU","Sabanci Uni.","METU","IKI"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["TUBITAK National Observatory"],"telescopes":["Russian-Turkish 1.5-m telescope (RTT150)"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msf?id=6530","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msf?id=6568","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msf?id=6572","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msf?id=6565"],"basic_data":{"author":{"email":"irekk@tug.tug.tubitak.gov.tr","institution":"TUG","name":"Irek Khamitov"},"coordinates":{},"detectionTime":"2007-06-23T14:22:12.000Z","event":"GRB070621","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6575\nSUBJECT: GRB070621: RTT150 optical observations\nDATE: 07/06/23 14:22:12 GMT\nFROM: Irek Khamitov at TUG  <irekk@tug.tug.tubitak.gov.tr>\n\nI. Khamitov (TUG), I. Bikmaev, N. Sakhibullin (KSU/AST),\nZ. Tunca (TUG), U. Kiziloglu (METU), E. Gogus (Sabanci Uni.),\nR. Burenin, M. Pavlinsky, R. Sunyaev (IKI)\n\nreports:\n\nWe observed the field of GRB 070621 (Sbarufatti et al., GCN 6530) with\nRussian-Turkish 1.5-m telescope (RTT150, Bakyrlytepe,TUBITAK National\nObservatory, Turkey). We made 16x60s exposures in R band, starting at June\n21, 23:25:40UT, i.e. approximately 500 s after the burst.\n\nWe detected no sources inside the XRT error circle in any of 60~s image,\nas well as in combined 16x60~s image with 3-sigma limiting magnitudes\nm_R=~20.8 and m_R=~22.3 respectively.\n\nThe source reported by Melesani et al (GCN 6565) is clearly detected on \nthe level m_R=22.15+/-0.2 using the same reference star USNO-B1 \n0651-0871887, i.e. is not variable within the errors. The astrometric \nposition of this source is RA=21:35:10.12, DEC=-24:49:07.2 with 0.1 arcsec \naccuracy.\n\nThe sourse to the east from XRT position, which was found in Gemini\nSouth data (s4, Bloom et. al., GCN 6568), and in image from Keck II LGS\nAO (i2, Bloom et. al., GCN 6572) is also detected marginally near the\nlimit of our combined image.\n\nThis message may be cited."}', 'A team of astronomers led by I. Khamitov at TUG reported non-detection of any sources within the error circle of GRB 070621 using the Russian-Turkish 1.5-m telescope (RTT150). They detected the source reported by Melesani et al. at a magnitude of 22.15+/-0.2, confirming it is not variable. A marginal detection was made of a source to the east of the XRT position, which was also detected in Gemini South and Keck II LGS AO data.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6574', 'gcn', 'GRB 070621', '2007-06-22T18:38:01.000Z', '{"measurements":{"dec":["-24:49:07.5","-24:49:02.8"],"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":[null,null],"other_measurements":{"comparison_magnitude_difference":"0.1 mag","discrepancy_in_magnitude":"~0.5 mag","uncertainty":"0.4\""},"ra":["21:35:10.08","21:35:10.27"],"redshift":null,"tables":[]},"authors":{"affiliations":["INAF - OABr","INAF - OAR","DARK/NBI"],"authors":["P. D''Avanzo","V. D''Elia","D. Fugazza","G. Tagliaferri","D. Malesani","J.P.U. Fynbo"],"institutions":["INAF-OAB","INAF-OAR","DARK/NBI"],"universities":["INAF","NBI"]},"telescopes":{"facilities":[],"instruments":["FORS1"],"observatories":[],"telescopes":["ESO-VLT"]},"urls":["https://gcn.gsfc.nasa.gov/gcn/gcn3_batch.msf?6560"],"basic_data":{"author":{"email":"paolo.davanzo@brera.inaf.it","institution":"INAF-OAB","name":"Paolo D''Avanzo"},"coordinates":{},"detectionTime":"2007-06-22T18:38:01.000Z","event":"GRB 070621","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6574\nSUBJECT: GRB 070621: VLT optical observations\nDATE: 07/06/22 18:38:01 GMT\nFROM: Paolo D''Avanzo at INAF-OAB  <paolo.davanzo@brera.inaf.it>\n\nP. D''Avanzo (INAF - OABr) V. D''Elia (INAF - OAR), D. Fugazza,  G. \nTagliaferri (INAF - OABr) on behalf of the MISTICI collaboration and D. \nMalesani and J.P.U. Fynbo (DARK/NBI) report:\n\nWe observed the field of GRB070621 (Sbarufatti et al., GCN 6560) with \nthe ESO-VLT equipped with the FORS1 camera in the R and I bands. \nObservations were carried out on Jun 22.36 and 22.38 UT (0.39 and 0.41 \ndays after the GRB) in the I and R filters, respectively.\n\nWe detect two extended sources near the revised XRT error box \n(Sbarufatti et al. GCN 6569), reported by different authors (Malesani et \nal. GCN 6565, Tanvir et al. GCN 6570, Bloom et al. GCN 6568 and GCN \n6572), at the following coordinates (J2000):\n\nS1) R.A. = 21:35:10.08, Dec. = -24:49:07.5\nS2) R.A. = 21:35:10.27, Dec. = -24:49:02.8\n\nwith an uncertainty of 0.4\".\n\nA comparison between the NOT (Malesani et al. GCN 6565) and VLT images \nshows that source S1 remained constant between the NOT and VLT \nobservation up to 0.1 mag.\n\nSource S2 is not visible in the NOT image, so that a direct  comparison \nis not possible. When considering the roughly simultaneous WHT I-band \nmeasurement by Tanvir et al. (GCN 6570), we note a small discrepancy \n(~0.5 mag) in the magnitude of source S1. After taking into account this \nuncertainty, no variability can be claimed for source S2 as well.\n\nSource S1 appears elongated in the East/West direction, consistent with \nthe superposition of two objects as resolved in the adaptive-optics Keck \nimage (Bloom et al. GCN 6572).\n\nWe acknowledge the support of the ESO staff.\n\nThis message can be quoted."}', 'Astronomers using the ESO-VLT with FORS1 camera detected two extended sources near the error box of GRB070621. Source S1, which was previously observed by NOT, remained constant between the NOT and VLT observations within 0.1 mag. Source S2 was not visible in the NOT image, but a comparison with a roughly simultaneous WHT measurement showed a small discrepancy in the magnitude of source S1. Both sources appear elongated, suggesting the superposition of two objects.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6573', 'gcn', 'GRB 070621', '2007-06-22T17:22:32.000Z', '{"measurements":[{"Exp(s)":806,"Filter":"V","Mag (3-sigma upper limit)":20.2,"T_start":226,"T_stop":1360},{"Exp(s)":10,"Filter":"B","Mag (3-sigma upper limit)":18.6,"T_start":702,"T_stop":714},{"Exp(s)":88,"Filter":"U","Mag (3-sigma upper limit)":19.7,"T_start":680,"T_stop":4799},{"Exp(s)":236,"Filter":"UVW1","Mag (3-sigma upper limit)":20.3,"T_start":656,"T_stop":4744},{"Exp(s)":38,"Filter":"UVM2","Mag (3-sigma upper limit)":18.8,"T_start":631,"T_stop":802},{"Exp(s)":19,"Filter":"UVW2","Mag (3-sigma upper limit)":18.1,"T_start":733,"T_stop":752},{"Exp(s)":204,"Filter":"White","Mag (3-sigma upper limit)":21.3,"T_start":120,"T_stop":954}],"authors":{"affiliations":["CRESST/GSFC/USRA","INAF-IASFPA","Swift UVOT team"],"authors":["S. T. Holland","B. Sbarufatti"],"institutions":["USRA","NASA/GSFC","INAF-IASFPA"],"universities":["USRA","NASA/GSFC","INAF-IASFPA"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"sholland@milkyway.gsfc.nasa.gov","institution":"USRA/NASA/GSFC/SSC","name":"Stephen Holland"},"coordinates":{},"detectionTime":"2007-06-22T17:22:32.000Z","event":"GRB 070621","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6573\nSUBJECT: GRB 070621: Swift/UVOT Upper Limits\nDATE: 07/06/22 17:22:32 GMT\nFROM: Stephen Holland at USRA/NASA/GSFC/SSC  <sholland@milkyway.gsfc.nasa.gov>\n\nS. T. Holland (CRESST/GSFC/USRA) and B. Sbarufatti (INAF-IASFPA)\nreport on the behalf of the Swift UVOT team:\n\n\n        The Swift/UVOT observed the field of GRB 070621 starting 120 s\nafter the BAT trigger (Sbarufatti, et al. 2007, GCN Circ. 6560).  We\ndo not find any source, in any of the UVOT observations, inside the\nrefined XRT error circle (Sbarufatti, et al., 2007 GCN Circ. 6567), or\nat the location of the NOT source (Malesani, et al. 2007, GCN\nCirc. 6565).\n\n        The 3-sigma upper limits for detecting a source inside the\nrefined XRT error circle in the initial data products are:\n\n\nFilter    T_start   T_stop    Exp(s)    Mag (3-sigma upper limit)\n-----------------------------------------------------------------\nV             226     1360       806    20.2\nB             702      714        10    18.6\nU             680     4799        88    19.7\nUVW1          656     4744       236    20.3\nUVM2          631      802        38    18.8\nUVW2          733      752        19    18.1\nWhite         120      954       204    21.3\n-----------------------------------------------------------------\n\nThe values quoted above are not corrected for the expected Galactic\nextinction corresponding to a reddening of E_{B-V} = 0.05 mag in the\ndirection of the burst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reports no detection of a source within the refined XRT error circle or at the NOT source location for GRB 070621. They provide 3-sigma upper limits for detecting a source in various UVOT filters, which range from 18.1 to 21.3 magnitudes.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6572', 'gcn', 'GRB 070621', '2007-06-22T17:01:48.000Z', '{"measurements":{"dec":"-24:49:07.4","distance":null,"duration":"13.8 hr","energy":null,"fluence":null,"magnitude":21.5,"other_measurements":{"FWHM":"130 mas","integration_time_per_frame":"60 sec","number_of_frames_stacked":45},"ra":"21:35:10.22","redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley","UC Santa Cruz"],"authors":["J. S. Bloom","L. Pollack","D. A. Perley"],"institutions":["UC Berkeley","UC Santa Cruz"],"universities":["University of California, Berkeley","University of California, Santa Cruz"]},"telescopes":{"facilities":[],"instruments":["Laser Guide Star (LGS) Adaptive Optics (AO) system + NIRC2"],"observatories":[],"telescopes":["Keck II"]},"urls":["http://lyra.berkeley.edu/~jbloom/grb070621_bloom_kecklaser.pdf"],"basic_data":{"author":{"email":"jbloom@astron.berkeley.edu","institution":"UC Berkeley","name":"Josh Bloom"},"coordinates":{},"detectionTime":"2007-06-22T17:01:48.000Z","event":"GRB 070621","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6572\nSUBJECT: Keck Laser Guide Star Adaptive Optics Imaging of GRB 070621\nDATE: 07/06/22 17:01:48 GMT\nFROM: Josh Bloom at UC Berkeley  <jbloom@astron.berkeley.edu>\n\nJ. S. Bloom (UC Berkeley), L. Pollack (UC Santa Cruz), D. A. Perley  \n(UC Berkeley) report:\n\n\"We observed the field of GRB 070621 (GCN #6560) in the K-prime  \nfilter using\nthe Laser Guide Star (LGS) Adaptive Optics (AO) system + NIRC2 on the\nKeck II telescope.  With integrations of 60 sec per frame, we stacked\n45 frames with a mean time since GRB trigger of 13.8 hr.  The brighter\ncompact sources in the field have typical FWHM of 130 mas, and the\npreliminary 5 sigma detection threshold is K-prime = 21.5 mag.  With\nfurther refinements we expect this limit to improve.\n\nA number of sources mentioned in previous circulars are detected (*)\nas well as a few red and faint sources near the XRT position. In\nparticular, we note source l1 (ra=21:35:10.22, dec=-24:49:07.4, J2000)\nwhich is 0.8 arcseconds East of apparent galaxy s1 (Bloom et al. GCN\n#6568 = Malesani et al. source #1 GCN #6565?).  The source near the\nEastern edge of the XRT position (l2) is nearly coincident with the\nposition of s4 (Bloom et al. GCN #6568 = Tanvir et al. source #2 GCN\n#6570) but appears only marginally extended at K-prime. Both l1 (being\nquite red and close to a galaxy) and l2 (appearing nearly point-like\nand close to the XRT position) are of prime interest in the search for\nthe afterglow of this GRB.  Given the large number of sources in the\nfield and the quality of the laser AO images, if either l1 or l2 are\nconfirmed as the GRB afterglow then the astrometric accuracy will be\ncomparable to that obtained previously with early and late HST\nimaging of other afterglows.\"\n\n(*) http://lyra.berkeley.edu/~jbloom/grb070621_bloom_kecklaser.pdf\n\nWe thank the WMKO staff for their assistance in obtaining these\nobservations, especially Randy Campbell and Al Conrad."}', 'A team of astronomers led by J. S. Bloom at UC Berkeley observed the field of GRB 070621 using the Laser Guide Star Adaptive Optics system on the Keck II telescope. They detected two potential afterglow candidates, sources l1 and l2, which are of prime interest due to their proximity to the X-ray position and red color. The team reports a preliminary 5 sigma detection threshold of K-prime = 21.5 mag and expects further refinements to improve this limit.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6571', 'gcn', 'GRB 070621', '2007-06-22T13:52:28.000Z', '{"measurements":{"dec":-24.809,"distance":null,"duration":33.3,"energy":null,"fluence":0.0000043,"magnitude":null,"other_measurements":{"fluence_band":"15-150 keV","fluence_value":"4.3 +- 0.1 x 10^-6 erg/cm2","partial_coding":31,"peak_photon_flux":2.5,"peak_photon_flux_band":"15-150 keV","peak_photon_flux_value":"2.5 +- 0.3 ph/cm2/sec","power_law_index":1.57},"ra":323.806,"redshift":null,"tables":[]},"authors":{"affiliations":["LANL","GSFC","UMBC","GSFC/UMD","GSFC/ORAU","GSFC/ISAS","INAF-IASFPA","GWU"],"authors":["E. Fenimore","L. Barbier","S. D. Barthelmy","J. Cummings","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","B. Sbarufatti","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","LANL","GSFC/UMBC","GSFC/UMD","GSFC/ORAU","GSFC/ISAS","INAF-IASFPA","GWU"],"universities":["GSFC","UMBC","UMD","ISAS","INAF-IASFPA","ORAU","GWU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-06-22T13:52:28.000Z","event":"GRB 070621","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6571\nSUBJECT: GRB 070621: Swift-BAT refined analysis\nDATE: 07/06/22 13:52:28 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nE. Fenimore (LANL), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), N. Gehrels (GSFC), H. Krimm (GSFC/USRA),\nC. Markwardt (GSFC/UMD), D. Palmer (LANL), A. Parsons (GSFC),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), B. Sbarufatti (INAF-IASFPA),\nM. Stamatikos (GSFC/ORAU), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-240 to T+962 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070621 (trigger #282808)\n(Sbarufatti, et al., GCN Circ. 6560).  The BAT ground-calculated position is\nRA, Dec = 323.806, -24.809 deg  which is \n   RA(J2000)  =  21h 35m 13.5s \n   Dec(J2000) = -24d 48'' 32\" \nwith an uncertainty of 1.0 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 31%.\n \nThe mask-weighted light curve shows several overlapping peaks starting at ~T-20 sec\nand ending at ~T+40 sec.  There is a low-significance bump (~3 sigma) from\nT+70 to T+105 sec.  T90 (15-350 keV) is 33.3 +- 1.0 sec (estimated error\nincluding systematics).\n \nThe time-averaged spectrum from T-5.2 to T+36.4 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.57 +- 0.06.  The fluence in the 15-150 keV band is 4.3 +- 0.1 x 10^-6 erg/cm2.\nThe 1-sec peak photon flux measured from T+21.56 sec in the 15-150 keV band\nis 2.5 +- 0.3 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'The Swift-BAT team has released refined analysis of GRB 070621 (trigger #282808), reporting a ground-calculated position with an uncertainty of 1.0 arcmin and a partial coding of 31%. The time-averaged spectrum is best fit by a simple power-law model with a power law index of 1.57 +- 0.06 and a fluence of 4.3 +- 0.1 x 10^-6 erg/cm2 in the 15-150 keV band. The peak photon flux was measured at 2.5 +- 0.3 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6570', 'gcn', 'GRB070621', '2007-06-22T12:33:06.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"25 minutes","energy":null,"fluence":null,"magnitude":["21.21 +/- 0.05","22.5 +/- 0.1"],"other_measurements":{"average_time_after_burst":"5.17 hours","observation_start_time":"4:14 UT, June 22"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["University of Leicester","ING"],"authors":["N. Tanvir","E. Rol","A. Cardwell"],"institutions":["ING"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":["Auxiliary Port Instrument"],"observatories":["La Palma"],"telescopes":["William Herschel Telescope"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"er45@star.le.ac.uk","institution":"U.Leicester","name":"Evert Rol"},"coordinates":{},"detectionTime":"2007-06-22T12:33:06.000Z","event":"GRB070621","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6570\nSUBJECT: WHT observations of GRB070621\nDATE: 07/06/22 12:33:06 GMT\nFROM: Evert Rol at U.Leicester  <er45@star.le.ac.uk>\n\nN. Tanvir, E. Rol (University of Leicester) and A. Cardwell (ING), report\non behalf of a larger collaboration:\n\nWe observed the position of GRB070621 (Sbarufatti, GCNC 6560) with the\nAuxiliary Port Instrument on the William Herschel Telescope at La\nPalma, for 25 minutes starting at 4:14 UT, June 22 (average time 5.17\nhours after burst).\n\nWe detect the extended object mentioned by Malesani et al. (GCNC\n6565), at a magnitude of I = 21.21 +/- 0.05.\nWe also detect the source on the east edge of the refined XRT error\ncircle (Sbarufatti, GCNC 6569) mentioned by Bloom et al (GCNC 6568),\nwith a magnitude of I = 22.5 +/- 0.1.\n\nPhotometry was performed relative to the USNO star 0651-0871887, which\nhas an I2 magnitude of 17.21."}', 'The University of Leicester and ING teams reported observing GRB070621, a gamma-ray burst, using the Auxiliary Port Instrument on the William Herschel Telescope at La Palma. They detected two distinct sources: one with a magnitude of I = 21.21 +/- 0.05, located at the extended object mentioned in another report, and another with a magnitude of I = 22.5 +/- 0.1, on the east edge of the refined XRT error circle. The observations were conducted 25 minutes after the burst, with an average time of 5.17 hours post-burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-657', 'gcn', 'GRB000429', '2000-04-30T01:12:41.000Z', '{"measurements":{"dec":"-4d24''49.24\"","distance":null,"duration":"~50 s","energy":null,"fluence":"~4 x 10^-6 erg/cm^2","magnitude":null,"other_measurements":{"error_box_area":"~90 sq. arcmin","peak_flux":"~6 x 10^-7 erg/cm^2 s"},"ra":"6h33m20.80s","redshift":null,"tables":[{"DEC(2000)":"-4 o 24 '' 49.24 \"","RA(2000)":"6 h 33 m 20.80 s"},{"DEC(2000)":"-4 o 27 '' 6.45 \"","RA(2000)":"6 h 32 m 49.24 s"},{"DEC(2000)":"-4 o 18 '' 40.36 \"","RA(2000)":"6 h 33 m 32.66 s"},{"DEC(2000)":"-4 o 30 '' 58.52 \"","RA(2000)":"6 h 33 m 8.98 s"},{"DEC(2000)":"-4 o 22 '' 32.36 \"","RA(2000)":"6 h 33 m 52.44 s"}]},"authors":{"affiliations":["UCBerkeley/SSL","Ulysses GRB Team","BATSE GRB Team","NEAR GRB Team","KONUS-WIND GRB Team","BeppoSAX GRBM Team"],"authors":["K. Hurley","S. Barthelmy","R. M. Kippen","T. Cline","E. Mazets","F. Frontera","C. Guidorzi","E. Montanari"],"institutions":["Ulysses GRB Team","BATSE GRB Team","NEAR GRB Team","KONUS-WIND GRB Team","BeppoSAX GRBM Team"],"universities":["UC Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Ulysses","BATSE","Konus","NEAR","BeppoSAX"]},"urls":[],"basic_data":{"author":{"email":"khurley@sunspot.ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2000-04-30T01:12:41.000Z","event":"GRB000429","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 657\nSUBJECT: IPN localization of GRB000429\nDATE: 00/04/30 01:12:41 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@sunspot.ssl.berkeley.edu>\n\nK. Hurley, on behalf of the Ulysses GRB Team, S. Barthelmy and\nR. M. Kippen on behalf of the BATSE GRB Team, T. Cline and E.\nMazets, on behalf of the NEAR and KONUS-WIND GRB Teams, and\nF. Frontera, C. Guidorzi and E. Montanari, on behalf of the\nBeppoSAX GRBM Team, report:\n\nUlysses, BATSE, Konus, NEAR, and the BeppoSAX GRBM observed\nGRB000429 (BATSE 8087) at 36430 s UT.  As observed by Ulysses,\nthis burst had a duration of ~50 s, a 25-100 keV fluence of\n~4 x 10^-6 erg/cm^2, and a 0.25 s peak flux of ~6 x 10^-7 erg/\ncm^2 s.  We have localized this burst to a preliminary 3 sigma\nerror box with an area of ~90 sq. arcmin with the following\ncoordinates:\n\n    RA(2000)                 DEC(2000)\n  6 h 33 m 20.80 s     -4 o 24 ''  49.24 \"  (CENTER)\n  6 h 32 m 49.24 s     -4 o 27 ''   6.45 \"  (CORNER)\n  6 h 33 m 32.66 s     -4 o 18 ''  40.36 \"  (CORNER)\n  6 h 33 m  8.98 s     -4 o 30 ''  58.52 \"  (CORNER)\n  6 h 33 m 52.44 s     -4 o 22 ''  32.36 \"  (CORNER)\n\nThis error box can be refined considerably."}', 'Astronomical alert: IPN localization of GRB000429', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6569', 'gcn', 'GRB070621', '2007-06-22T11:31:25.000Z', '{"measurements":{"dec":"-24 49 03.1","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":"21 35 10.14","redshift":null,"tables":[{"column_name":"Initial Decay Index","value":"-3.8 +/-0.1"},{"column_name":"Flare Time","value":"T+150s"},{"column_name":"Post-Break Decay Index","value":"-0.91 +/- 0.04"},{"column_name":"Predicted Count Rate 24h Post-Trigger","value":"2.1E-2 counts/s"},{"column_name":"Predicted Flux 24h Post-Trigger","value":"1.8E-12 ergs cm^-2 s^-1"},{"column_name":"Photon Index","value":"2.5+/-0.3"},{"column_name":"Column Density","value":"(4.4 +/- 0.9)E21 cm^-2"},{"column_name":"Galactic Column Density","value":"3.5E20 cm^-2"},{"column_name":"Absorbed Flux (WT Spectrum)","value":"8.4E-10 ergs cm^-2 s^-1"},{"column_name":"Unabsorbed Flux (WT Spectrum)","value":"2.2E-09 ergs cm^-2 s^-1"},{"column_name":"Absorbed Flux (PC Spectrum)","value":"1.4E-11 ergs cm^-2 s^-1"},{"column_name":"Unabsorbed Flux (PC Spectrum)","value":"3.6E-11 ergs cm^-2 s^-1"}]},"authors":{"affiliations":["INAF-IASFPA","Univ. Bicocca & INAF-OAB","INAF-OAB"],"authors":["B. Sbarufatti","P. Romano","C. Guidorzi","A. Moretti"],"institutions":["INAF-IASFPA","INAF-OAB"],"universities":["Univ. Bicocca","INAF-OAB","IFC-INAF.it"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"sbarufatti@ifc.inaf.it","institution":"INAF-IASF-Pa","name":"Boris Sbarufatti"},"coordinates":{"dec":21.58615},"detectionTime":"2007-06-22T11:31:25.000Z","event":"GRB070621","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6569\nSUBJECT: GRB070621: Swift XRT refined analysis\nDATE: 07/06/22 11:31:25 GMT\nFROM: Boris Sbarufatti at INAF-IASF-Pa  <sbarufatti@ifc.inaf.it>\n\nB. Sbarufatti (INAF-IASFPA), P. Romano, C. Guidorzi (Univ. Bicocca &  \nINAF-OAB)\nA. Moretti (INAF-OAB) report, on behalf of the Swift-XRT team\n\nWe have analysed the first three orbits of Swift XRT data  for GRB070621\n(Sbarufatti et al., GCN Circ. 6560), consisting of 150 s in Window  \nTiming\nmode data and 1.3 ks in Photon Counting mode.\n\nThe UVOT enhanced XRT position (Sbarufatti et al., GCN Circ. 6567) is\nRA, Dec = 323.79225, -24.81752 which is equivalent to:\n\nRA (J2000):   21 35 10.14\nDec (J2000): -24 49 03.1\n\nwith an uncertainty of 2.0 arcsec (90% confidence).\n\nThe X-ray light curve exhibits an initial steep decay (index -3.8  \n+/-0.1)\nup to T+380 s. A flare is observed around T+150s. After the break, the\ncount-rate decays with a power-law index of -0.91 +/- 0.04. If the  \npresent\nslow decay continues, the predicted count rate 24h after the trigger is\n2.1E-2 counts/s, corresponding to  a flux of 1.8E-12 ergs cm^-2 s^-1.\n\nThe WT and PC spectra can be fitted simultaneously with an absorbed\npower-law model with a photon index 2.5+/-0.3 and a column density\n(4.4 +/- 0.9)E21 cm^-2, significantly in excess with respect to the\ngalactic value (3.5E20 cm^-2, Dickey & Lockman, 1990). The absorbed\n(unabsorbed) fluxes are 8.4E-10 (2.2E-09) ergs cm^-2 s^-1 for\nthe WT spectrum and 1.4E-11 (3.6E-11) ergs cm^-2 s^-1  for\nthe PC spectrum.\n\nThis circular is an official product of the XRT team."}', 'Astronomers have analyzed Swift XRT data for GRB070621 and found an initial steep decay with an index of -3.8 +/- 0.1, followed by a flare at around T+150s. The post-break decay index is -0.91 +/- 0.04. The predicted count rate 24 hours after the trigger is 2.1E-2 counts/s, corresponding to a flux of 1.8E-12 ergs cm^-2 s^-1. The X-ray spectra can be fitted with an absorbed power-law model, indicating significant excess absorption with a column density of (4.4 +/- 0.9)E21 cm^-2.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6568', 'gcn', 'GRB 070621', '2007-06-22T11:27:19.000Z', '{"measurements":{"dec":"-24:49:06.9","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":"21:35:10.14","redshift":null,"tables":[{"apparent_motion_east_west":"4.69 W \"/hr","apparent_motion_north_south":"10.4 S \"/hr","beta":"-09:53:28.791","lambda":"+318:07:27.207"}]},"authors":{"affiliations":["UC Berkeley","U Chicago","UC Santa Cruz"],"authors":["J. S. Bloom","H.-W. Chen","D. A. Perley","L. Pollack"],"institutions":["UC Berkeley","U Chicago","UC Santa Cruz"],"universities":["UC Berkeley","U Chicago","UC Santa Cruz"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Gemini South"],"telescopes":["Gemini South"]},"urls":["http://scully.harvard.edu/~cgi/CheckSN","http://lyra.berkeley.edu/~jbloom/grb070621-gemini.reg","http://lyra.berkeley.edu/~jbloom/grb070621-gemini.png"],"basic_data":{"author":{"email":"dperley@astro.berkeley.edu","institution":"U.C. Berkeley","name":"Daniel Perley"},"coordinates":{},"detectionTime":"2007-06-22T11:27:19.000Z","event":"GRB 070621","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6568\nSUBJECT: GRB 070621: Gemini South optical imaging\nDATE: 07/06/22 11:27:19 GMT\nFROM: Daniel Perley at U.C. Berkeley  <dperley@astro.berkeley.edu>\n\nJ. S. Bloom (UC Berkeley), H.-W. Chen (U Chicago), D. A. Perley (UC \nBerkeley), and L. Pollack (UC Santa Cruz) report:\n\n\"The receipt of the BAT_POSITION notice for GRB 070621 (Sbarufatti et \nal. GCN #6560) triggered our automated imaging program on Gemini South \nat 23:18:26 UT and the first images were obtained at 22 June 2007 \n04:54:57 UT by Byran Miller and the Gemini staff once the conditions \ncleared. Images in griz-bands were obtained, with a total of 5x180 \nsecond exposures in each band.\n\nA number of faint sources are detected near the UVOT-enhanced XRT \nposition (Sbarufatti et al., GCN #6567), including the source (s1 = \n21:35:10.14, -24:49:06.9) to the South of the XRT position which may be \nthe same source noted by Malesani et al. (GCN #6565). There is an \napparent galaxy (s4: 21:35:10.34, -24:49:02.2, PA ~ -45 deg) to the east \nof the GRB but outside the current XRT position. A color image of the \nfield has been posted (*) along with a ds9 region file (**) giving the \nJ2000 locations of the sources near the GRB.\n\nWe note the presence of an asteroid, not found in the Minor Planet \nChecker (***), moving near the GRB at the time of the Gemini \nobservations. The quickly derived parameters for this asteroid are:\n\n  apparent motion: 10.4 S \"/hr, 4.69 W \"/hr\n  position (ecliptic): lambda = +318:07:27.207, beta = -09:53:28.791  @ \n  22 June 2007 05:22:37.4 UTC\n\n(*)   http://lyra.berkeley.edu/~jbloom/grb070621-gemini.png\n(**)  http://lyra.berkeley.edu/~jbloom/grb070621-gemini.reg\n(***) http://scully.harvard.edu/~cgi/CheckSN\n\nWe thank Bryan Miller and the Gemini Staff for observing this ToO.\""}', 'Astronomers at UC Berkeley, U Chicago, and UC Santa Cruz report the detection of several sources near the position of a gamma-ray burst (GRB 070621) observed by the Swift satellite. The team obtained optical images of the area using the Gemini South telescope and identified a potential match to the burst source, as well as a nearby galaxy and an asteroid. The asteroid, not previously identified in the Minor Planet Checker, was moving near the GRB position during the Gemini observations.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6567', 'gcn', 'GRB 070621', '2007-06-22T08:56:15.000Z', '{"measurements":{"dec":"-24 49 03.1","distance":null,"duration":"746 s","energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":"21 35 10.10","redshift":null,"tables":[]},"authors":{"affiliations":["INAF-IASF Pa","LU"],"authors":["B. Sbarufatti","P. A. Evans"],"institutions":["INAF-IASF Pa","LU"],"universities":["INAF-IASF-Pa"]},"telescopes":{"facilities":[],"instruments":["XRT","UVOT"],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"sbarufatti@ifc.inaf.it","institution":"INAF-IASF-Pa","name":"Boris Sbarufatti"},"coordinates":{"dec":21.586138888888886},"detectionTime":"2007-06-22T08:56:15.000Z","event":"GRB 070621","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6567\nSUBJECT: GRB 070621: UVOT-enhanced XRT position\nDATE: 07/06/22 08:56:15 GMT\nFROM: Boris Sbarufatti at INAF-IASF-Pa  <sbarufatti@ifc.inaf.it>\n\nB. Sbarufatti (INAF-IASF Pa),  P. A. Evans (LU) report  on behalf of  \nthe Swift team\n\nUsing 746 s of overlapping XRT Photon Counting mode and UVOT V-band\ndata, we find an astrometrically corrected X-ray position (using the  \nXRT-UVOT\nalignment and matching UVOT field sources to the USNO-B1 catalogue):  \nRA, Dec =\n323.79225, -24.81752 which is equivalent to:\n\nRA (J2000):  21 35 10.10\nDec (J2000): -24 49 03.1\n\nwith an uncertainty of 2.0 arcsec (90% confidence)."}', 'Astronomers using data from the Swift satellite have determined an astrometrically corrected X-ray position for a gamma-ray burst (GRB 070621) with an uncertainty of 2.0 arcsec (90% confidence). The coordinates are RA (J2000): 21 35 10.10, Dec (J2000): -24 49 03.1.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6552', 'gcn', 'GRB070616', '2007-06-18T05:05:26.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"exposure_time_per_frame":"1 min","frames_coadded":"5","observation_end_time":"18:10:30","observation_start_time":"18:04:40","time_after_burst":"1h 35m"},"ra":null,"redshift":null,"tables":[{"band":"g''","exp.time":"5 x 1 min.","mid-UT (2007)":"June 16 18:07:35","upper limit":"19.5 mag"},{"band":"Rc","exp.time":"5 x 1 min.","mid-UT (2007)":"June 16 18:07:35","upper limit":"18.9 mag"},{"band":"Ic","exp.time":"5 x 1 min.","mid-UT (2007)":"June 16 18:07:35","upper limit":"18.4 mag"}]},"authors":{"affiliations":["OAO, NAOJ","National Astronomical Observatory of Japan","Tokyo Tech"],"authors":["M. Yoshida","K. Yanagisawa","Y. Shimizu","S. Nagayama","N. Kawai"],"institutions":["Okayama Astrophysical Observatory","National Astronomical Observatory of Japan","Tokyo Institute of Technology"],"universities":["NAOJ","Tokyo Tech"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Okayama Astrophysical Observatory"],"telescopes":["50cm MITSuME telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6547","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6542","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6548"],"basic_data":{"author":{"email":"yoshida@oao.nao.ac.jp","institution":"Okayama Astrophysical Obs","name":"Michitoshi Yoshida"},"coordinates":{},"detectionTime":"2007-06-18T05:05:26.000Z","event":"GRB070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6552\nSUBJECT: GRB070616: Optical Observation by MITSuME Okayama\nDATE: 07/06/18 05:05:26 GMT\nFROM: Michitoshi Yoshida at Okayama Astrophysical Obs  <yoshida@oao.nao.ac.jp>\n\nM. Yoshida, K. Yanagisawa, Y. Shimizu, S. Nagayama (OAO, NAOJ)\nand N. Kawai (Tokyo Tech) report on behalf of the MITSuME\ncollaboration:\n\nWe performed optical imaging observation (g'', Rc, and Ic) of the\nfield of GRB 070616 (Starling et al. GCN 6542) with 50cm MITSuME\ntelescope at Okayama Astrophysical Observatory from UT 18:04:40\n(1h 35m after burst) to UT 18:10:30 on June 16 2007.\n\nWe coadded 5 CCD frames for each band. Exposure time of each\nframe is 1 minute. We made flux calibration using USNO B1.0\ncatalg. We could not identify new source at the position of the\nafterglow candidate reported by Fatkhullin et al. (GCN 6547) and\nUgarte Postigo (GCN 6548). Three sigma limiting magnitudes of\nour observation are listed below.\n\n----------------------------------------------------\nband  mid-UT (2007)      exp.time     upper limit\ng''    June 16 18:07:35   5 x 1 min.   19.5 mag\nRc    June 16 18:07:35   5 x 1 min.   18.9 mag\nIc    June 16 18:07:35   5 x 1 min.   18.4 mag\n----------------------------------------------------"}', 'On June 16, 2007, the MITSuME collaboration at Okayama Astrophysical Observatory performed optical imaging observations of GRB 070616 using a 50cm MITSuME telescope. They could not detect a new source at the position of the afterglow candidate reported by other teams. The team obtained upper limits in magnitudes for g'', Rc, and Ic bands: 19.5 mag, 18.9 mag, and 18.4 mag, respectively.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6551', 'gcn', 'GRB 070616', '2007-06-17T16:53:05.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["GSFC/ISAS","GSFC"],"authors":["G. Sato","S. Barthelmy"],"institutions":["NASA/GSFC","GSFC/ISAS"],"universities":["GSFC","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-06-17T16:53:05.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6551\nSUBJECT: GRB 070616, Swift-BAT further refined analysis\nDATE: 07/06/17 16:53:05 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nG. Sato (GSFC/ISAS) and S. Barthelmy (GSFC)\non behalf of the Swift-BAT team:\n\nThe time-averaged spectrum from T-2.6 to T+602.2 sec is best fit\nby a simple power-law model.  The power law index of the time-averaged\nspectrum is 1.61 +- 0.04.  The fluence in the 15-150 keV band is\n1.92 +- 0.03 x 10^-5 erg/cm2.  The 1-sec peak photon flux measured\nfrom T+139.74 sec in the 15-150 keV band is 1.9 +- 0.1 ph/cm2/sec.\nAll the quoted errors are at the 90% confidence level.\n \nThe mask-weighted light curve shows many peaks.  The burst started with \na low-level smooth emission at ~T-55 sec continuing smoothly and increasing\nslowly until ~T+100 sec when the main emission started.  The main peak is\nat T+120 sec.  Smaller overlapping peaks continue out past T+550 sec.\nIn particular, there is a small peak from T+730 to T+850 sec which is coincident\nwith a peak (flare) in the XRT lightcurve (Fig 2, GCN Report 66.1,\nStarling et al.).  T90 (15-350 keV) is 402 +- 10 sec (estimated error\nincluding systematics)."}', 'Swift-BAT team reports updated analysis of GRB 070616. The time-averaged spectrum is best fit by a power-law model with a power law index of 1.61 +- 0.04 and a fluence of 1.92 +- 0.03 x 10^-5 erg/cm2 in the 15-150 keV band. The burst started with a low-level emission and had a main peak at T+120 sec, with smaller overlapping peaks continuing out to T+550 sec. A coincident peak in the XRT lightcurve was observed at T+730 to T+850 sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6550', 'gcn', 'GRB 070616', '2007-06-17T10:52:11.000Z', '{"measurements":{"dec":"+56 56 43.9","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"alpha_1":"-4.6","alpha_2":"-1.2","count_rate":"4.9E-02 count/s","error_radius":"2.3 arcseconds","galactic_column_density":"3.4E21 cm^-2","gamma":"2.4+0.2,-0.1","observed_flux_0_3_to_10_kev":"2.2E-12 erg/cm^2/s","predicted_flux_t0_plus_24h":"2.3E-13 erg/cm^2/s","predicted_flux_t0_plus_48h":"9.9E-14 erg/cm^2/s","unabsorbed_flux_0_3_to_10_kev":"4.0E-12 erg/cm^2/s"},"ra":"02 08 36.70","redshift":null,"tables":[]},"authors":{"affiliations":["U. Leicester"],"authors":["R.L.C. Starling"],"institutions":["Swift XRT team"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift XRT","UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"rlcs1@star.le.ac.uk","institution":"U of Leicester","name":"Rhaana Starling"},"coordinates":{"dec":2.143527777777778},"detectionTime":"2007-06-17T10:52:11.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6550\nSUBJECT: GRB 070616: Swift XRT refined circular\nDATE: 07/06/17 10:52:11 GMT\nFROM: Rhaana Starling at U of Leicester  <rlcs1@star.le.ac.uk>\n\nR.L.C. Starling (U. Leicester) reports, on behalf of the Swift XRT team:\n\nWe have analysed the first eight orbits of Swift XRT data (18.6 ks of data \nout to T0+5.8E4s) for GRB 070616 (Starling et al., GCN Circ. 6542).\n\nUsing 1.1 ks of overlapping XRT PC mode data and UVOT V-band data, we\nobtain an astrometrically corrected X-ray position (using the USNO-B1 \ncatalogue) of \n\nRA(J2000) = 02 08 36.70\nDec(J2000)= +56 56 43.9\n\nwith an error of 2.3 arcseconds (radius, 90% containment).\nThis is 3.7 arcsec from the initially reported XRT position\nand 6.4 arcsec from the BAT position (GCN Circ. 6542), and 6.3 arcsec from \nthe possible optical transient reported in De Ugarte Postigo et al. (GCN\nCirc. 6548). The error circle overlaps with the USNO-B1.0 source noted in \nGCN Circ. 6542.\n\nThe lightcurve began with a constant flux up to T0+536s, and then decayed \nwith alpha=-4.6 until about T0+1000s. A steep decay follows this, though\nthere are not enough data to accurately measure its slope. \nAfter T0+1400s the decay continues with a shallower slope of alpha=-1.2.\nSeveral small flares appear on top of the continuum emission up to \nT0+1000s, some of which may be simultaneous with BAT peaks.\n\nThe PC mode spectrum including 14.6 ks of data from the second orbit \nonwards is well fit with a power law of photon index\nGamma=2.4+0.2,-0.1 (90%) absorbed only by the large Galactic column of \n3.4E21 cm^-2.\nThe 0.3-10 keV observed (unabsorbed) flux is 2.2E-12 (4.0E-12) erg/cm^2/s,\ncorresponding to a count rate of 4.9E-02 count/s.\n\nThe predicted fluxes at T0+24h and T0+48h are 2.3E-13 and 9.9E-14 \nerg/cm^2/s respectively, assuming the decay continues with alpha=-1.2.\n\nThis is an official product of the Swift XRT team."}', 'The Swift XRT team has analyzed the first eight orbits of data for GRB 070616 and obtained a refined X-ray position with an error of 2.3 arcseconds. The position is 3.7 arcsec from the initially reported XRT position and 6.4 arcsec from the BAT position. The lightcurve shows a decay with an initial slope of -4.6, followed by a shallower decay with a slope of -1.2. The PC mode spectrum is well fit with a power law absorbed only by the large Galactic column. The observed 0.3-10 keV flux is $2.2E-12$ erg/cm$^2$/s and the predicted fluxes at 24 hours and 48 hours are $2.3E-13$ and $9.9E-14$ erg/cm$^2$/s, respectively.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-655', 'gcn', 'GRB000418', '2000-04-29T03:27:12.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"flux_density":"850+/-33 microJy","frequency":"8.46 GHz"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NRAO"],"authors":["D. A. Frail"],"institutions":["NRAO"],"universities":["NRAO"]},"telescopes":{"facilities":["VLA"],"instruments":[],"observatories":["NRAO"],"telescopes":["VLA"]},"urls":[],"basic_data":{"author":{"email":"dfrail@nrao.edu","institution":"NRAO","name":"Dale A. Frail"},"coordinates":{},"detectionTime":"2000-04-29T03:27:12.000Z","event":"GRB000418","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 655\nSUBJECT: GRB000418, Radio detection\nDATE: 00/04/29 03:27:12 GMT\nFROM: Dale A. Frail at NRAO  <dfrail@nrao.edu>\n\nD. A. Frail (NRAO) reports on behalf of a larger collaboration:\n\n\"Beginning on April 29.07 UT we observed GRB000418 with the VLA at a\nfrequency of 8.46 GHz. At the position of the IR/optical transient\nreported by Klose et al. (GCN 645) and Mirabal et al. (GCN 650), we\ndetect a bright radio source with a flux density of 850+/-33 microJy.\nWe will continue to monitor this source.\""}', 'A radio source with a flux density of 850 microJy at 8.46 GHz has been detected at the position of GRB000418 by the VLA team at NRAO.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6549', 'gcn', 'GRB 070612A', '2007-06-17T10:46:54.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"flux":"78 +/- 25 microJy","observation_end_time":"June 15 20.09 UT","observation_frequency":"4.9 GHz","observation_start_time":"June 15 8.10 UT","time_after_burst":"3.23 - 3.73 days"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["University of Amsterdam","University of Leicester"],"authors":["A.J. van der Horst","R.A.M.J. Wijers","K. Wiersema","E. Rol"],"institutions":[],"universities":["University of Amsterdam","University of Leicester"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Westerbork Synthesis Radio Telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_6525.gif","https://gcn.gsfc.nasa.gov/gcn3/gcn3_6509.gif","https://gcn.gsfc.nasa.gov/gcn3/gcn3_6515.gif"],"basic_data":{"author":{"email":"avdhorst@science.uva.nl","institution":"U of Amsterdam","name":"Alexander van der Horst"},"coordinates":{},"detectionTime":"2007-06-17T10:46:54.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6549\nSUBJECT: GRB 070612A: Possible WSRT Radio Detection\nDATE: 07/06/17 10:46:54 GMT\nFROM: Alexander van der Horst at U of Amsterdam  <avdhorst@science.uva.nl>\n\nA.J. van der Horst, R.A.M.J. Wijers, K. Wiersema (University of Amsterdam),\nand E. Rol (University of Leicester) report on behalf of a larger\ncollaboration:\n\n\"We observed the position of the GRB 070612A afterglow (GCN 6509) at 4.9 GHz\nwith the Westerbork Synthesis Radio Telescope at June 15 8.10 UT to 20.09 UT,\ni.e. 3.23 - 3.73 days after the burst.\nWe tentatively detect a radio source at 3 sigma significance, located at the\nposition of the optical counterpart (GCN 6515, GCN 6525), with a flux of\n78 +/- 25 microJy.\nFurther observations at radio wavelengths of this afterglow are planned and\nencouraged, especially given the suggested association with a nearby\nlow-redshift host galaxy (GCN 6525).\n\nWe would like to thank the WSRT staff for scheduling and obtaining these\nobservations.\""}', 'A team of astronomers led by A.J. van der Horst from the University of Amsterdam reported a tentative radio detection of the afterglow of GRB 070612A, located at a flux of 78 +/- 25 microJy using the Westerbork Synthesis Radio Telescope. The observation was made 3.23-3.73 days after the gamma-ray burst. Further observations are encouraged due to the suggested association with a nearby low-redshift host galaxy.', 0.8, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6548', 'gcn', 'GRB 070616', '2007-06-17T09:52:58.000Z', '{"measurements":{"dec":"+56:56:39.7","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":"02:08:36.12","redshift":null,"tables":[]},"authors":{"affiliations":["IAA-CSIC","SAO-RAS, Russia"],"authors":["A. de Ugarte Postigo","T. Fatkhullin","A. J. Castro-Tirado"],"institutions":["IAA-CSIC","SAO-RAS","Russia"],"universities":["IAA-CSIC","SAO-RAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://www.iaa.es/~deugarte/GRBs/070616/GRB070616.gif"],"basic_data":{"author":{"email":"deugarte@iaa.es","institution":"IAA-CSIC","name":"Antonio Deugarte"},"coordinates":{"dec":2.1433666666666666},"detectionTime":"2007-06-17T09:52:58.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6548\nSUBJECT: GRB 070616: BTA astrometry and finding chart\nDATE: 07/06/17 09:52:58 GMT\nFROM: Antonio Deugarte at IAA-CSIC  <deugarte@iaa.es>\n\nA. de Ugarte Postigo (IAA-CSIC) T. Fatkhullin\n(SAO-RAS, Russia), A. J. Castro-Tirado (IAA-CSIC,\nSpain) on behalf of a larger collaboration report:\n\n\"We have redone astrometry of the optical afterglow\ncandidate reported by Fatkhullin et al. (GCNC 6547)\nfor GRB 070616 (Starling et al. GCNC 6542). The\nupdated position for the object is (J2000, +/- 0.5\"):\n\nR.A.: 02:08:36.12\nDec. +56:56:39.7\n\nA finding chart can be found at:\n\nhttp://www.iaa.es/~deugarte/GRBs/070616/GRB070616.gif \"\n\nThis message can be quoted."}', 'Astronomers at IAA-CSIC and SAO-RAS have updated the astrometry of the optical afterglow candidate for GRB 070616, providing a new position of (J2000, R.A.: 02:08:36.12, Dec.: +56:56:39.7). A finding chart is available at the provided URL.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6547', 'gcn', 'GRB 070616', '2007-06-17T05:52:23.000Z', '{"measurements":{"dec":"+56 56 41.0","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":22,"other_measurements":{"position_error":"1\"","time_after_event":"7.5 hr"},"ra":"02 08 36.00","redshift":null,"tables":[]},"authors":{"affiliations":["SAO-RAS, Russia","Cukurova Univ., Turkey","IAA-CSIC, Spain","Univ. de Jaén, Spain","IAA-CSIC, Spain","IAA-CSIC, Spain","Univ. de Jaén, Spain","Nikolaev St. Univ., Ukraine","IAA-CSIC, Spain"],"authors":["T. Fatkhullin","V. Sokolov","E. Sonbas","A. de Ugarte Postigo","M. Jelínek","J. Gorosabel","D. Pérez-Ramírez","S. Guziy","A. J. Castro-Tirado"],"institutions":["SAO-RAS (Russia)","Instituto de Astrofísica de Andalucía (IAA-CSIC)","Cukurova University","University of Jaén"],"universities":["University of Jaén","Instituto de Astrofísica de Andalucía (IAA-CSIC)","Cukurova University","Nikolaev National University"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["BTA (6m) SAO-RAS"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_class.js?notice_id=6542"],"basic_data":{"author":{"email":"ajct@iaa.es","institution":"Inst.de Astro. de Andalucia","name":"Alberto Castro-Tirado"},"coordinates":{},"detectionTime":"2007-06-17T05:52:23.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6547\nSUBJECT: GRB 070616: BTA optical observations\nDATE: 07/06/17 05:52:23 GMT\nFROM: Alberto Castro-Tirado at Inst.de Astro. de Andalucia  <ajct@iaa.es>\n\nT. Fatkhullin, V. Sokolov (SAO-RAS, Russia), E. Sonbas\n(Cukurova Univ., Turkey), A. de Ugarte Postigo, M. Jelínek,\nJ. Gorosabel (IAA-CSIC, Spain), D. Pérez-Ramírez (Univ.\nde Jaén, Spain), S. Guziy (Nikolaev St. Univ., Ukraine) and\nA. J. Castro-Tirado (IAA-CSIC, Spain),\n\nreport:\n\n\"Following the detection by SWIFT of GRB 070616 (Starling\net al. GCNC 6542), we have obtained single VRI frames at the\n6m BTA SAO-RAS telescope at Nizhnij Arkhyz (Russia), starting\nat 23:57 UT (i.e. 7.5 hr after the event). Within the SWIFT/XRT\nerror box , we detect in all filters a faint (R ~ 22), reddened\npoint-like source. Preliminary astrometry yielded RA (J2000)\n= 02 08 36.00; Dec (J2000) = +56 56 41.0  (+/- 1\"), a position\nvery close to the USNO B-1 star reported by Kann et al. (GCNC\n6545). Further observations are needed to confirm if this is the\noptical afterglow to GRB 070616. \"\n\nThis message can be quoted."}', 'Astronomical alert: GRB 070616: BTA optical observations', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6546', 'gcn', 'GRB070616', '2007-06-17T02:38:44.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["MSSL/UCL","Univ. Leicester"],"authors":["M. De Pasquale","R. Starling","P. Schady"],"institutions":["MSSL/UCL"],"universities":["MSSL-UCL","Univ. Leicester"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift/UVOT"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6546"],"basic_data":{"author":{"email":"mdp@mssl.ucl.ac.uk","institution":"MSSL-UCL","name":"Massimiliano de Pasquale"},"coordinates":{},"detectionTime":"2007-06-17T02:38:44.000Z","event":"GRB070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6546\nSUBJECT: Swift/UVOT observations of GRB070616\nDATE: 07/06/17 02:38:44 GMT\nFROM: Massimiliano de Pasquale at MSSL-UCL  <mdp@mssl.ucl.ac.uk>\n\nM. De Pasquale (MSSL/UCL), R. Starling (Univ. Leicester)\nand P. Schady (MSSL/UCL) report, on the behalf ot the Swift\nUVOT team:\n\n  The Swift UVOT telescope began its White filter finding\nchart exposure of GRB070616 (Starling et al., GCN circ 6542)\n144 seconds after the trigger. The XRT position lies on\na bright object, listed in the USNO-B1.0 catalogue, therefore\nwe caution that this source strongly affects the photometry.\nIn the XRT error circle we do not detect any optical\nafterglow. We derive the following 3 sigma upper limits:\n\n\nFilter  Time after trigger (s)  Exposure (s)   3s U.L.\n\n  White       144-243              98            18.3\n\n  V           250-649             390            18.1\n\n\n  White       144-979             209            18.6\n\n  V           250-1122            547            18.3\n\n  B           729-738             10             17.1\n\n  U           707-874             39             17.2\n\n  UW1         680-850             39             17.1\n\n  UM2         655-825             39             17.3\n\n  UW2         758-777             20             17.0\n\n\n  No correction has been made for the high Galactic\nreddening of E(B-V)=0.4. We note that this value should\nbe taken with caution, having the burst occurred at low\nGalactic latitude."}', 'Swift/UVOT team reports no optical afterglow detected for GRB070616 in XRT error circle. Upper limits on magnitudes in various filters are provided, with caution for high Galactic reddening.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6545', 'gcn', 'GRB 070616', '2007-06-17T01:39:22.000Z', '{"measurements":{"dec":"+56:56:22.3","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":15.44,"other_measurements":{"airmass":1.95},"ra":"02:08:34.67","redshift":null,"tables":[{"Ic limit":20.3,"date":"070617.00838","exp. time":600,"time (days)":0.32119}]},"authors":{"affiliations":["TLS Tautenburg"],"authors":["D. A. Kann, U. Laux, B. Stecklum, S. Klose"],"institutions":["TLS Tautenburg"],"universities":["TLS Tautenburg"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Tautenburg 1.34m Schmidt telescope"]},"urls":["<https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6545>"],"basic_data":{"author":{"email":"kann@tls-tautenburg.de","institution":"TLS Tautenburg","name":"Alexander Kann"},"coordinates":{},"detectionTime":"2007-06-17T01:39:22.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6545\nSUBJECT: GRB 070616: TLS observation\nDATE: 07/06/17 01:39:22 GMT\nFROM: Alexander Kann at TLS Tautenburg  <kann@tls-tautenburg.de>\n\nD. A. Kann, U. Laux, B. Stecklum and S. Klose (TLS Tautenburg) report:\n\nWe observed the field of Swift GRB 070616 (Starling et al., GCN 6542) with \nthe Tautenburg 1.34m Schmidt telescope. A single 600 second image in Ic \nwas obtained before clouds forced us to shut down. The airmass was 1.95.\n\nAt the XRT position (Starling et al., GCN 6542), we do not detect any \nafterglow. Assuming the USNO B1.0 star at RA = 02:08:34.67,\nDec. = +56:56:22.3 to have I = 15.44, we derive the following upper limit \nfor the image:\n\ndate\t\ttime (days)\texp. time\tIc limit\n070617.00838\t0.32119\t\t600\t\t20.3\n\nWe caution that, as Starling et al. (GCN 6542) noted, this is very close \nto a star in the USNO B1.0 catalog. Thus, the true limiting magnitude at \nthe XRT position is much shallower than what is stated above.\n\nJudging from the early BAT/XRT light curve, this is a real GRB that \nhappens to lie close to a bright star by chance. As the field is crowded, \nthe probability of such a chance alignement is non-negligible.\n\nThis message may be cited."}', 'The TLS Tautenburg team reported observing the field of GRB 070616 with their 1.34m Schmidt telescope and obtained a single 600-second image in Ic band before clouds forced them to shut down. They did not detect an afterglow at the XRT position due to its proximity to a bright star, deriving an upper limit of Ic = 20.3 for the image. The team cautions that the true limiting magnitude at the XRT position is shallower due to the star''s proximity.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6544', 'gcn', 'GRB070615', '2007-06-16T20:55:10.000Z', '{"measurements":{"dec":"-04d 24'' 26.6\"","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"background_counts_expected":"~0.07","count_confidence_range":"between 0.8 and 14.9 counts","counts_detected":5,"probability_background_fluctuation":"6e-7","uncertainty":"7.5 arcsec (90% containment radius)"},"ra":"02h 57m 15.37s","redshift":null,"tables":[]},"authors":{"affiliations":["(U. Leicester)","(INAF-OAB)"],"authors":["O. Godet","N. Lyons","K.L. Page","P.A. Evans","J. Osborne","R. Starling","G. Tagliaferri"],"institutions":["U.of Leicester","INAF-OAB"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"og19@star.le.ac.uk","institution":"U.of Leicester","name":"Olivier Godet"},"coordinates":{},"detectionTime":"2007-06-16T20:55:10.000Z","event":"GRB070615","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6544\nSUBJECT: Swift XRT observations of the INTEGRAL burst GRB070615: Possible\nDATE: 07/06/16 20:55:10 GMT\nFROM: Olivier Godet at U.of Leicester  <og19@star.le.ac.uk>\n\nO. Godet, N. Lyons, K.L. Page, P.A. Evans, J. Osborne, R. Starling\n(U. Leicester) and G.  Tagliaferri (INAF-OAB) report on behalf the\nSwift-XRT team:\n\nThe XRT started to observe the field of the INTEGRAL burst GRB 070615\n(Mereghetti et al., GCN 6537) 10.7h after the IBAS trigger. We analysed\naround 3ks of PC data. A possible weak and uncatalogued X-ray source is\ndetected at a position of:\n\nRA(J2000)  =  02h 57m 15.37s \nDec(J2000) = -04d 24'' 26.6\"\n\nwith an uncertainty of 7.5 arcsec (90% containment radius). This is 23\narcsec from the INTEGRAL position given by Mereghetti et al. (GCN Circ.\n6537). \n\nWe note that there are only 5 counts detected in the error circle\ncentred on this position. In this region, only ~0.07 background counts\nwould be expected. Using the Bayesian method to find a 99.7\\% level\nconfidence limit on the actual number of counts from the source, the\nrange would then be between 0.8 and 14.9 counts. We estimate the\nprobability that this detection is due to a background fluctuation to be\n6e-7, suggesting that this is a real detection.\n\nSince it is impossible to say whether or not the source is fading, we\ncannot say with any certainty that the source is the X-ray afterglow of\nGRB 070615.\n\nThis circular is an official product of the Swift-XRT team."}', 'The Swift XRT team reports the detection of a possible uncatalogued X-ray source, 23 arcsec from the position of the INTEGRAL burst GRB 070615. The source was detected after 10.7 hours and has an uncertainty of 7.5 arcsec. With only 5 counts detected and an expected background of 0.07 counts, the team estimates a probability of 6e-7 that this is a background fluctuation, suggesting a real detection.', 0.85, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6543', 'gcn', 'GRB 070616', '2007-06-16T20:11:00.000Z', '{"measurements":{"dec":"56d 56'' 45\"","distance":null,"duration":"175 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"end_of_downloaded_data":"T+500 sec","main_peak_time":"T+120 sec","start_time_of_low_level_emission":"~T-55 sec"},"ra":"02h 08m 23.0s","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/ORAU","GSFC","GSFC","GSFC/UMBC","LANL","GSFC","GSFC/USRA","GSFC/UMD","LANL","GSFC","GSFC","GSFC/ISAS","U Leicester","GSFC","GWU"],"authors":["M. Stamatikos","L. Barbier","S.D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","R.L.C. Starling","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","ORAU","GSFC/ORAU","GSFC/UMBC","GSFC","GSFC/USRA","GSFC/UMD","LANL","GWU","U Leicester"],"universities":["GSFC","UMBC","LANL","UMD","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-06-16T20:11:00.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6543\nSUBJECT: GRB 070616, Swift-BAT partial refined analysis\nDATE: 07/06/16 20:11:00 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nM. Stamatikos (GSFC/ORAU), L. Barbier (GSFC), S.D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), T. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS),\nR.L.C. Starling (U Leicester), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-239 to T+497 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 070616 (trigger #282445)\n(Starling, et al., GCN Circ. 6542).  The BAT ground-calculated position is\nRA, Dec = 32.096, 56.946 deg  which is \n   RA(J2000)  = 02h 08m 23.0s \n   Dec(J2000) = 56d 56'' 45\" \nwith an uncertainty of 2.6 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 60%.\n \nThe mask-weighted light curve shows many peaks.  The burst started with \na low-level smooth emission at ~T-55 sec continuing smoothly and increasing\nslowly until ~T+100 sec when the main emission started. The main peak is\nat T+120 sec.  Smaller overlapping peaks continue out past T+500 sec\n(the limit of the downloaded data so far).  We are currently in the gap\nof Malindi downlink passes, and will not receive more data until\n03:30 UT 17 Jul 07.  We will issue another Circular then describing\nthe activity beyond T+500 sec and giving the T90 value.  T90 is at least 175 sec.\n\nSince we do not have the full data set downlinked yet, we will not\nquote any spectral parameters at this time."}', 'Astronomers from NASA and various institutions have released a preliminary analysis of GRB 070616 (trigger #282445), a gamma-ray burst detected by the Swift-BAT team. The burst occurred on July 6, 2007, and the ground-calculated position is RA: 02h 08m 23.0s, Dec: 56d 56'' 45'''' with an uncertainty of 2.6 arcmin. The burst started with a low-level emission at ~T-55 sec, followed by a main peak at T+120 sec, and smaller overlapping peaks extending beyond T+500 sec. The duration of the burst is at least 175 seconds. The team will issue another circular with more data and the T90 value when they receive more downlinked data.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6542', 'gcn', 'GRB 070616', '2007-06-16T17:02:59.000Z', '{"measurements":{"dec":56.948,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":18.5,"other_measurements":{"exposure_time_unit_uvot":"seconds","exposure_time_uvot":100,"flux_unit_xrt":"erg/cm2/s","initial_flux_xrt":7.6e-9,"upper_limit_magnitude":18.5,"upper_limit_magnitude_unit":"mag"},"ra":32.155,"redshift":null,"tables":[]},"authors":{"affiliations":["U Leicester","GSFC","PSU","UMD","NASA/GSFC","INAF-OAB","LANL","NASA/ORAU"],"authors":["R. L. C. Starling","S. D. Barthelmy","A. P. Beardmore","D. N. Burrows","P. A. Evans","N. Gehrels","C. Guidorzi","J. A. Kennea","C. B. Markwardt","F. E. Marshall","P. T. O''Brien","J. P. Osborne","K. L. Page","D. M. Palmer","A. M. Parsons","G. Sato","M. Stamatikos","D. E. Vanden Berk","L. Vetere"],"institutions":["NASA/GSFC","INAF-OAB","CRESST/GSFC/UMD","NASA/ORAU"],"universities":["U Leicester","PSU","LANL","UMD","NASA/ORAU"]},"telescopes":{"facilities":[],"instruments":["Swift Team"],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":[],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-06-16T17:02:59.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6542\nSUBJECT: GRB 070616: Swift detection of a burst\nDATE: 07/06/16 17:02:59 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nR. L. C. Starling (U Leicester), S. D. Barthelmy (GSFC),\nA. P. Beardmore (U Leicester), D. N. Burrows (PSU),\nP. A. Evans (U Leicester), N. Gehrels (NASA/GSFC),\nC. Guidorzi (Univ Bicocca&INAF-OAB), J. A. Kennea (PSU),\nC. B. Markwardt (CRESST/GSFC/UMD), F. E. Marshall (NASA/GSFC),\nP. T. O''Brien (U Leicester), J. P. Osborne (U Leicester),\nK. L. Page (U Leicester), D. M. Palmer (LANL), A. M. Parsons (GSFC),\nG. Sato (GSFC/ISAS), M. Stamatikos (NASA/ORAU),\nD. E. Vanden Berk (PSU) and L. Vetere (PSU) report on behalf of the\nSwift Team:\n\nAt 16:29:33 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070616 (trigger=282445).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 32.155, +56.948 which is \n   RA(J2000)  =  02h 08m 37s\n   Dec(J2000) = +56d 56'' 53\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows nothing much \naround T_zero (as is typical for image triggers).  We note that there\nis bright and variable activity in the TDRSS lightcurve starting at T+100 sec\nand lasting to 600 sec.  This may be long-term burst activity, although we can\nnot rule out a contribution from a bright galactic source such as Cyg X-1\ncoming into the FOV (due to the slew).  We will be able to separate this \nambiguity when we get the full Malindi data to construct a mask-weighted \nlightcurve. \n\nThe XRT began observing the field at 16:31:44 UT, 131 seconds after the\nBAT trigger. XRT found a bright, variable and fading, uncatalogued X-ray source. \nUsing prompt downlinked data we find a position of \nlocated at RA, Dec 32.1513, +56.9451 which is\n   RA(J2000)  =  02h 08m 36.3s\n   Dec(J2000) =  56d 56'' 42.5\"\nwith an uncertainty of 4.9 arcseconds (radius, 90% containment). \nThis location is 12.7 arcseconds from the BAT on-board position,\nwithin the BAT error circle. The initial flux in the 2.5s image\nwas 7.6e-09 erg/cm2/s (0.2-10 keV). \nWe note that this is 3.1 arcseconds from source USNO-B1.0 1469-0076513. \n\n\nUVOT took a finding chart exposure of 100 seconds with the White (160-650 nm)\nfilter starting 142 seconds after the BAT trigger. No afterglow candidate has\nbeen found in the initial data products. The 2.7''x2.7'' sub-image covers 100% of\nthe XRT error circle. The typical 3-sigma upper limit has been about 18.5 mag. \nThe 8''x8'' region for the list of sources generated on-board covers 100% of the\nXRT error circle. The list of sources is typically complete to about 18 mag. No\ncorrection has been made for the large, but uncertain extinction expected."}', 'The Swift satellite detected a gamma-ray burst (GRB 070616) at 16:29:33 UT on June 7, 2016. The burst was located by the Burst Alert Telescope (BAT) and Swift immediately slewed to the position. The X-ray Telescope (XRT) identified a bright, variable, and fading X-ray source near the BAT location, and the Ultraviolet/Optical Telescope (UVOT) took a finding chart exposure but did not detect an afterglow candidate. The XRT initial flux was 7.6e-09 erg/cm2/s (0.2-10 keV), and the upper limit magnitude for UVOT was 18.5 mag.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6541', 'gcn', 'GRB 070612B', '2007-06-16T09:01:57.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":21.9,"other_measurements":{"Exp. (Ic)":"3x1200 seconds","Exp. (Rc)":"3x1800 seconds","Limit (Ic)":"22.0 (3 sigma)","Limit (Rc)":"22.2 (3 sigma)","Magnitude (Ic-band)":"21.9 +/- 0.16"},"ra":null,"redshift":null,"tables":[{"Exp.":"3x1800","Limit":"22.2","filter":"Rc","tmid (UT)":"June 13.917"},{"Exp.":"3x1200","Limit":"22.0","filter":"Ic","tmid (UT)":"June 13.975"}]},"authors":{"affiliations":["Bologna University, Italy","INAF/IASF Bologna, Italy","INAF/OAR, Italy","Second University of Rome Tor Vergata, Italy","Bologna Observatory, Italy"],"authors":["Giuseppe Greco","F. Terra","C. Bartolini","A. Guarnieri","A. Piccioni","G. Pizzichini","D. Nanni","R. Gualandi"],"institutions":["Bologna University","INAF/IASF Bologna","INAF/OAR","Second University of Rome Tor Vergata","Bologna Observatory"],"universities":["University of Bologna","Second University of Roma Tor Vergata"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Bologna Observatory"],"telescopes":["152 cm Loiano telescope"]},"urls":["sftp://ermione.bo.astro.it/publicGRB/GRB070612B"],"basic_data":{"author":{"email":"giuseppe.greco2@studio.unibo.it","institution":"U Bologna","name":"Giuseppe Greco"},"coordinates":{},"detectionTime":"2007-06-16T09:01:57.000Z","event":"GRB 070612B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6541\nSUBJECT: GRB 070612B: optical observations\nDATE: 07/06/16 09:01:57 GMT\nFROM: Giuseppe Greco at U Bologna  <giuseppe.greco2@studio.unibo.it>\n\nG. Greco (Bologna University), F. Terra (Second University of\nRoma \"Tor Vergata\"), C. Bartolini, A. Guarnieri, A. Piccioni\n(Bologna University), G. Pizzichini (INAF/IASF Bologna),\nD. Nanni (INAF/OAR and Second University of Rome \"Tor Vergata\"),\nR. Gualandi (Bologna Observatory) report:\n\n\nWe imaged the field of GRB 070612B (Grupe et al., GCN 6511) with the\n152 cm Loiano telescope in the Rc and Ic filters in clear sky conditions.\n\nWe do not detect any new sources in the combined images within the \nXRT error box (Grupe and Evans, GCN6521) with the following upper limits:\n\ntmid (UT)        filter        Exp.       Limit\nJune 13.917        Rc         3x1800      22.2   (3 sigma)\nJune 13.975        Ic         3x1200      22.0   (3 sigma)\n\nWe detect the faint source indicated by Cenko et\nal. (GCN 6521) at an Ic-band magnitude of 21.9+/-0.16\n\nMagnitude and upper limits were estimated by comparison with the\nUSNO-B1 stars and are not corrected for galactic dust extinction.\n\nThe co-added Ic image, in which the comparison stars are marked, has been\nposted in our public directory from where it can be retrieved\nby sftp using\nhostname: ermione.bo.astro.it\nusername: publicGRB\npassword: GRB_bo.\ndirectory: GRB070612B\n\n[GCN OPS NOTE(17jun07): Per author''s request, the reference to \"GCN 6517\"\nwas corrected to \"GCN 6521\", and \"GCN6514\" was corrected to \"GCN 6521\".]"}', 'A team of astronomers led by Giuseppe Greco at the University of Bologna reported non-detection of new sources in the error box of GRB 070612B using the 152 cm Loiano telescope in the Rc and Ic filters. They detected a faint source at an Ic-band magnitude of 21.9+/-0.16. The team also provided upper limits for magnitudes in Rc and Ic bands.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6540', 'gcn', 'GRB070615', '2007-06-16T08:12:52.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"v_filter":19.59,"white_filter":18.07},"other_measurements":{"E_B_V":0.12},"ra":null,"redshift":null,"tables":[{"Exp":2887,"T_mid":46354,"UL_Mag":19.59,"filter":"V"},{"Exp":36,"T_mid":51435,"UL_Mag":18.07,"filter":"White"}]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"ps@mssl.ucl.ac.uk","institution":"MSSL/Swift","name":"Patricia Schady"},"coordinates":{},"detectionTime":"2007-06-16T08:12:52.000Z","event":"GRB070615","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6540\nSUBJECT: UVOT Observations of INTEGRAL burst GRB070615\nDATE: 07/06/16 08:12:52 GMT\nFROM: Patricia Schady at MSSL/Swift  <ps@mssl.ucl.ac.uk>\n\nP.Schady (MSSL-UCL) and N. Lyons (Leicster) report on behalf of the \nUVOT team\n\nSwift/UVOT began observing the field of the INTEGRAL burst GRB070615 \n10.7hrs after the IBAS trigger in the V and white filters. No afterglow \nis detected in any of the individual or co-added observations down to \nthe following 5-sigma upper limits:\n\nFilter           T_mid (s) Exp (s)   UL Mag (5sig)\n====================================\nV\t\t46354\t2887\t19.59\nWhite\t51435\t36\t\t18.07\n====================================\n\nwhere T_mid corresponds to weighted mid time of the observation. The \nvalues quoted above are not corrected for the expected Galactic \nreddening of E(B-V) = 0.12 mag (Schlegel et al. 1998)."}', 'The Swift/UVOT team reported no detection of an afterglow from the INTEGRAL burst GRB070615 in V and white filters, setting 5-sigma upper limits of 19.59 mag for the V filter and 18.07 mag for the white filter.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-654', 'gcn', 'GRB000418', '2000-04-28T18:11:26.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":17.5,"other_measurements":{"limiting_magnitude":18.5,"uncertainty":0.5},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Thueringer Landessternwarte Tautenburg","Universitaets-Sternwarte Jena","DSRI, Copenhagen","LAEFF-INTA, Madrid","LAEFF-INTA, Madrid and IAA-CSIC, Granada","Max-Planck-Institut fuer Astronomie, Heidelberg","Max-Planck-Institut fuer Astronomie, Heidelberg and Calar Alto observatory","USRA/USNO","Clemson University","AIP Potsdam"],"authors":["B. Stecklum","S. Klose","O. Fischer","J. Gorosabel","C. Sanchez-Fernandez","A. Castro-Tirado","D. Butler","S. Hippler","Th. Ott","M. Kasper","R. Weiss","L. Montoya","A. Aguirre","A. Henden","D. H. Hartmann","J. Greiner"],"institutions":["Thueringer Landessternwarte Tautenburg","LAEFF-INTA","IAA-CSIC","USRA/USNO","AIP Potsdam"],"universities":["Universitaets-Sternwarte Jena","Max-Planck-Institut fuer Astronomie","Max-Planck-Institut fuer Extraterrestrische Physik","Clemson University"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Calar Alto observatory"],"telescopes":[]},"urls":[""],"basic_data":{"author":{"email":"klose@tls-tautenburg.de","institution":"TLS Tautenburg","name":"Sylvio Klose"},"coordinates":{},"detectionTime":"2000-04-28T18:11:26.000Z","event":"GRB000418","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 654\nSUBJECT: GRB000418, K''-band photometry\nDATE: 00/04/28 18:11:26 GMT\nFROM: Sylvio Klose at TLS Tautenburg  <klose@tls-tautenburg.de>\n\nB. Stecklum, S. Klose (Thueringer Landessternwarte Tautenburg), \nO. Fischer (Universitaets-Sternwarte Jena),\nJ. Gorosabel (DSRI, Copenhagen),  \nC. Sanchez-Fernandez (LAEFF-INTA, Madrid),\nA. Castro-Tirado (LAEFF-INTA, Madrid, and IAA-CSIC, Granada), \nD. Butler (Max-Planck-Institut fuer Extraterrestrische Physik, Garching),\nS. Hippler, Th. Ott, M. Kasper, R. Weiss\n   (Max-Planck-Institut fuer Astronomie, Heidelberg),\nL. Montoya, A. Aguirre (Max-Planck-Institut fuer Astronomie, Heidelberg, \n   and Calar Alto observatory),\nA. Henden (USRA/USNO), on behalf of the USNO GRB team,\nD. H. Hartmann (Clemson University, Clemson), and\nJ. Greiner (AIP Potsdam)\n\n\nreport:\n\nAs a supplement to our previous GCN report (Klose et al., GCN #645) we\ncan provide now a more accurate estimate of the K''-band magnitude of\nthe afterglow of GRB 000418. It is based on the assumption that the\nB-R colours of three USNO stars on the detection image are\nrepresentative for their spectral types. A value of K'' = 17.5 was\nfound with an uncertainty of 0.5 mag.\n\nIn addition, in GCN #645 one should read: The limiting magnitude of the \n(3.5-m) K''-band images is about 18.5.\n\nThis message is quotable."}', 'A new measurement of the K''-band magnitude for the afterglow of GRB 000418 has been reported, with a value of 17.5 and an uncertainty of 0.5 mag. This measurement was made by a collaboration of astronomers from various institutions and universities, using data from the Thueringer Landessternwarte Tautenburg, Universitaets-Sternwarte Jena, DSRI, LAEFF-INTA, IAA-CSIC, Max-Planck-Institut fuer Astronomie, USRA/USNO, Clemson University, and AIP Potsdam.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6539', 'gcn', 'GRB 070610', '2007-06-15T17:03:01.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"1 hour","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"frequency":"8.46 GHz","observation_time":"2007 June 15 13.67 UT","peak_radio_flux":"80 uJy ± 100 uJy"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NRAO","NRAO/UVA"],"authors":["Dale A. Frail","Poonam Chandra"],"institutions":["NRAO","Caltech-NRAO-Carnegie GRB Collaboration"],"universities":["University of Virginia","Caltech"]},"telescopes":{"facilities":["National Science Foundation"],"instruments":[],"observatories":["National Radio Astronomy Observatory"],"telescopes":["Very Large Array"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6539"],"basic_data":{"author":{"email":"pc8s@virginia.edu","institution":"U Virginia/NRAO","name":"Poonam Chandra"},"coordinates":{},"detectionTime":"2007-06-15T17:03:01.000Z","event":"GRB 070610","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6539\nSUBJECT: VLA upper limit on GRB 070610\nDATE: 07/06/15 17:03:01 GMT\nFROM: Poonam Chandra at U Virginia/NRAO  <pc8s@virginia.edu>\n\nDale A. Frail (NRAO) and Poonam Chandra (NRAO/UVA) report on\nbehalf of the Caltech-NRAO-Carnegie GRB Collaboration:\n\n\n\"We used the Very Large Array to observe the field of view toward GRB\n070610 (GCN 6489) at a frequency of 8.46 GHz on 2007 June 15  at  13.67\nUT for 1 hour.  The GRB is undetected and the peak radio flux at the\noptical afterglow position obtained from 1.5m OSN telescope (GCN 6501) is\n80 uJy � 100 uJy.\n\nThe National Radio Astronomy Observatory is a facility of the National\nScience Foundation operated under cooperative agreement by Associated\nUniversities, Inc.\""}', 'The Very Large Array (VLA) at the National Radio Astronomy Observatory did not detect GRB 070610 at a frequency of 8.46 GHz on June 15, 2007. The peak radio flux at the optical afterglow position was estimated to be between 80 and 100 uJy.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6538', 'gcn', 'GRB 070615', '2007-06-15T10:30:56.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":15,"other_measurements":{"time_after_trigger":"1m22s"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["University College Dublin, Ireland","GACE Valencia","IAA CSIC, Granada, Spain"],"authors":["John French","Petr Kubanek","Gary Melady","Mereghetti"],"institutions":["Watcher collaboration","GACE Valencia","IAA-CSIC"],"universities":["University College Dublin","Universidad Autónoma de Valencia","CSIC"]},"telescopes":{"facilities":["INTEGRAL"],"instruments":[],"observatories":["Boyden Observatory"],"telescopes":["Watcher 40cm robotic telescope"]},"urls":[],"basic_data":{"author":{"email":"jfrench@bermuda.ucd.ie","institution":"UCD,Ireland","name":"John French"},"coordinates":{},"detectionTime":"2007-06-15T10:30:56.000Z","event":"GRB 070615","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6538\nSUBJECT: GRB 070615\nDATE: 07/06/15 10:30:56 GMT\nFROM: John French at UCD,Ireland  <jfrench@bermuda.ucd.ie>\n\nJohn French (University College Dublin), Petr Kubanek (GACE Valencia),\nGary Melady (University College Dublin), Martin Jelinek IAA CSIC\nGranada)\n\nreport on behalf of the Watcher collaboration:\n\nThe Watcher 40cm robotic telescope, located at Boyden Observatory,\nSouth Africa, began imaging the field of INTEGRAL GRB 070615\n(Mereghetti et al., GCN 6537) at 02:22:08 UT, 1m22s after the IBAS\ntrigger.\n\nInitial observations were performed at high airmass and show no new\nsource down to an R-band limiting magnitude of approximately 15 (in\ncomparison with USNO-B1). Observations and analysis are ongoing.\n\nThis message may be cited."}', 'The Watcher collaboration reported observing GRB 070615 using the Watcher 40cm robotic telescope at Boyden Observatory, South Africa, 1 minute and 22 seconds after the IBAS trigger. Initial observations did not detect a new source with an R-band limiting magnitude of approximately 15.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6537', 'gcn', 'GRB 070615', '2007-06-15T03:18:15.000Z', '{"measurements":{"dec":-4.407888,"distance":null,"duration":30,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"duration_unit":"s","uncertainty":"2 arcmin"},"ra":44.307736,"redshift":null,"tables":[]},"authors":{"affiliations":["IASF-Milano, INAF, Italy","CEA-Saclay, France","ISDC, Versoix, Switzerland","CAMK, Torun, Poland"],"authors":["S.Mereghetti","A.Paizis","D.Gotz","V.Beckmmann","M.Beck","C.Steiner","J. Borkowski"],"institutions":["IASF-Milano","CEA-Saclay","ISDC, Versoix","CAMK, Torun"],"universities":["IASF-Milano","CEA-Saclay","ISDC, Versoix","CAMK, Torun"]},"telescopes":{"facilities":["IBAS"],"instruments":["IBIS/ISGRI"],"observatories":[],"telescopes":["IBIS/ISGRI"]},"urls":[],"basic_data":{"author":{"email":"sandro@iasf-milano.inaf.it","institution":"IASF/CNR","name":"Sandro Mereghetti"},"coordinates":{},"detectionTime":"2007-06-15T03:18:15.000Z","event":"GRB 070615","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6537\nSUBJECT: GRB 070615: A long GRB detected by INTEGRAL\nDATE: 07/06/15 03:18:15 GMT\nFROM: Sandro Mereghetti at IASF/CNR  <sandro@iasf-milano.inaf.it>\n\nS.Mereghetti, A.Paizis (IASF-Milano), D.Gotz (CEA-Saclay), V.Beckmmann, M. \nBeck, C.Steiner (ISDC, Versoix), and J. Borkowski (CAMK, Torun) on behalf \nof the IBAS Localization Team report:\n\nA GRB lasting about 30 s has been detected by IBAS in IBIS/ISGRI data on \nJune 15 at 02:20:45 UT\n\nThe coordinates (J2000)  are:\n\nRA: 44.307736 [degrees] \nDEC: -4.407888 [degrees]\n\nwith an uncertainty of 2  arcmin (90% c.l.).\n\nThe light curve is a single, FRED-like peak\n\nThis message can be cited."}', 'A long gamma-ray burst (GRB) lasting about 30 seconds was detected by IBIS/ISGRI on June 15, 2015 at 02:20:45 UT. The event occurred in the region of the sky with coordinates RA: 44.307736 degrees, DEC: -4.407888 degrees, with an uncertainty of 2 arcmin. The light curve shows a single, FRED-like peak.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6536', 'gcn', 'GRB 070610', '2007-06-15T01:27:13.000Z', '{"measurements":{"dec":"+26d14m06s","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"limiting_r_band":21.16,"limiting_r_band_error":0.4,"super_lotis_limiting_r_band":20.9,"super_lotis_limiting_r_band_error":0.3},"other_measurements":{"exposure_time":300,"exposure_time_unit":"seconds"},"ra":"19h55m09.6s","redshift":null,"tables":[]},"authors":{"affiliations":["Clemson University","Steward Observatory","MMT","FIT","University of Missouri - Rolla","Massachusetts Institute of Technology"],"authors":["Adria C. Updike","Peter A. Milne","Grant G. Williams","Jason Puls","Dieter H. Hartmann","Matt Wood","Josh Cardenzana","Shelsea Pederson"],"institutions":["Clemson U","Steward Observatory","MMT","FIT"],"universities":["Clemson University","University of Missouri - Rolla","Massachusetts Institute of Technology"]},"telescopes":{"facilities":["SARA Observatory"],"instruments":[],"observatories":["Kitt Peak"],"telescopes":["SARA 0.9m telescope"]},"urls":["http://saraobservatory.org"],"basic_data":{"author":{"email":"aupdike@clemson.edu","institution":"Clemson U","name":"Adria C. Updike"},"coordinates":{},"detectionTime":"2007-06-15T01:27:13.000Z","event":"GRB 070610","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6536\nSUBJECT: SWIFT J195509.6+261406 (GRB 070610): further observations\nDATE: 07/06/15 01:27:13 GMT\nFROM: Adria C. Updike at Clemson U  <aupdike@clemson.edu>\n\nAdria C. Updike (Clemson University), Peter A. Milne (Steward\nObservatory),  Grant G. Williams (MMT), Jason Puls, Dieter H. Hartmann\n(Clemson University), Matt Wood (FIT), Josh Cardenzana (U Missouri -\nRolla), and Shelsea Pederson (MIT) report:\n\n\nThe SARA 0.9m telescope at Kitt Peak imaged the field of SWIFT\nJ195509.6+261406 (GRB 070610) on June 12 from 09:11:24 UT until 10:03:24\nUT.  Our observations consisted of 10 300 sec exposures in the R band.\nThe source was marginally detected in the exposure beginning at 09:26:55\nUT, near our limiting magnitude of 21.16 +/- 0.4  It was not detected in\nthe other exposures.\n\nSuper-LOTIS observed the source on June 13.  It made four passes of the\nfield, beginning at 06:03:20 UT, 08:08:20 UT, 09:48:20 UT, and 10:48:20\nUT.  The source was not detected in the individual or stacked images,\ndown to a maximum limiting R-band magnitude of 20.9 +/- 0.3 (as measured\non the second pass).\n\n\nThe SARA Homepage can be found at:\nhttp://saraobservatory.org\n\nThis message may be cited."}', 'A team of astronomers led by Adria Updike at Clemson University reported observations of SWIFT J195509.6+261406 (GRB 070610) using the SARA 0.9m telescope at Kitt Peak and Super-LOTIS. The source was marginally detected in one R-band exposure with a limiting magnitude of 21.16 ± 0.4, but not in other observations or stacked images. The team did not detect the source in Super-LOTIS observations with a limiting magnitude of 20.9 ± 0.3.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6535', 'gcn', 'GRB 070612A', '2007-06-14T06:27:26.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"25 hours and 4 minutes","energy":null,"fluence":null,"magnitude":17.73,"other_measurements":{"error_magnitude":0.76,"exposure_duration":"6 minutes","observation_time":"June 13, 03:42:00 UT"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Clemson University","Steward Observatory","MMT"],"authors":["A. C. Updike","P. A. Milne","G. G. Williams","D. H. Hartmann"],"institutions":["Steward Observatory","MMT"],"universities":["Clemson University"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["0.6m Super-LOTIS telescope"]},"urls":[],"basic_data":{"author":{"email":"aupdike@clemson.edu","institution":"Clemson U","name":"Adria C. Updike"},"coordinates":{},"detectionTime":"2007-06-14T06:27:26.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6535\nSUBJECT: GRB 070612A: Super-LOTIS observations\nDATE: 07/06/14 06:27:26 GMT\nFROM: Adria C. Updike at Clemson U  <aupdike@clemson.edu>\n\nA. C. Updike (Clemson University), P. A. Milne (Steward Observatory), G.\nG. Williams (MMT), and D. H. Hartmann (Clemson University) report on\nbehalf of the Super-LOTIS collaboration:\n\nWe observed the field of GRB 070612A with the 0.6m Super-LOTIS telescope\non June 13, beginning at 03:42:00 UT, or 25 hours and 4 minutes after the\nburst trigger (282066).  In 6 minutes of stacked exposures, we marginally\ndetect the afterglow (Updike et al. GCN 6515, Cenko et al. GCN 6525) at an\nR-band magnitude of 17.73 +/- 0.76 as calibrated relative to 6 USNO B1.0\nstars.\n\nThis message may be cited."}', 'A team of astronomers led by A. C. Updike at Clemson University reported the detection of the afterglow of GRB 070612A using the 0.6m Super-LOTIS telescope 25 hours and 4 minutes after the burst trigger. The afterglow was detected at an R-band magnitude of 17.73 +/- 0.76.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6534', 'gcn', 'GRB 070612A', '2007-06-14T04:45:10.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":-1.88,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Columbia U."],"authors":["N. Mirabal","I. D. McGreer","J. P. Halpern"],"institutions":["MDM GRB follow-up team"],"universities":["Columbia U."]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/int_telegram.jsp?id=6525","http://gcn.gsfc.nasa.gov/gcn3/int_telegram.jsp?id=6515","http://gcn.gsfc.nasa.gov/gcn3/int_telegram.jsp?id=6510","http://gcn.gsfc.nasa.gov/gcn3/int_telegram.jsp?id=6526"],"basic_data":{"author":{"email":"mirabal@astro.columbia.edu","institution":"Columbia U","name":"Nestor Mirabal"},"coordinates":{},"detectionTime":"2007-06-14T04:45:10.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6534\nSUBJECT: GRB 070612A: Rapid Decay\nDATE: 07/06/14 04:45:10 GMT\nFROM: Nestor Mirabal at Columbia U  <mirabal@astro.columbia.edu>\n\nN. Mirabal, I. D. McGreer and J. P. Halpern (Columbia U.)\nreport on behalf of the MDM GRB follow-up team:\n\n\"We have re-observed the optical afterglow of Swift\nGRB 070612A (Updike et al. GCN 6515, Cenko et al.\nGCN 6525) in the R and i'' filters using the same\ninstrumental setup as in Mirabal et al. (GCN  6526).\nPreliminary calibration referenced to the SDSS photometry\nof field stars (Cool et al. GCN 6510) shows that the\nafterglow has faded by 1.88 mag since the previous night.\nThis corresponds to a decay rate steeper than ~ -2.5, which\nmight represent the end of an optical flash from reverse shock emission\n(Meszaros & Rees 1997, ApJ, 306, 301; Sari & Piran 1999,\nApJ, 496, L1). Alternatively, the steepening could be the\nsignature of a \"jet break\". Further observations are encouraged\nto distinguish between various possibilities.\""}', 'The afterglow of Swift GRB 070612A has faded by 1.88 magnitudes since the previous night, indicating a decay rate steeper than -2.5. This could be the end of an optical flash from reverse shock emission or the signature of a ''jet break''. Further observations are encouraged to distinguish between these possibilities.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6533', 'gcn', 'GRB 070612A', '2007-06-14T03:01:27.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"uehara@hirax7.hepl.hiroshima-u.ac.jp","institution":"Hiroshima U","name":"Takeshi Uehara"},"coordinates":{},"detectionTime":"2007-06-14T03:01:27.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6533\nSUBJECT: GRB 070612A: Suzaku/WAM observation of the prompt emission\nDATE: 07/06/14 03:01:27 GMT\nFROM: Takeshi Uehara at Hiroshima U  <uehara@hirax7.hepl.hiroshima-u.ac.jp>\n\nT. Uehara, M. Ohno, T. Takahashi, C. Kira, Y. Fukazawa (Hiroshima U.),\nT. Enoto, R. Miyawaki, K. Nakawaza, K. Makishima (Univ. of Tokyo),\nK. Yamaoka, Y. E. Nakagawa, S. Sugita (Aoyama Gakuin U.),\nY. Urata, K. Onda, M. Suzuki, K. Morigami, N. Kodaka, M. Tashiro, A. Endo (Saitama U.),\nT. Tamagawa, Y. Terada (RIKEN), S. Hong (Nihon U.),\nM. Suzuki, M. Kokubun, T. Takahashi (ISAS/JAXA), \nE. Sonoda, M.Yamauchi, S. Maeno, H. Tanaka, R. Hara(Univ. of Miyazaki),\nand Suzaku WAM team report:\n\nThe long burst, GRB 070612A (Swift/BAT trigger #282066; D. Grupe et al.,\nGCN Circ. 6509 ), was triggered at 02:38:41 UT (=T0) by the Suzaku Wide-band\nAll-sky Monitor (WAM) which covers an energy range of 50 keV - 5 MeV.\nThe observed light curve shows a single peaked structure with a duration (T90)\nof nearly 35 seconds. The fluence in 100-1000 keV was (8.2 +/- 2.4) * 10^-6 erg/cm^2.\nThe 1-s peak flux was 1.2 (+0.4, -0.3) photons/cm^2/s in the same energy range.\n\nPreliminary result shows that the time-averaged spectrum from T0-4 to\nT0+36 sec is well fitted by a single power law model with a photon index\nof 2.5 +/ -0.3 (chi^2/d.o.f. = 31/21).\n\nAll the quoted errors are at statistical 90% confidence level, in which\nthe systematic uncertainties are not included.\n\nThe WAM light curve of this event is available at the following web cite.\n\nhttp://www.astro.isas.ac.jp/suzaku/HXD-WAM/WAM-GRB/grb/trig/grb_table.html"}', 'The long gamma-ray burst (GRB) 070612A was detected by the Suzaku Wide-band All-sky Monitor (WAM) on June 7, 2007. The burst had a duration of approximately 35 seconds and a fluence of (8.2 +/- 2.4) * 10^-6 erg/cm^2 in the energy range of 100-1000 keV. Preliminary analysis suggests a single power law model fits the time-averaged spectrum from the burst''s start to 36 seconds later.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6532', 'gcn', 'GRB 070610', '2007-06-14T02:14:40.000Z', '{"measurements":{"dec":"+26:14:06","distance":null,"duration":[16,18,45,17],"energy":null,"fluence":null,"magnitude":[18.9,18.7,18.4,19.2,21.4],"other_measurements":{},"ra":"19:55:09.6","redshift":null,"tables":[{"approx_peak_mag":18.9,"duration":16,"t_start":"21:55:45"},{"approx_peak_mag":18.7,"duration":18,"t_start":"22:23:13"},{"approx_peak_mag":18.4,"duration":45,"t_start":"22:26:33"},{"approx_peak_mag":19.2,"duration":17,"t_start":"22:34:14"}]},"authors":{"affiliations":["MPE, Garching","FORTH, Heraklion (3)=NCAC, Torun","Univ. of Crete"],"authors":["A. Stefanescu","A. Slowikowska","G. Kanbach","S. Duscha","F. Schrey","H. Steinle","Z. Ioannou"],"institutions":["FORTH, Foundation for Research and Technology - Hellas","NCAC, Nicolaus Copernicus Astronomical Centre"],"universities":["University of Crete","MPE, Max-Planck-Institut für extraterrestrische Physik"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["University of Crete, Greece"],"telescopes":["1.3m Skinakas Observatory"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6532"],"basic_data":{"author":{"email":"astefan@mpe.mpg.de","institution":"MPE","name":"Alexander Stefanescu"},"coordinates":{},"detectionTime":"2007-06-14T02:14:40.000Z","event":"GRB 070610","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6532\nSUBJECT: SWIFT J195509.6+261406 / GRB 070610: OPTIMA-Burst observations\nDATE: 07/06/14 02:14:40 GMT\nFROM: Alexander Stefanescu at MPE  <astefan@mpe.mpg.de>\n\nA. Stefanescu (1), A. Slowikowska (2)(3), G. Kanbach (1), S. Duscha (1),\nF. Schrey (1), H. Steinle (1), Z. Ioannou (4) of the OPTIMA-Burst Team\nreport the following:\n(1)=MPE, Garching, (2)=FORTH, Heraklion (3)=NCAC, Torun (4)=Univ. of Crete\n\n\"OPTIMA-Burst at the 1.3m Skinakas Observatory of the University of\nCrete, Greece continued observations of the OT associated with SWIFT \nJ195509.6+261406 (GRB 070610).\n\nOn 2007-06-12 we observed the source during 21:00-23:10 UT, using our \nphoton counting mode. In this period we detected flaring activity \nconsisting of only four short, dim flares:\n\nt_start      duration   approx peak mag.\n21:55:45     16s        18.9\n22:23:13     18s        18.7\n22:26:33     45s        18.4\n22:34:14     17s        19.2\n\n\nOn 2007-06-13 we observed the source between 20:15-20:43 UT and \n20:59-22:10 UT. We did not detect any flaring activity, the source \nstayed below the background level detected by our photon counters at all \ntimes. The brightness of a fluctuation 1 sigma above background noise \ncorresponds roughly to 21.4 mag.\n\nWe conclude that the flaring activity of the optical counterpart of \nSWIFT J195509.6+261406 (GRB 070610) is greatly diminished, or may have \neven come to an end.\"\n\nThis message may be cited.\n\n[GCN OPS NOTE(17jun07):  Per author''s request, the two epoch dates\nwere corrected from \"2007-06-13\" to \"2007-06-12\" in the 2nd paragraph\nand from \"2007-06-14\" to \"2007-06-13\" in the 3rd paragraph.]"}', 'The OPTIMA-Burst team reports observing diminished or possibly ended flaring activity of the optical counterpart of SWIFT J195509.6+261406 (GRB 070610) using the 1.3m Skinakas Observatory. Four short, dim flares were detected on June 12, 2007, with magnitudes ranging from 18.9 to 19.2 and durations from 16 to 45 seconds. No flaring activity was detected during later observations on June 13, 2007.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6531', 'gcn', 'GRB070612A', '2007-06-13T23:25:29.000Z', '{"measurements":{"dec":"+37:16:15","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"Ic":"17.1 mag +/- 0.3 mag","Rc":"> 16.7 mag"},"other_measurements":{},"ra":"08:05:29.6","redshift":null,"tables":[{"band":"Rc","exp.time":"4 x 1 min.","magnitude":"> 16.7 mag (upper limit)","mid-UT":"June 12 11:23"},{"band":"Ic","exp.time":"4 x 1 min.","magnitude":"17.1 mag +/- 0.3 mag","mid-UT":"June 12 11:34"}]},"authors":{"affiliations":["OAO, NAOJ",""],"authors":["M. Yoshida","K. Yanagisawa","Y. Shimizu","S. Nagayama","N. Kawai"],"institutions":["MITSuME collaboration"],"universities":["Okayama Astrophysical Observatory","NAOJ","Tokyo Tech"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Okayama Astrophysical Observatory"],"telescopes":["50cm MITSuME telescope"]},"urls":["<https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6509>","<https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6525>"],"basic_data":{"author":{"email":"yoshida@oao.nao.ac.jp","institution":"Okayama Astrophysical Obs","name":"Michitoshi Yoshida"},"coordinates":{"dec":37.270833333333336,"ra":8.091555555555557},"detectionTime":"2007-06-13T23:25:29.000Z","event":"GRB070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6531\nSUBJECT: GRB070612A: MITSuME Okayama Observation\nDATE: 07/06/13 23:25:29 GMT\nFROM: Michitoshi Yoshida at Okayama Astrophysical Obs  <yoshida@oao.nao.ac.jp>\n\nM. Yoshida, K. Yanagisawa, Y. Shimizu, S. Nagayama (OAO, NAOJ)\nand N. Kawai (Tokyo Tech) report on behalf of the MITSuME\ncollaboration:\n\nWe performed optical imaging observations (Rc and Ic) of the\nfield of GRB 070612A (Grupe et al., GCN 6509) with 50cm MITSuME\ntelescope at Okayama Astrophysical Observatory from UT 11:19 to\nUT 11:27 on June 12 2007.\n\nWe coadded 4 CCD frames for each band. Exposure time of each\nframe is 1 minute. We made flux calibration using USNO B1.0\ncatalg. We found a faint source at the position of the afterglow\ncandidate reported by Cenko et al. (GCN 6525, RA:08:05:29.6,\nDEC:+37:16:15) in Ic band. The Ic magnitude was 17.1 +/- 0.3.\nThere was no source brigher than 16.7 magnitude in Rc band. Flux\ncalibration was made with three USNO-B stars around the object.\n\n---------------------------------------------------------------\nband  mid-UT          exp.time     magnitude\nRc    June 12 11:23   4 x 1 min.   > 16.7 mag (upper limit)\nIc    June 12 11:34   4 x 1 min.   17.1 mag +/- 0.3 mag\n---------------------------------------------------------------"}', 'The MITSuME collaboration at Okayama Astrophysical Observatory performed optical imaging observations of GRB 070612A using a 50cm MITSuME telescope. They detected a faint source in the Ic band with a magnitude of 17.1 +/- 0.3, and no source brighter than 16.7 mag was detected in the Rc band.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6530', 'gcn', 'GRB 070612A', '2007-06-13T21:02:58.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":18.3,"other_measurements":{"magnitude_uncertainty":"+/- 0.4","observation_duration":"15 minutes","time_since_trigger":"24 hours"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Clemson University","FIT","U Missouri - Rolla","MIT"],"authors":["Adria C. Updike","Jason Puls","Dieter H. Hartmann","Matt Wood","Josh Cardenzana","Shelsea"],"institutions":["Clemson U","FIT","U Missouri - Rolla","MIT"],"universities":["Clemson University","FIT","U Missouri - Rolla","MIT"]},"telescopes":{"facilities":["SARA Observatory"],"instruments":[],"observatories":["Kitt Peak"],"telescopes":["SARA 0.9m telescope"]},"urls":["http://saraobservatory.org"],"basic_data":{"author":{"email":"aupdike@clemson.edu","institution":"Clemson U","name":"Adria C. Updike"},"coordinates":{},"detectionTime":"2007-06-13T21:02:58.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6530\nSUBJECT: GRB 070612A: continued SARA observations\nDATE: 07/06/13 21:02:58 GMT\nFROM: Adria C. Updike at Clemson U  <aupdike@clemson.edu>\n\nAdria C. Updike, Jason Puls, Dieter H. Hartmann (Clemson University), \nMatt Wood (FIT), Josh Cardenzana (U Missouri - Rolla), and Shelsea \nPederson (MIT) report:\n\nWe re-imaged the field of GRB 070612A (GCN 6509, Grupe et al.) with the \nSARA 0.9m telescope at Kitt Peak under decent weather conditions.  We \nobtained 15 minutes of R-band images beginning 24 hours after the \ntrigger (282006).\n\nThe afterglow (Updike et al. GCN 6515, Cenko et al. GCN 6525) is \ndetected at a R-band magnitude of 18.3 +/- 0.4 as calibrated relative to \n9 USNO B1.0 stars, thus confirming the fading behavior.\n\n\nThe SARA Homepage can be found at:\nhttp://saraobservatory.org\n\nThis message may be cited."}', 'Astronomers at Clemson University, FIT, U Missouri - Rolla, and MIT used the SARA 0.9m telescope at Kitt Peak to observe the afterglow of GRB 070612A, confirming its fading behavior with a magnitude of 18.3 +/- 0.4.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-653', 'gcn', 'GRB 000418', '2000-04-28T13:51:38.000Z', '{"measurements":{"dec":"+20:06:11.1","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":22.8,"other_measurements":{"decline_rate":-0.84,"decline_rate_error":0.2,"magnitude_error":0.31,"reference_star_magnitude":15.4},"ra":"12:25:19.30","redshift":null,"tables":[]},"authors":{"affiliations":["Columbia U.","Ohio State U.","MDM Observatory"],"authors":["N. Mirabal","J. P. Halpern","R. M. Wagner"],"institutions":["MDM Observatory"],"universities":["Columbia U.","Ohio State U."]},"telescopes":{"facilities":[],"instruments":[],"observatories":["MDM Observatory"],"telescopes":["MDM 2.4m telescope"]},"urls":[],"basic_data":{"author":{"email":"abulafia@astro.columbia.edu","institution":"Columbia U.","name":"Nestor Mirabal"},"coordinates":{"dec":20.082722222222223,"ra":12.422027777777776},"detectionTime":"2000-04-28T13:51:38.000Z","event":"GRB 000418","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 653\nSUBJECT: GRB 000418, Optical Observation\nDATE: 00/04/28 13:51:38 GMT\nFROM: Nestor Mirabal at Columbia U.  <abulafia@astro.columbia.edu>\n\nN. Mirabal, J. P. Halpern (Columbia U.), R. M. Wagner (Ohio State U.)\nreport on behalf of the MDM Observatory GRB follow-up team:\n\n\"We obtained additional R-band images of the afterglow candidate\nfor GRB 000418(Klose et al., GCN #645) using the\nMDM 2.4m telescope. The object located at (J2000) RA 12:25:19.30,\nDec. +20:06:11.1 has an estimated magnitude R = 22.8 +/- 0.31 on\nApril 28.3 UT, this magnitude is referenced to USNO star\n(J2000) RA 12:25:25.62, Dec +20:04:57.8 (R = 15.4).\nThe decline is consistent with the -0.84 +/- 0.2 power-law\nderived from previous detections (Mirabal et al., GCN #646,#650). In\naddition we note that the OT appears to be slightly extended which might\nbe an indication of residual light from an underlying host galaxy.\n\nThis message may be cited.\""}', 'The MDM Observatory GRB follow-up team reports an R-band magnitude of 22.8 (+/- 0.31) for the afterglow candidate of GRB 000418 using the MDM 2.4m telescope. The object, located at RA 12:25:19.30, Dec. +20:06:11.1, shows a consistent decline with a power-law rate of -0.84 +/- 0.2. An extended optical transient is also observed, suggesting the presence of an underlying host galaxy.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6529', 'gcn', 'GRB 070612A', '2007-06-13T19:28:21.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":["15-25 keV","50-100 keV","25-50 keV","100-350 keV"],"fluence":null,"magnitude":null,"other_measurements":{"spectral_lag_1":"2.5 s +2.1-1.8 s (2.5 +0.7-0.5 s)","spectral_lag_2":"5.8 s +2.6-1.9 s"},"ra":null,"redshift":"~ 0.1","tables":[]},"authors":{"affiliations":["Stanford U","GSFC","U.Denver"],"authors":["J.P. Norris","S.D. Barthelmy","N. Gehrels"],"institutions":["GSFC","U.Denver"],"universities":["Stanford U"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"jpnorris@stanford.edu","institution":"Stanford U","name":"Jay Norris"},"coordinates":{},"detectionTime":"2007-06-13T19:28:21.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6529\nSUBJECT: GRB 070612A:  spectral lag\nDATE: 07/06/13 19:28:21 GMT\nFROM: Jay Norris at Stanford U  <jpnorris@stanford.edu>\n\nJ.P. Norris (U.Denver), S.D. Barthelmy (GSFC), N. Gehrels (GSFC):\n\nSpectral lag analysis of the two main emission episodes in GRB 070612A,\ndescribed in GCN Circ. 6522 (Barthelmy et al.) indicate that this burst\nhas relatively long lags, comparable to and longer than that of GRB 980425\n(~ 2-3 s), the first burst associated with a supernova.\n\nFor the first, brighter FRED-like pulse structure, the lag measurement\nbetween BAT energy bands 15-25 keV and 50-100 keV (25-50 and 100-350 keV)\nis 2.5 s +2.1-1.8 s (2.5 +0.7-0.5 s).\n\nFor the second, dimmer pulse structure, the 15-25 keV to 50-100 keV\nlag is 5.8 s +2.6-1.9 s.  The flux in the 100-350 keV band for this\nsecond episode was too low to make a useful measurement.\n\nSpectral lags of several seconds indicate a relatively low luminosity\nburst, consistent with the nearby host (z ~ 0.1) described in GCN Circ.\n6525 (Cenko et al.)."}', 'GRB 070612A, a gamma-ray burst with a redshift of ~ 0.1, exhibits relatively long spectral lags of approximately 2.5 seconds for the first, brighter pulse and 5.8 seconds for the second, dimmer pulse in its emission. These findings suggest a lower luminosity burst and are consistent with the nearby host described in a previous alert.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6528', 'gcn', 'GRB 070611', '2007-06-13T17:57:50.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":19.08,"other_measurements":{"initial exposure duration":440,"initial exposure mid-time":"02:05:21","limiting magnitude":19.2},"ra":null,"redshift":null,"tables":[{"Rmag":19.08,"Rmag uncertainty":0.24,"exp(s)":900,"mean time UT":"02:18:56","t-t0(s)":1316},{"Rmag":18.53,"Rmag uncertainty":0.24,"exp(s)":210,"mean time UT":"02:32:48","t-t0(s)":2148},{"Rmag":19.12,"Rmag uncertainty":0.3,"exp(s)":180,"mean time UT":"02:37:11","t-t0(s)":2411},{"Rmag":18.99,"Rmag uncertainty":0.26,"exp(s)":240,"mean time UT":"02:42:46","t-t0(s)":2746},{"Rmag":19.19,"Rmag uncertainty":0.24,"exp(s)":330,"mean time UT":"02:48:54","t-t0(s)":3144}]},"authors":{"affiliations":["UCD","IAA CSIC Granada, Spain"],"authors":["Gary Melady","John French","Petr Kubanek","Martin Jelinek"],"institutions":["IAA CSIC Granada, Spain"],"universities":["University College Dublin"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Boyden Observatory"],"telescopes":["Watcher 40cm robotic telescope"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"gmelady@bermuda.ucd.ie","institution":"UCD","name":"Gary Melady"},"coordinates":{},"detectionTime":"2007-06-13T17:57:50.000Z","event":"GRB 070611","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6528\nSUBJECT: GRB 070611: Watcher Observations\nDATE: 07/06/13 17:57:50 GMT\nFROM: Gary Melady at UCD  <gmelady@bermuda.ucd.ie>\n\nGary Melady, John French, (University College Dublin), Petr Kubanek, \nMartin Jelinek (IAA CSIC Granada, Spain)\n\non behalf of the Watcher collaboration report:\n\nThe Watcher 40cm robotic telescope, located at Boyden Observatory, South\nAfrica, began imaging the field of GRB 070611 (Stroh et al., GCN\n6494) at 01:58:33 UT, 1m 17s after the Swift trigger (40s after receipt of \nthe GCN notice).\n\nWe combined our initial series of 10s exposures to create a 440s unfiltered \nimage with an exposure mid-time of 2:05:21 (501s after the burst). This shows \nno new source in the XRT error box (Stroh et al., GCN 6496) down to an R-band \nlimiting magnitude of approx. 19.2 (in comparison to USNO-B1). Later images show \na faint, uncatalogued source within the XRT error box coincident with the ROTSE \ndetection (Rykoff et al., GCN 6497).\n\nThese observations are summarised below:\n\nmean time UT      t-t0(s) \texp(s) \t      Rmag\n-------------------------------------------------------- \n 02:18:56          1316\t\t 900\t  19.08 +/- 0.24\n 02:32:48\t   2148\t\t 210\t  18.53 +/- 0.24\n 02:37:11\t   2411\t\t 180\t  19.12 +/- 0.30\n 02:42:46\t   2746\t\t 240\t  18.99 +/- 0.26\n 02:48:54\t   3144\t\t 330\t  19.19 +/- 0.24\n\nThe source is not detected in subsequent observations down to an R-band limiting \nmagnitude of approx 19.2.\n\nThe field was no longer observed after 02:54 due to the system''s\nincorrect handling of the retracted XRT position.\n\nThis message may be cited."}', 'The Watcher collaboration reported observations of GRB 070611 using the Watcher 40cm robotic telescope at Boyden Observatory. Initial images showed no new source within the XRT error box, but later images detected a faint, uncatalogued source within the error box with a magnitude of approximately 19.08. The source was not detected in subsequent observations, and the observations ended due to a system error.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6527', 'gcn', 'Swift Trigger 282176 is Cygnus X-1', '2007-06-13T11:33:54.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Penn State University","GSFC (Goddard Space Flight Center)","Penn State University","Penn State University","Los Alamos National Laboratory","University of Bicocca & INAF-OAB","University of Leicester"],"authors":["L. Vetere","S. D. Barthelmy","D. Grupe","J. A. Kennea","D. M. Palmer","P. Romano","R. L. C. Starling"],"institutions":["GSFC (Goddard Space Flight Center)"],"universities":["Penn State University (PSU)","University of Leicester","University of Bicocca","Los Alamos National Laboratory (LANL)"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[""],"basic_data":{"author":{"email":"palmer@lanl.gov","institution":"LANL","name":"David Palmer"},"coordinates":{},"detectionTime":"2007-06-13T11:33:54.000Z","event":"Swift Trigger 282176 is Cygnus X-1","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6527\nSUBJECT: Swift Trigger 282176 is Cygnus X-1\nDATE: 07/06/13 11:33:54 GMT\nFROM: David Palmer at LANL  <palmer@lanl.gov>\n\nL. Vetere (PSU), S. D. Barthelmy (GSFC), D. Grupe (PSU),\nJ. A. Kennea (PSU), D. M. Palmer (LANL),\nP. Romano (Univ. Bicocca & INAF-OAB) and\nR. L. C. Starling (U Leicester) report on behalf of the Swift Team:\n\nBAT trigger 282176 (2007-06-13 11:13:41 UT) was not a GRB. \nInstead, it is the remnant of the Cyg X-1 peak after\nbright source peak removal in the image (cleaning). \n\nThis is an instrumental and statistical artifact, and does \nnot indicate an interesting variation in the Cyg X-1 flux."}', 'Swift Trigger 282176, previously identified as a potential gamma-ray burst, was found to be an instrumental artifact from the remnant of Cygnus X-1. This false alarm does not indicate any significant variation in the flux of Cygnus X-1.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6526', 'gcn', 'GRB 070612A', '2007-06-13T04:38:28.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"i''":18.4,"r''":19},"other_measurements":{"i'' uncertainty":0.2,"r'' uncertainty":0.3},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Columbia U.","Ohio State U.","MDM GRB follow-up team"],"authors":["N. Mirabal","I. D. McGreer","J. P. Halpern","M. Dietrich","B. M. Peterson"],"institutions":["MDM GRB follow-up team"],"universities":["Columbia U.","Ohio State U."]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["MDM 2.4m telescope"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msfc?id=6525","http://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msfc?id=6515"],"basic_data":{"author":{"email":"mirabal@astro.columbia.edu","institution":"Columbia U","name":"Nestor Mirabal"},"coordinates":{},"detectionTime":"2007-06-13T04:38:28.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6526\nSUBJECT: GRB 070612A: MDM Observations\nDATE: 07/06/13 04:38:28 GMT\nFROM: Nestor Mirabal at Columbia U  <mirabal@astro.columbia.edu>\n\nN. Mirabal, I. D. McGreer, J. P. Halpern (Columbia U.),\nM. Dietrich, B. M. Peterson (Ohio State U.) report on\nbehalf of the MDM GRB follow-up team:\n\n\"We observed the candidate optical afterglow of Swift\nGRB 070612A (Updike et al. GCN 6515, Cenko et al.\nGCN 6525) using the MDM 2.4m telescope. Preliminary\ncalibration with respect to USNO magnitudes\nof nearby stars yields r'' ~ 19.0 +/- 0.3 on June 13 03:59 UT\nand i'' ~ 18.4 +/- 0.2 on June 13 03:49 UT respectively.\nThese measurements indicate that the afterglow\nhas faded with respect to previous reports.\""}', 'The MDM GRB follow-up team reported observations of Swift GRB 070612A using the MDM 2.4m telescope. Preliminary measurements indicate that the optical afterglow has faded since previous reports, with r'' magnitude at 19.0 +/- 0.3 and i'' magnitude at 18.4 +/- 0.2 on June 13, 2013.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6525', 'gcn', 'GRB 070612A', '2007-06-12T22:15:19.000Z', '{"measurements":{"dec":"+37:16:15.2","distance":null,"duration":"370 s","energy":null,"fluence":null,"magnitude":{"i_prime_final":16.27,"i_prime_initial":16.97},"other_measurements":{"angle_from_sun":"~ 38 degrees","offset_from_host_galaxy":"~ 14\"","time_after_burst_first_image":"1.8 hr","time_after_burst_second_image":"2.2 hours"},"ra":"08:05:29.61","redshift":"0.096 +/- 0.023","tables":[]},"authors":{"affiliations":["Caltech","Penn State"],"authors":["S. B. Cenko","E. O. Ofek","D. B. Fox"],"institutions":["Caltech","Penn State"],"universities":["Caltech","Penn State"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Palomar 60-inch telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_read_abstract.msf?id=6525"],"basic_data":{"author":{"email":"cenko@srl.caltech.edu","institution":"Caltech","name":"S. Bradley Cenko"},"coordinates":{"dec":37.27088888888889,"ra":8.091558333333333},"detectionTime":"2007-06-12T22:15:19.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6525\nSUBJECT: GRB 070612A: P60 Confirmation of Afterglow and An Underlying, Nearby\nDATE: 07/06/12 22:15:19 GMT\nFROM: S. Bradley Cenko at Caltech  <cenko@srl.caltech.edu>\n\nS. B. Cenko, E. O. Ofek (Caltech) and D. B. Fox (Penn State) report on\nbehalf of a larger collaboration:\n\nWe have imaged the field of GRB 070612A (Grupe et al., GCN 6509) with the\nautomated Palomar 60-inch telescope.  Images were taken in the Sloan i''\nfilter beginning at 4:27:29 12 June UT (~ 1.8 hr after the burst) at large\nairmass (> 2.5).\n\nInside the BAT error circle we identify a bright, stationary, variable\nsource located at coordinates (J2000.0):\n\n  \tRA: 08:05:29.61\n  \tDec: +37:16:15.2\n\nThe object increases in brightness over the duration of our exposure,\nranging from i'' = 16.97 in our first image to i'' = 16.27 approximately 2.2\nhours after the burst.\n\nGiven the brightness, we consider it likely this is the same candidate\nproposed by Updike et al. (GCN 6515), despite the fact that their position\ndiffers from ours by ~ 14\".  Furthermore, as first noted by this group,\nthere is a faint galaxy underlying the OT visible in the SDSS images of\nthis field (Cool et al., GCN 6510) located at RA: 08:05:29.64, Dec:\n+37:16:14.6 (J2000.0).  The photometric redshift, taken from the SDSS\ndatabase, for this putative host is z = 0.096 +/- 0.023.\n\nAltogether, GRB 070612A has 1) a very long duration (t90 ~ 370 s;\nBarthelmy et al., GCN 6522), 2) a bright, rising optical afterglow at t ~\n2 hr, and 3) an underlying, nearby (z ~ 0.1) putative host galaxy.  In all\nthese ways it is similar to XRF 060218.  Despite its proximity to the\nsun (~ 38 degrees away and setting), we encourage follow-up observations\nat all wavelengths while still possible to further investigate this\ninteresting source and search for signs of an associated supernova."}', 'Astronomers report the detection of a bright, variable source in the afterglow of GRB 070612A using the Palomar 60-inch telescope. The source, located near the burst coordinates, is considered likely to be the same candidate identified by Updike et al. despite a slight position difference. The underlying, nearby galaxy detected in SDSS images is proposed as the putative host, with a redshift of z = 0.096 +/- 0.023. GRB 070612A exhibits a long duration (t90 ~ 370 s), a bright, rising optical afterglow at t ~ 2 hr, and an underlying, nearby (z ~ 0.1) putative host galaxy, making it similar to XRF 060218. Follow-up observations are encouraged to further investigate this interesting source.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6524', 'gcn', 'GRB 070612B', '2007-06-12T21:22:00.000Z', '{"measurements":{"dec":null,"distance":null,"duration":65,"energy":null,"fluence":null,"magnitude":20.6,"other_measurements":{"limiting_magnitude_uncertainty":0.6,"observation_duration_minutes":65,"observation_start_delay_minutes":24},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Clemson University","ETSU","SARA REU program"],"authors":["Adria C. Updike","Dieter H. Hartmann","Gary Henson","Robert Mesler","Christina Bunker","Jason Carson"],"institutions":["Clemson U","ETSU","SARA REU program"],"universities":["Clemson University","ETSU"]},"telescopes":{"facilities":["SARA"],"instruments":[],"observatories":["Kitt Peak"],"telescopes":["0.9m SARA telescope"]},"urls":["http://saraobservatory.org"],"basic_data":{"author":{"email":"aupdike@clemson.edu","institution":"Clemson U","name":"Adria C. Updike"},"coordinates":{},"detectionTime":"2007-06-12T21:22:00.000Z","event":"GRB 070612B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6524\nSUBJECT: GRB 070612B: SARA upper limit\nDATE: 07/06/12 21:22:00 GMT\nFROM: Adria C. Updike at Clemson U  <aupdike@clemson.edu>\n\nAdria C. Updike, Dieter H. Hartmann (Clemson University), Gary Henson\n(ETSU), Robert Mesler, Christina Bunker, and Jason Carson (ETSU/SARA REU\nprogram) report:\n\nUsing the 0.9m SARA telescope at Kitt Peak, we imaged the field of GRB \n070612B (GCN 6511, Grupe et al.).  Observations began 24 minutes after \nthe trigger (282073) and consisted of 65 minutes of R-band images.\n\nWe do not detect any new sources in the refined XRT error box (GCN 6521, \nGrupe et al.) or at the position indicated by P60 (GCN 6517, Cenko et \nal.) down to a limiting magnitude of 20.6 +/- 0.6 in the R-band as \ncalibrated relative to 10 USNO B1.0 stars.\n\n\nThe SARA Homepage can be found at:\nhttp://saraobservatory.org\n\nThis message may be cited."}', 'A team of astronomers using the 0.9m SARA telescope at Kitt Peak reported no detection of any new sources near GRB 070612B down to a limiting magnitude of 20.6 ± 0.6 in the R-band. This observation did not find any source in the refined XRT error box or at the position indicated by P60.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6523', 'gcn', 'GRB 070612B', '2007-06-12T20:39:42.000Z', '{"measurements":{"dec":-8.747,"distance":null,"duration":13.5,"energy":null,"fluence":0.0000017,"magnitude":null,"other_measurements":{"fluence_band":"15-150 keV","fluence_unit":"erg/cm2","partial_coding":17,"peak_photon_flux":2.6,"peak_photon_flux_band":"15-150 keV","peak_photon_flux_unit":"ph/cm2/sec","power_law_index":1.55},"ra":261.716,"redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/UMBC","GSFC","GSFC","LANL","GSFC","PSU","GSFC/ORAU","GSFC/UMD","LANL","GSFC","GSFC/ORAU","GSFC/ISAS"],"authors":["J. Cummings","L. Barbier","S. D. Barthelmy","E. Fenimore","N. Gehrels","D. Grupe","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","UMBC","GSFC","LANL","PSU","GWU","ORAU","USRA"],"universities":["UMBC","GSFC","LANL","PSU","ORAU","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-06-12T20:39:42.000Z","event":"GRB 070612B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6523\nSUBJECT: GRB 070612B, Swift-BAT refined analysis\nDATE: 07/06/12 20:39:42 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nJ. Cummings (GSFC/UMBC), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nE. Fenimore (LANL), N. Gehrels (GSFC), D. Grupe (PSU),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), T. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS),\nM. Stamatikos (GSFC/ORAU), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-240 to T+962 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070612B (trigger #282073)\n(Grupe, et al., GCN Circ. 6511).  The BAT ground-calculated position is\nRA, Dec = 261.716, -8.747 deg  which is \n   RA(J2000)  = 17h 26m 51.8s \n   Dec(J2000) = -8d 44'' 48\" \nwith an uncertainty of 1.1 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 17%.\n \nThe mask-weighted light curve shows a single roughly symetrical peak\nstarting at T-5 sec, peaking at T+0 sec, and ending at T+12 sec.\nT90 (15-350 keV) is 13.5 +- 1 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-6.4 to T+10.3 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.55 +- 0.11.  The fluence in the 15-150 keV band is 1.7 +- 0.1 x 10^-6 erg/cm2.\nThe 1-sec peak photon flux measured from T-0.16 sec in the 15-150 keV band\nis 2.6 +- 0.4 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'The Swift-BAT team reported a refined analysis of GRB 070612B, a gamma-ray burst detected on June 12, 2007. The ground-calculated position was determined with an uncertainty of 1.1 arcmin, and the time-averaged spectrum was found to be best fit by a simple power-law model with a power law index of 1.55 +- 0.11. The fluence in the 15-150 keV band was measured to be 1.7 +- 0.1 x 10^-6 erg/cm2, and the 1-sec peak photon flux was 2.6 +- 0.4 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6522', 'gcn', 'GRB 070612A', '2007-06-12T20:36:55.000Z', '{"measurements":{"dec":"37d 15'' 30\"","distance":null,"duration":"370 +- 10 sec","energy":null,"fluence":"1.1 +- 0.1 x 10^-5 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"11%","peak_photon_flux":"1.5 +- 0.4 ph/cm2/sec","power_law_index":"1.69 +- 0.10"},"ra":"8h 5m 25.2s","redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","GSFC/UMBC","GSFC","LANL","GSFC/UMD","GSFC/ORAU","GSFC","GSFC/ISAS"],"authors":["S. D. Barthelmy","L. Barbier","J. Cummings","E. Fenimore","N. Gehrels","D. Grupe","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","GSFC/UMBC","LANL","GSFC/UMD","GSFC/ORAU","GSFC/ISAS"],"universities":["GSFC","UMBC","LANL","UMD","ORAU","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-06-12T20:36:55.000Z","event":"GRB 070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6522\nSUBJECT: GRB 070612A, Swift-BAT refined analysis\nDATE: 07/06/12 20:36:55 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS. D. Barthelmy (GSFC), L. Barbier (GSFC), J. Cummings (GSFC/UMBC),\nE. Fenimore (LANL), N. Gehrels (GSFC), D. Grupe (PSU),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), T. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS),\nM. Stamatikos (GSFC/ORAU), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-239 to T+963 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 070612A (trigger #282066)\n(Grupe, et al., GCN Circ. 6509).  The BAT ground-calculated position is\nRA, Dec = 121.355, 37.258 deg  which is \n   RA(J2000)  =  8h  5m 25.2s \n   Dec(J2000) = 37d 15'' 30\" \nwith an uncertainty of 1.4 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 11%.\n \nThe mask-weighted light curve shows two main overlapping peaks\nwith the first starting at ~T-20 sec and the second ending at ~T+400 sec.\nThe two peaks are at T+5 and T+200 sec.  T90 (15-350 keV) is 370 +- 10 sec\n(estimated error including systematics).\n \nThe time-averaged spectrum from T-4.7 to T+418 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.69 +- 0.10.  The fluence in the 15-150 keV band is 1.1 +- 0.1 x 10^-5 erg/cm2.\nThe 1-sec peak photon flux measured from T+10.39 sec in the 15-150 keV band\nis 1.5 +- 0.4 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Astronomers, led by the Swift-BAT team, have refined their analysis of GRB 070612A, reporting a position with an uncertainty of 1.4 arcmin, a duration of 370 +- 10 sec, and a time-averaged power-law spectrum with a index of 1.69 +- 0.10. The event occurred at RA(J2000) = 8h 5m 25.2s, Dec(J2000) = 37d 15'' 30', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6521', 'gcn', 'GRB 070612B', '2007-06-12T20:01:19.000Z', '{"measurements":{"dec":"-08d 45'' 06.3\"","distance":null,"duration":"4.7 ks","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"absorption_column_density_nh":"1.68e21 cm^-2","decay_slope":"2.8+/-0.6","distance_from_preliminary_position":"2.7\"","error_radius":"4.0\" (90% confidence)","photon_index_gamma":"1.7+-0.8"},"ra":"17h 26m 54.49s","redshift":null,"tables":[]},"authors":{"affiliations":["PSU/Swift-XRT"],"authors":["D. Grupe"],"institutions":["Penn State University"],"universities":["Penn State University (PSU)"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6514","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6509","https://ui.adsabs.harvard.edu/abs/1990ApJ...357..115D","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6521"],"basic_data":{"author":{"email":"grupe@astro.psu.edu","institution":"PSU/Swift-XRT","name":"Dirk Grupe"},"coordinates":{},"detectionTime":"2007-06-12T20:01:19.000Z","event":"GRB 070612B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6521\nSUBJECT: GRB 070612B: Swift-XRT refined analysis\nDATE: 07/06/12 20:01:19 GMT\nFROM: Dirk Grupe at PSU/Swift-XRT  <grupe@astro.psu.edu>\n\nD. Grupe (PSU) reports on behalf of the Swift/XRT team\n\nWe have analyzed two orbits of GRB 070612B (Grupe et al., GCN 6509)\nwith total observing times of 4.7 ks\nin Photon Counting mode in the Swift XRT.\nDue to Earth-constrain Swift did not slew immediately and XRT \nobservations were\ndelayed by almost one hour (Grupe \\& Evans, GCN 6514).\nThe Photon Counting mode image\nprovides a refined XRT position at\nRa, Dec= 261.7271, -8.7517, which is\n\nRA(J2000) = 17h 26m 54.49s\nDec(J2000) = -08d 45'' 06.3\"\n\nwith an error of 4.0\" (90% confidence). This position is 2.7 \"\naway from the preliminary XRT position reported in GCN 6514.\n\nThe X-ray light curve shows a decaying source. While the afterglow is \nclearly\ndetected in the first orbit, only a 3sigma upper limit of 0.012 counts/s \ncan be\ngiven for the second orbit.\n Based on this result, we estimated a decay slope of 2.8+/-0.6.\n\n\nThe X-ray data can be fitted by a single power law with a photon\nindex Gamma=1.7+-0.8 and the absorption column density fixed to the Galactic\nvalue of NH=1.68e21\ncm-2 (Dickey & Lockman, 1990) with chi2/dof=4/3.\n\n\n\nThis circular is an official product of the Swift XRT team."}', 'Swift-XRT team reports updated analysis of GRB 070612B, revealing a refined X-ray position with an error of 4.0" (90% confidence), which is 2.7" away from the preliminary position. The X-ray light curve shows a decaying source with a decay slope of 2.8+/-0.6, and the X-ray data can be fitted by a single power law with a photon index of 1.7+-0.8 and absorption column density fixed to the Galactic value.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6520', 'gcn', 'GRB 070610', '2007-06-12T16:02:08.000Z', '{"measurements":{"dec":"261406","distance":null,"duration":"4.6 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"absorbed_flux":"2.4E-12 ergs cm^-2 s^-1","photon_index":"1.8+/-0.3","total_column_density":"1.01e22 cm^-2","unabsorbed_flux":"3.9E-12 ergs cm^-2 s^-1","xrt_observation_end_time":"T+122 ks","xrt_observation_start_time":"T+3.1 ks","xrt_photon_counting_data_duration":"13.2 ks"},"ra":"195509.6","redshift":null,"tables":[]},"authors":{"affiliations":["PSU/Swift-XRT","CRESST/U.Md./GSFC","U. Leicester","NASA/GSFC","NASA/GSFC"],"authors":["C. Pagani","C. B. Markwardt","P. Evans","F. Gavriil","J. A. Kennea","A. D. Falcone","W. Landsman","F. E. Marshall"],"institutions":["PSU","CRESST","U.Md./GSFC","GSFC","NASA/GSFC"],"universities":["Penn State University","University of Maryland","University of Leicester","NASA Goddard Space Flight Center"]},"telescopes":{"facilities":["GSFC"],"instruments":["Swift-XRT"],"observatories":["Swift"],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6520"],"basic_data":{"author":{"email":"pagani@astro.psu.edu","institution":"PSU/Swift-XRT","name":"Claudio Pagani"},"coordinates":{},"detectionTime":"2007-06-12T16:02:08.000Z","event":"GRB 070610","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6520\nSUBJECT: SWIFT J195509.6+261406 / GRB 070610: SWIFT continued observations\nDATE: 07/06/12 16:02:08 GMT\nFROM: Claudio Pagani at PSU/Swift-XRT  <pagani@astro.psu.edu>\n\nC. Pagani (PSU), C. B. Markwardt (CRESST/U.Md./GSFC), P. Evans (U. Leicester), \nF. Gavriil (NPP/GSFC), J. A. Kennea (PSU), A. D. Falcone (PSU), W. Landsman \n(NASA/GSFC) and F. E. Marshall (NASA/GSFC) report on behalf of the Swift \nTeam:\n\nWe report on the continued SWIFT observations of the BAT trigger 281993, \noriginally designated GRB 070610.\n \nWe have collected 13.2 ks of XRT Photon Counting data in the T+3.1 ks to T+122 \nks time interval.  The X-ray light curve shows evidence of rapid variability, \nwith intense flaring activity and a possible late rebrightening.\nUnlike a typical GRB afterglow, the lightcurve has shown no evidence of \noverall fading.\n\nWe can exclude at this point a GRB afterglow origin of the counterpart \nobserved by the narrow field instruments.  The BAT trigger 281993 is probably \na Galactic X-ray Transient, but we can not completely discard the possibility \nof a GRB origin with an undetected X-ray counterpart.\nIn particular, an undetected afterglow from a short GRB (the T90 for \nthis trigger is 4.6 sec, GCN Circ. 6491) would not be unusual considering the \nXRT observations started at T+3.1 ks.  The flaring behavior reported by \nground based observations (GCN Circ. 6492, GCN Circ. 6501, GCN Circ. 6505, \nGCN Circ. 6508) also favors the fast X-ray transient origin of the \ncounterpart. For additional details on the interpretations on the origin of \nthe source, refer to Markwardt et al. ATEL #1102.\n\nThe X-ray spectrum of the PC data in the T+3.1 ks to T+122 ks time interval, \nmodeled with an absorbed power law, gives a photon index of 1.8+/-0.3 with the \ntotal column density consistent with the Galactic value of 1.01e22 cm**-2. \nThe absorbed (unabsorbed) 0.3-10.0keV average flux in the T+3.1 ks - T+122 ks \ntime interval is 2.4E-12 (3.9E-12) ergs cm^-2 s^-1.\n\nWe also note that in the XRT field of view we detect an additional X-ray \nsource 4.3 arcmin from the BAT refined position (and outside of the BAT 1.8 \narcmin 90% error circle) that is most probably an X-ray active star.  The \nanalysis of this source (designated SWIFT J195456.7+261301) will be reported \nin a separate ATEL."}', 'SWIFT J195509.6+261406, initially identified as a gamma-ray burst (GRB) with a duration of 4.6 seconds, has been observed by SWIFT-XRT for 13.2 ks between T+3.1 ks and T+122 ks. The X-ray light curve shows rapid variability and no evidence of overall fading, suggesting a different origin than a typical GRB afterglow. The source is most likely a Galactic X-ray Transient, but a short GRB origin cannot be completely ruled out.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-652', 'gcn', 'GRB 000418', '2000-04-27T16:43:56.000Z', '{"measurements":{"dec":"+20:06:11.6","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":22.49,"other_measurements":{"magnitude_uncertainty":0.2,"position_uncertainty":0.3},"ra":"12:25:19.30","redshift":null,"tables":[{"comparison_star_magnitude":null,"exposure_time":"1800 seconds","filter_used":"Cousins R","limiting_magnitude":null,"observation_date":"000426 UT","observation_time":"000426.316","observed_magnitude":"22.49","source_position":"near limiting magnitude"}]},"authors":{"affiliations":["USNO/USRA","USRA/USNO","Thueringer Landessternwarte Tautenburg"],"authors":["A. Henden","H. Harris","S. Klose"],"institutions":["USNO","USRA","Thueringer Landessternwarte Tautenburg"],"universities":["USNO","USRA"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Thueringer Landessternwarte Tautenburg"],"telescopes":["NOFS 1.3-m automated telescope"]},"urls":["<aah@nofs.navy.mil>"],"basic_data":{"author":{"email":"aah@nofs.navy.mil","institution":"USNO/USRA","name":"Arne A. Henden"},"coordinates":{"dec":20.103222222222225,"ra":12.422027777777776},"detectionTime":"2000-04-27T16:43:56.000Z","event":"GRB 000418","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 652\nSUBJECT: GRB 000418, optical observation\nDATE: 00/04/27 16:43:56 GMT\nFROM: Arne A. Henden at USNO/USRA  <aah@nofs.navy.mil>\n\nA. Henden (USRA/USNO) and H. Harris (USNO),\n on behalf of the USNO GRB team,\nS. Klose, (Thueringer Landessternwarte Tautenburg),\n on behalf of a much larger European team, report:\n\nWe have observed the error box of GRB 000418\nwith the NOFS 1.3-m automated telescope on\n000426 UT with a total exposure time of 1800\nseconds in Cousins R.  At the position of the proposed\nafterglow candidate (Klose et. al. GCN #645)\nwe find a faint source near our limiting\nmagnitude.  With respect to the USNO-A2.0\nstar used by Mirabal et. al. (GCN #646, #650),\nwe obtain\n\nRA 12:25:19.30  DEC +20:06:11.6 +/- 0.3  J2000\nUT 000426.316  R=22.49 +/- 0.20\n\nWe will be calibrating this field in UBVRI\nover the weekend."}', 'The USNO GRB team, in collaboration with a European team, report the observation of a faint source near the proposed afterglow candidate of GRB 000418 using the NOFS 1.3-m automated telescope. The source is located at RA 12:25:19.30, DEC +20:06:11.6, with a magnitude of 22.49 ± 0.2. The team plans to calibrate the field in UBVRI over the weekend.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6519', 'gcn', 'GRB 070612B', '2007-06-12T15:15:50.000Z', '{"measurements":[20.3,21.7,20,20.4,20.1,20.1,20,20.9],"authors":{"affiliations":["NASA/GSFC","PSU"],"authors":["W. Landsman","D. Grupe"],"institutions":["PSU","GSFC/SSAI"],"universities":["PSU","NASA/GSFC"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"landsman@milkyway.gsfc.nasa.gov","institution":"GSFC/SSAI","name":"Wayne Landsman"},"coordinates":{},"detectionTime":"2007-06-12T15:15:50.000Z","event":"GRB 070612B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6519\nSUBJECT: GRB 070612B: Swift/UVOT upper limits\nDATE: 07/06/12 15:15:50 GMT\nFROM: Wayne Landsman at GSFC/SSAI  <landsman@milkyway.gsfc.nasa.gov>\n\nW. Landsman (NASA/GSFC) and D. Grupe (PSU) report on behalf of the \nSwift/UVOT team.\n\nThe Swift/UVOT observed the field of GRB 070612B starting 3256 s after \nthe BAT trigger (Grupe et al., GCN Circ. 6511).   The UVOT observations \nwere delayed due to a Earth-limb constraint. \n\nWe do not find any source in any of the UVOT observations inside the \nrefined XRT error circle (Grupe et al., GCN Circ. 6514). The 3-sigma \nupper limits for detecting  a source in the first finding chart (FC) \nexposure and co-added frames are:\n\nFilter    T_start(s)   T_stop(s)     Exp(s)     Mag (3-sigma UL)\n\nWh  (FC)   3256         3356          98          >20.3\n\nWh         3256         9882        1201          >21.7\nV          3238        11624        1113          >20.0\nB          4180         5813         393          >20.4\nU          3975         5608         393          >20.1\nUVW1       3772         5404         393          >20.1\nUVM2       3567         5199         393          >20.0\nUVW2       4590        10888        1082          >20.9"}', 'The Swift/UVOT team reported no detection of a source within the error circle of GRB 070612B, providing 3-sigma upper limits for detecting a source in various filters: Wh (>20.3), Wh (>21.7), V (>20.0), B (>20.4), U (>20.1), UVW1 (>20.1), and UVW2 (>20.9).', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6518', 'gcn', 'GRB 070612B', '2007-06-12T13:16:52.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":14.8,"other_measurements":{"effective_wavelength":"640nm","exposure_time":"20s","time_after_grb":"62s","time_after_notification":"45s"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Instituto de Astrofísica de Andalucía (IAA-CSIC), Granada, Spain","Columbia U. New York, USA","FZU Praha, Czech Rep."],"authors":["Martin Jelínek","Petr Kubánek","Michael Prouza"],"institutions":["Instituto de Astrofísica de Andalucía (IAA-CSIC)","Columbia U. New York","FZU Praha"],"universities":["University of Granada, Spain","Columbia University, New York, USA","Czech Technical University in Prague, Czech Rep."]},"telescopes":{"facilities":["Pierre Auger observatory"],"instruments":["wide field camera"],"observatories":["Pierre Auger observatory"],"telescopes":["FRAM"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6518"],"basic_data":{"author":{"email":"mates@iaa.es","institution":"Inst.Astrophys.Andalucia,Granada","name":"Martin Jelinek"},"coordinates":{},"detectionTime":"2007-06-12T13:16:52.000Z","event":"GRB 070612B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6518\nSUBJECT: GRB 070612B: FRAM limit\nDATE: 07/06/12 13:16:52 GMT\nFROM: Martin Jelinek at Inst.Astrophys.Andalucia,Granada  <mates@iaa.es>\n\nMartin Jelínek, Petr Kubánek (IAA CSIC Granada, Spain), \nand Michael Prouza (Columbia U. New York, USA and FZU Praha, Czech Rep.) \non behalf of the FRAM team, coordinated by FZU Praha, Czech Rep.\n\nreport\n\n\"The wide field camera of the telescope FRAM,  located \nat  Pierre Auger observatory  in Malargue,  Argentina,\nfollowed  the  Swift  GRB 070612B  (Grupe  et al. GCNs\n6511 and 6514).\n\n20s R-band (lambda_eff = 640nm,  limmag = 14.8) images\nwere  obtained starting  62s after the  GRB (45s after\nreceiving the notification).\n\nWe do not detect any new source in single nor combined\nimages within the BAT or XRT errorboxes.\"\n\nthis message may be cited"}', 'The FRAM team using the wide field camera at Pierre Auger observatory in Argentina did not detect any new source within the errorboxes of Swift GRB 070612B in 20-second R-band images obtained 62 seconds after the GRB.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6517', 'gcn', 'GRB070612B', '2007-06-12T08:56:35.000Z', '{"measurements":{"dec":"-08:45:08.35","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"Mag. Limit i''":21,"Mag. Limit z''":20.5,"i''":22},"other_measurements":{},"ra":"17:26:54.936","redshift":null,"tables":[{"Filter":"i''","Mag. Limit":"> 21.0","t_b (min.)":21.2},{"Filter":"z''","Mag. Limit":"> 20.5","t_b (min.)":22.7}]},"authors":{"affiliations":["Caltech","Penn State"],"authors":["S. B. Cenko","A. Rau","D. B. Fox"],"institutions":["Caltech","Penn State"],"universities":["Caltech","Penn State"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Palomar 60-inch telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6514","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6511"],"basic_data":{"author":{"email":"cenko@srl.caltech.edu","institution":"Caltech","name":"S. Bradley Cenko"},"coordinates":{"dec":7.247680555555555,"ra":17.448593333333335},"detectionTime":"2007-06-12T08:56:35.000Z","event":"GRB070612B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6517\nSUBJECT: GRB070612B: P60 Observations\nDATE: 07/06/12 08:56:35 GMT\nFROM: S. Bradley Cenko at Caltech  <cenko@srl.caltech.edu>\n\nS. B. Cenko, A. Rau (Caltech) and D. B. Fox (Penn State) report on behalf\nof a larger collaboration:\n\nWe have imaged the field of GRB070612B (Grupe et al., GCN 6511) with the\nautomated Palomar 60-inch telescope.  Images were taken in the Kron R and\nSloan i'' and z'' filters beginning approximately 12 minutes after the\nburst.\n\nWe find no sources inside the XRT error circle (Grupe and Evans, GCN\n6514).  Photometric calibration for the limits below was performed using\nUSNO B-1 mangitudes converted to the SDSS photometric sytem using\nempirical relations from Jordi, Grebel & Ammon (A&A 460, 339, 2006):\n\nt_b (min.)\t\tFilter\t\tMag. Limit\n-----------------------------------------------------------------------\n21.2\t\t\ti''\t\t> 21.0\n22.7\t\t\tz''\t\t> 20.5\n\nWe marginally detect a source just outside of the XRT error circle in our\ni'' coaddition.  The source, with i'' magnitude ~ 22.0, is located at\ncoordinates (J2000.0):\n\n\tRA: 17:26:54.936\n\tDec: -08:45:08.35\n\nThis source is not present in either our R- our z''-band imaging of\nthis field.  Because of the faintness, we cannot assess the variability\nof this source at the present time."}', 'The Caltech and Penn State collaboration reported no detected sources within the error circle of GRB070612B using the Palomar 60-inch telescope in i'' and z'' filters. A faint source was marginally detected outside the error circle with i'' magnitude ~ 22.0. The source''s variability cannot be assessed at this time.', 0.95, ARRAY[], NOW(), NOW());